/* AUTO-GENERATED by build-search-index.mjs - do not edit by hand. Re-run: node build-search-index.mjs */
window.MT_DOCS = [{"u":"api-examples.html","t":"API Examples","s":[{"id":"","t":"API Examples","x":"Copy-paste worked examples against the MultiTerminal REST API on http://localhost:5050 , each shown in curl, PowerShell ( Invoke-RestMethod ), and Python ( requests ). For the full endpoint catalogue, see the REST API Reference ."},{"id":"","t":"On This Page","x":"Before you start List tasks Create a task Send a message Get project context Search the code graph"},{"id":"notes","t":"Before you start","x":"The API binds to loopback only ( localhost:5050 ). It has no auth boundary by design — it's reachable only from the local machine. Don't expose it directly; the phone story goes through the gateway (see Multi-Connect ). MultiTerminal must be running so the API is listening. Verify with curl http://localhost:5050/health . All request and response bodies are JSON. The Python snippets assume pip install requests and a shared base URL: import requests BASE = \"http://localhost:5050\""},{"id":"list-tasks","t":"List tasks","x":"GET /api/tasks — optionally filter with ?status= ( all , todo , in_progress , done , suggestion )."},{"id":"","t":"curl","x":"curl \"http://localhost:5050/api/tasks?status=in_progress\""},{"id":"","t":"PowerShell","x":"Invoke-RestMethod -Uri \"http://localhost:5050/api/tasks?status=in_progress\" | Select-Object id, title, status, assignee"},{"id":"","t":"Python","x":"r = requests.get(f\"{BASE}/api/tasks\", params={\"status\": \"in_progress\"}) for task in r.json(): print(task[\"id\"], task[\"title\"], task[\"status\"])"},{"id":"create-task","t":"Create a task","x":"POST /api/tasks . Required: title , description , createdBy . Optional: status (default todo ), priority (default normal ), projectId . The response is { \"taskId\": \"...\", \"task\": { ... } } ."},{"id":"","t":"curl","x":"curl -X POST http://localhost:5050/api/tasks \\ -H \"Content-Type: application/json\" \\ -d '{ \"title\": \"Fix login bug\", \"description\": \"500 error on login when password contains special characters\", \"createdBy\": \"Alice\", \"status\": \"todo\", \"priority\": \"high\" }'"},{"id":"","t":"PowerShell","x":"$body = @{ title = \"Fix login bug\" description = \"500 error on login when password contains special characters\" createdBy = \"Alice\" status = \"todo\" priority = \"high\" } | ConvertTo-Json $resp = Invoke-RestMethod -Uri \"http://localhost:5050/api/tasks\" ` -Method Post -ContentType \"application/json\" -Body $body $resp.taskId"},{"id":"","t":"Python","x":"resp = requests.post(f\"{BASE}/api/tasks\", json={ \"title\": \"Fix login bug\", \"description\": \"500 error on login when password contains special characters\", \"createdBy\": \"Alice\", \"status\": \"todo\", \"priority\": \"high\", }) print(resp.json()[\"taskId\"])"},{"id":"send-message","t":"Send a message","x":"Messaging is keyed by a terminal id, not a name. First register to get a terminalId via POST /api/messaging/register , then send with that id as fromTerminalId . # 1) Register once — returns { \"terminalId\": \"...\" } curl -X POST http://localhost:5050/api/messaging/register \\ -H \"Content-Type: application/json\" \\ -d '{\"name\":\"Alice\",\"docId\":\"cli\"}' POST /api/messaging/send — fields: fromTerminalId , to (recipient name), message , and optional priority ."},{"id":"","t":"curl","x":"curl -X POST http://localhost:5050/api/messaging/send \\ -H \"Content-Type: application/json\" \\ -d '{ \"fromTerminalId\": \"a1b2c3d4-e5f6-7890-abcd-ef1234567890\", \"to\": \"Bob\", \"message\": \"Build is ready for testing\", \"priority\": \"normal\" }'"},{"id":"","t":"PowerShell","x":"# Register, then send using the returned terminalId $reg = Invoke-RestMethod -Uri \"http://localhost:5050/api/messaging/register\" ` -Method Post -ContentType \"application/json\" ` -Body (@{ name = \"Alice\"; docId = \"cli\" } | ConvertTo-Json) $body = @{ fromTerminalId = $reg.terminalId to = \"Bob\" message = \"Build is ready for testing\" priority = \"normal\" } | ConvertTo-Json Invoke-RestMethod -Uri \"http://localhost:5050/api/messaging/send\" ` -Method Post -ContentType \"application/json\" -Body $body"},{"id":"","t":"Python","x":"reg = requests.post(f\"{BASE}/api/messaging/register\", json={\"name\": \"Alice\", \"docId\": \"cli\"}).json() requests.post(f\"{BASE}/api/messaging/send\", json={ \"fromTerminalId\": reg[\"terminalId\"], \"to\": \"Bob\", \"message\": \"Build is ready for testing\", \"priority\": \"normal\", })"},{"id":"project-context","t":"Get project context","x":"GET /api/projects/{projectId}/context returns the single \"everything an agent needs\" object — the project plus all its associations (agents, MCP servers, specialists, paths, prompts, skills). List projects with GET /api/projects to find an id."},{"id":"","t":"curl","x":"# Find a project id, then fetch its context curl http://localhost:5050/api/projects curl http://localhost:5050/api/projects/proj-123/context"},{"id":"","t":"PowerShell","x":"$ctx = Invoke-RestMethod -Uri \"http://localhost:5050/api/projects/proj-123/context\" $ctx | ConvertTo-Json -Depth 6"},{"id":"","t":"Python","x":"ctx = requests.get(f\"{BASE}/api/projects/proj-123/context\").json() print(ctx) Note: a missing project id returns 404 with { \"error\": \"Project '...' not found\" } ."},{"id":"code-search","t":"Search the code graph","x":"GET /api/code-graph/search?query=... finds symbols by name, with an optional type filter ( class , method , interface , ...). The response is { \"success\": true, \"count\": N, \"results\": [ ... ] } . Index the project first (see Code Graph ) — an unindexed graph returns 503 ."},{"id":"","t":"curl","x":"curl \"http://localhost:5050/api/code-graph/search?query=MessageBroker&type=class\""},{"id":"","t":"PowerShell","x":"$res = Invoke-RestMethod ` -Uri \"http://localhost:5050/api/code-graph/search?query=MessageBroker&type=class\" $res.count $res.results | Select-Object name, type, file_path, line_number"},{"id":"","t":"Python","x":"res = requests.get(f\"{BASE}/api/code-graph/search\", params={\"query\": \"MessageBroker\", \"type\": \"class\"}).json() print(res[\"count\"]) for sym in res[\"results\"]: print(sym[\"name\"], sym[\"type\"], sym[\"file_path\"], sym[\"line_number\"]) From a result's symbol id you can walk the graph further: /api/code-graph/callers , /api/code-graph/callees , /api/code-graph/impact , and /api/code-graph/inheritance all accept ?symbolId= (or ?symbolName= )."}]},{"u":"api-reference.html","t":"REST API Reference","s":[{"id":"","t":"REST API Reference","x":"Complete reference for the MultiTerminal REST API running on http://localhost:5050 . All endpoints accept and return JSON."},{"id":"","t":"On This Page","x":"Health & Discovery Messaging Tasks Checklist Workflow Inbox & Notifications Attachments Office Panel Agent Spawning Agent Panels Knowledge Base Session Lineage Projects Team Debug Code Search Task Relationships Task File Links Task Reports Agent Stats Notifications Owner Profile Companions MCP Gateway Browser Tabs Terminal Streaming XAML Preview Code Graph Branch Metadata"},{"id":"health","t":"Health & Discovery","x":"GET / Basic health check. Returns a confirmation that the API is running. Response \"MultiTerminal API is running\" curl curl http://localhost:5050/ GET /health Health check with port information. Response { \"status\": \"healthy\", \"port\": 5050 } curl curl http://localhost:5050/health GET /api/tools Self-documenting endpoint. Lists all available API endpoints with method, path, and description. Response { \"baseUrl\": \"http://localhost:5050\", \"endpoints\": [ { \"method\": \"GET\", \"path\": \"/\", \"description\": \"Health check - API is running\" }, { \"method\": \"POST\", \"path\": \"/api/messaging/register\", \"description\": \"Register a terminal (name, docId)\" }, ... ] } curl curl http://localhost:5050/api/tools"},{"id":"messaging","t":"Messaging","x":"Terminal registration and inter-terminal messaging. All messaging endpoints are under /api/messaging . POST /api/messaging/register Register a terminal with the messaging system. Returns a unique terminal ID used for subsequent messaging calls. Request Body { \"name\": \"Alice\", \"docId\": \"abc123\" } Response { \"terminalId\": \"a1b2c3d4-e5f6-7890-abcd-ef1234567890\" } Error Response { \"error\": \"Terminal already registered\" } curl curl -X POST http://localhost:5050/api/messaging/register \\ -H \"Content-Type: application/json\" \\ -d '{\"name\":\"Alice\",\"docId\":\"abc123\"}' POST /api/messaging/send Send a direct message to another terminal by name. Request Body { \"fromTerminalId\": \"a1b2c3d4-e5f6-7890-abcd-ef1234567890\", \"to\": \"Bob\", \"message\": \"Hello, can you help with the database migration?\" } Response { \"success\": true, \"from\": \"Alice\", \"to\": \"Bob\" } curl curl -X POST http://localhost:5050/api/messaging/send \\ -H \"Content-Type: application/json\" \\ -d '{\"fromTerminalId\":\"a1b2c3d4\",\"to\":\"Bob\",\"message\":\"Hello!\"}' POST /api/messaging/broadcast Broadcast a message to all registered terminals. Request Body { \"fromTerminalId\": \"a1b2c3d4-e5f6-7890-abcd-ef1234567890\", \"message\": \"Build is ready for testing!\" } Response { \"success\": true, \"from\": \"Alice\", \"recipientCount\": 3 } curl curl -X POST http://localhost:5050/api/messaging/broadcast \\ -H \"Content-Type: application/json\" \\ -d '{\"fromTerminalId\":"},{"id":"tasks","t":"Tasks","x":"CRUD operations for kanban tasks. All task endpoints are under /api/tasks . GET /api/tasks List all tasks, optionally filtered by status. Query Parameters Param Type Default Description status string all Filter: all , todo , in_progress , done , suggestion Response [ { \"id\": \"c0ce8037\", \"title\": \"Add dark mode\", \"description\": \"Implement dark mode theme switching\", \"status\": \"in_progress\", \"assignee\": \"Alice\", \"createdBy\": \"Alice\", \"createdAt\": \"2026-03-05T08:00:00Z\", \"priority\": \"normal\", \"subStatus\": \"active\", \"checklistJson\": \"[...]\", \"plan\": \"...\", \"continuationNotes\": \"...\" } ] curl curl http://localhost:5050/api/tasks?status=in_progress GET /api/tasks/{taskId} Get a specific task by ID. Response { \"id\": \"c0ce8037\", \"title\": \"Add dark mode\", \"status\": \"in_progress\", ... } Error (404) { \"error\": \"Task c0ce8037 not found\" } curl curl http://localhost:5050/api/tasks/c0ce8037 GET /api/tasks/{taskId}/detail Get full task detail including parsed checklist with notes history, helpers, and progress summary. Response { \"task\": { \"id\": \"c0ce8037\", \"title\": \"Add dark mode\", ... }, \"checklistSummary\": { \"total\": 5, \"done\": 2, \"coding\": 1, \"testing\": 1, \"pending\": 1 }, \"checklist\": [ { \"item\": \"Create theme service\", \"status\": \"done\", \"notes\": [ { \"text\": \"Implemented ThemeService with light/dark toggle\", \"at\": \"2026-03-05T09:00:00Z\", \"by\": \"Alice\" } ], \"assignee\": \"Alice\", \"cycleCount"},{"id":"checklist","t":"Checklist Workflow","x":"Enhanced checklist management with state machine transitions. The lifecycle is: pending → coding → testing → done (cycling allowed between coding and testing ). PATCH /api/tasks/{taskId}/checklist Replace all checklist items. Use for initial setup or bulk editing. Request Body { \"checklistJson\": \"[{\\\"item\\\":\\\"Setup database\\\",\\\"status\\\":\\\"pending\\\",\\\"notes\\\":[]},{\\\"item\\\":\\\"Create API\\\",\\\"status\\\":\\\"pending\\\",\\\"notes\\\":[]}]\" } Response { \"success\": true } curl curl -X PATCH http://localhost:5050/api/tasks/c0ce8037/checklist \\ -H \"Content-Type: application/json\" \\ -d '{\"checklistJson\":\"[{\\\"item\\\":\\\"Setup database\\\",\\\"status\\\":\\\"pending\\\",\\\"notes\\\":[]}]\"}' POST /api/tasks/{taskId}/checklist/append Append items to the existing checklist (preserves existing items). Appended items default to status pending . Request Body { \"itemsJson\": \"[{\\\"item\\\":\\\"Add validation\\\",\\\"status\\\":\\\"pending\\\",\\\"notes\\\":[]}]\" } Response { \"success\": true } curl curl -X POST http://localhost:5050/api/tasks/c0ce8037/checklist/append \\ -H \"Content-Type: application/json\" \\ -d '{\"itemsJson\":\"[{\\\"item\\\":\\\"Add validation\\\",\\\"status\\\":\\\"pending\\\",\\\"notes\\\":[]}]\"}' POST /api/tasks/{taskId}/checklist/{itemIndex}/transition Transition a checklist item to a new status. Enforces the state machine and tracks cycle count for escalation. Request Body { \"newStatus\": \"testing\", \"notes\": \"Implemented database schema and C"},{"id":"inbox","t":"Inbox & Notifications","x":"Inbox notifications for task events like checklist items ready for testing, escalations, and helper requests. Endpoints are under /api/tasks/inbox . GET /api/tasks/inbox/{userId} Get inbox messages for a user. Query Parameters Param Type Default Description unreadOnly boolean false Only return unread messages limit integer 50 Max messages to return Response { \"success\": true, \"messages\": [ { \"id\": \"abc12345\", \"userId\": \"Owner\", \"taskId\": \"c0ce8037\", \"taskTitle\": \"Add dark mode\", \"checklistItemIndex\": 2, \"checklistItemName\": \"Add validation\", \"type\": \"ready_for_testing\", \"summary\": \"Alice finished 'Add validation' - ready for testing\", \"createdAt\": \"2026-03-05T10:30:00Z\", \"createdBy\": \"Alice\", \"readAt\": null, \"replyText\": null, \"repliedAt\": null } ], \"unreadCount\": 5, \"totalCount\": 1 } Message types: ready_for_testing , escalation , task_complete , helper_request curl curl \"http://localhost:5050/api/tasks/inbox/Owner?unreadOnly=true\" POST /api/tasks/inbox/{messageId}/read Mark a single inbox message as read. Response { \"success\": true } curl curl -X POST http://localhost:5050/api/tasks/inbox/abc12345/read POST /api/tasks/inbox/{userId}/read-all Mark all inbox messages as read for a user. Response { \"success\": true } curl curl -X POST http://localhost:5050/api/tasks/inbox/Owner/read-all POST /api/tasks/inbox/{messageId}/reply Reply to an inbox message. Auto-marks the message as r"},{"id":"attachments","t":"Attachments","x":"Image attachments for tasks and checklist items. Stored as binary blobs in SQLite. GET /api/tasks/{taskId}/attachments Get attachment metadata for a task, optionally filtered by checklist item index. Query Parameters Param Type Default Description itemIndex integer - Filter by checklist item index Response [ { \"id\": \"att-12345\", \"taskId\": \"c0ce8037\", \"checklistItemIndex\": 0, \"fileName\": \"screenshot.png\", \"mimeType\": \"image/png\", \"addedBy\": \"Alice\", \"addedAt\": \"2026-03-05T10:00:00Z\" } ] curl curl \"http://localhost:5050/api/tasks/c0ce8037/attachments?itemIndex=0\" GET /api/tasks/attachments/{attachmentId}/image Get raw binary image data for an attachment. Returns the file with appropriate MIME type. Response Raw binary image data with Content-Type header (e.g., image/png ). curl curl http://localhost:5050/api/tasks/attachments/att-12345/image -o screenshot.png GET /api/tasks/attachments/{attachmentId}/base64 Get attachment image as base64-encoded string with metadata. Useful for agents that need to analyze images. Response { \"base64\": \"iVBORw0KGgoAAAANSUhEUgAA...\", \"mimeType\": \"image/png\", \"fileName\": \"screenshot.png\" } curl curl http://localhost:5050/api/tasks/attachments/att-12345/base64 POST /api/tasks/{taskId}/attachments Add a base64-encoded image attachment to a task or checklist item. Request Body { \"checklistItemIndex\": 0, \"fileName\": \"bug-screenshot.png\", \"mimeType\": \"ima"},{"id":"office","t":"Office Panel","x":"Agent presence tracking for the Office Panel UI. Triggers walk-in/exit animations. Endpoints are under /api/office . POST /api/office/agents Notify that an agent has been spawned. Triggers walk-in animation in the Office Panel. Request Body { \"name\": \"Alice\", \"spawnedBy\": \"Owner\" } Response { \"success\": true, \"agentName\": \"Alice\" } curl curl -X POST http://localhost:5050/api/office/agents \\ -H \"Content-Type: application/json\" \\ -d '{\"name\":\"Alice\",\"spawnedBy\":\"Owner\"}' DELETE /api/office/agents/{name} Notify that an agent has departed. Triggers exit animation in the Office Panel. Response { \"success\": true, \"agentName\": \"Alice\" } curl curl -X DELETE http://localhost:5050/api/office/agents/Alice GET /api/office/agents List all currently active office agents. Response [ { \"name\": \"Alice\", \"spawnedBy\": \"Owner\", \"spawnedAt\": \"2026-03-05T10:00:00Z\" }, { \"name\": \"Bob\", \"spawnedBy\": \"Alice\", \"spawnedAt\": \"2026-03-05T10:05:00Z\" } ] curl curl http://localhost:5050/api/office/agents DELETE /api/office/agents/cleanup Remove stale/ghost office agents older than a specified number of minutes. Query Parameters Param Type Default Description olderThanMinutes integer 30 Remove agents older than this Response { \"success\": true, \"removedCount\": 2, \"removedAgents\": [\"Ghost1\", \"Ghost2\"] } curl curl -X DELETE \"http://localhost:5050/api/office/agents/cleanup?olderThanMinutes=60\" DELETE /api/office/a"},{"id":"spawn","t":"Agent Spawning","x":"POST /api/spawn/agent Spawn a headless AgentProcess with piped stdin/stdout. The agent runs Claude Code in stream-json mode and its conversation is displayed in the Agent Panel. Request Body { \"agentName\": \"Agent Alice\", \"workingDir\": \"H:\\\\DevLaptop\\\\ClarionPowerShell\\\\MultiTerminal\", \"initialPrompt\": \"Implement the dark mode feature\", \"mcpConfigPath\": \"C:\\\\Users\\\\<username>\\\\.claude\\\\mcp-config.json\", \"spawnerName\": \"Owner\", \"taskDescription\": \"Add dark mode toggle to the settings panel\", \"subagentType\": \"coder\" } Field Type Required Description agentName string Yes Name for the spawned agent workingDir string No Working directory for the agent initialPrompt string No Initial prompt to send to the agent mcpConfigPath string No Path to MCP configuration spawnerName string No Who is spawning this agent taskDescription string No Description of the task for the agent subagentType string No Type of subagent (e.g., coder , reviewer ) Response { \"success\": true, \"agentName\": \"Agent Alice\", \"processId\": 12345, \"sessionId\": \"a1b2c3d4-e5f6-7890-abcd-ef1234567890\" } curl curl -X POST http://localhost:5050/api/spawn/agent \\ -H \"Content-Type: application/json\" \\ -d '{\"agentName\":\"Agent Alice\",\"workingDir\":\"H:\\\\DevLaptop\\\\MyProject\",\"initialPrompt\":\"Fix the bug\",\"spawnerName\":\"Owner\"}'"},{"id":"agent-panels","t":"Agent Panels","x":"POST /api/agent-panels/close Close an agent panel by transcript path. Called by the SubagentStop hook when a subagent finishes. Request Body { \"transcriptPath\": \"C:\\\\Users\\\\<username>\\\\.claude\\\\teams\\\\my-team\\\\Agent Alice\\\\transcript.jsonl\" } Response { \"success\": true, \"transcriptPath\": \"C:\\\\Users\\\\<username>\\\\.claude\\\\teams\\\\my-team\\\\Agent Alice\\\\transcript.jsonl\" } curl curl -X POST http://localhost:5050/api/agent-panels/close \\ -H \"Content-Type: application/json\" \\ -d '{\"transcriptPath\":\"C:\\\\Users\\\\<username>\\\\.claude\\\\teams\\\\my-team\\\\Agent Alice\\\\transcript.jsonl\"}'"},{"id":"knowledge","t":"Knowledge Base","x":"Institutional memory system for decisions, patterns, gotchas, and code digests. Endpoints are under /api/knowledge . GET /api/knowledge/search Search knowledge entries by text query, category, project, and tags. Uses FTS5 full-text search. Query Parameters Param Type Default Description query string - Search text category string - decision , pattern , gotcha , anti_pattern , debug_insight , preference projectId string - Filter by project tags string - Comma-separated tags limit integer 20 Max results (max 500) Response { \"results\": [ { \"id\": 1, \"projectId\": \"proj-123\", \"category\": \"gotcha\", \"title\": \"PowerShell single-quote injection\", \"content\": \"Always escape single quotes with Replace(\\\"'\\\", \\\"''\\\") before interpolating into PowerShell commands\", \"sourceType\": \"session\", \"tags\": \"security,powershell\", \"confidence\": \"confirmed\", \"createdAt\": \"2026-02-28T10:00:00Z\" } ], \"totalCount\": 1 } curl curl \"http://localhost:5050/api/knowledge/search?query=injection&category=gotcha&limit=10\" POST /api/knowledge Create a new knowledge entry. Request Body { \"title\": \"Always use parameterized queries\", \"content\": \"Never interpolate user input into SQL strings. Use SQLiteParameter for all values.\", \"category\": \"pattern\", \"projectId\": \"proj-123\", \"sourceType\": \"review\", \"tags\": \"security,sql,database\", \"confidence\": \"confirmed\" } Response { \"success\": true, \"id\": 42 } curl curl -X POST http:"},{"id":"session-lineage","t":"Session Lineage","x":"Import, query, and search Claude Code session transcripts. Supports lineage chaining for tracking agent cycling. Endpoints are under /api/session-lineage . POST /api/session-lineage/import Import a Claude Code session JSONL file and link it to a kanban task. Extracts messages and indexes them with FTS5 for full-text search. Request Body { \"sessionFilePath\": \"C:\\\\Users\\\\<username>\\\\.claude\\\\projects\\\\...\\\\sessions\\\\abc123.jsonl\", \"taskId\": \"c0ce8037\", \"agentName\": \"Alice\", \"parentSessionId\": \"prev-session-id\", \"sessionType\": \"coding\" } Field Type Required Description sessionFilePath string Yes Path to JSONL file (must be within ~/.claude/projects ) taskId string Yes Kanban task ID agentName string Yes Agent who ran the session parentSessionId string No Parent session for lineage chaining sessionType string No Semantic label: coding , review , testing Response { \"success\": true, \"sessionId\": \"def456\", \"messageCount\": 127 } curl curl -X POST http://localhost:5050/api/session-lineage/import \\ -H \"Content-Type: application/json\" \\ -d '{\"sessionFilePath\":\"C:\\\\Users\\\\<username>\\\\.claude\\\\...\\\\abc123.jsonl\",\"taskId\":\"c0ce8037\",\"agentName\":\"Alice\"}' GET /api/session-lineage/task/{taskId}/sessions Get all session lineage records for a task, newest first. Response [ { \"sessionId\": \"def456\", \"parentSessionId\": \"abc123\", \"taskId\": \"c0ce8037\", \"agentName\": \"Alice\", \"sessionType\": \"coding\", \""},{"id":"projects","t":"Projects","x":"Project context endpoints for agent orientation. Endpoints are under /api/projects . GET /api/projects/{projectId}/context Get the full project context: project record joined with all association tables (agents, MCP servers, specialist agents, paths, prompts, skills) in a single response. Response { \"project\": { \"id\": \"proj-123\", \"name\": \"MultiTerminal\", \"description\": \"Multi-agent coordination system\", \"path\": \"H:\\\\DevLaptop\\\\ClarionPowerShell\\\\MultiTerminal\", \"deployPath\": \"H:\\\\DevLaptop\\\\ClarionPowerShell\\\\Deploy\", \"buildCommand\": \"dotnet build\", \"projectType\": \"WinForms\", \"gitRepoUrl\": \"...\", \"gitDefaultBranch\": \"main\", \"isPinned\": true, \"teamLead\": \"Owner\" }, \"agents\": [ { \"agentName\": \"Alice\", \"role\": \"backend\", \"preferredModel\": \"sonnet\" } ], \"mcpServers\": [ { \"serverName\": \"multiterminal-mcp\", \"isEnabled\": true } ], \"specialistAgents\": [ { \"agentType\": \"verifier\", \"isEnabled\": true, \"customPrompt\": null } ], \"paths\": [ { \"pathType\": \"source\", \"pathValue\": \"H:\\\\DevLaptop\\\\...\", \"description\": \"Main source\" } ], \"prompts\": [ { \"promptType\": \"system\", \"promptText\": \"...\", \"displayOrder\": 0 } ], \"skills\": [ { \"skillName\": \"kanban-task\", \"isEnabled\": true } ] } curl curl http://localhost:5050/api/projects/proj-123/context GET /api/projects/contexts List all project contexts with their full association data. Response { \"count\": 3, \"contexts\": [ ... ] } curl curl http://localh"},{"id":"team","t":"Team","x":"GET /api/team/roster Get the team roster for a project, merged with profile data. Returns each agent's name, preferred model, instructions, role, and skills. Query Parameters Param Type Required Description projectPath string Yes Absolute path to the project directory Response { \"projectName\": \"MultiTerminal\", \"projectPath\": \"H:\\\\DevLaptop\\\\ClarionPowerShell\\\\MultiTerminal\", \"agents\": [ { \"name\": \"Alice\", \"hasProfile\": true, \"preferredModel\": \"sonnet\", \"agentInstructions\": \"Backend systems architect specializing in C# and SQLite\", \"role\": \"backend\", \"skills\": [\"database\", \"api-design\", \"c-sharp\"], \"isOnline\": true, \"isTeamLead\": false } ] } curl curl \"http://localhost:5050/api/team/roster?projectPath=H%3A%5CDevLaptop%5CClarionPowerShell%5CMultiTerminal\""},{"id":"debug","t":"Debug","x":"Debug logging for system diagnostics. Endpoints are under /api/debug . GET /api/debug/logs Get debug log entries with filtering and pagination. Ordered by most recent first. Query Parameters Param Type Default Description count integer 50 Number of entries to return offset integer 0 Skip entries for pagination source string - Filter by component (e.g., InboxMonitor , MessageBroker ) level string - Trace , Info , Warning , Error search string - Text search within messages (case-insensitive) Response { \"total\": 1234, \"offset\": 0, \"count\": 2, \"entries\": [ { \"timestamp\": \"10:30:45.123\", \"source\": \"InboxMonitor\", \"level\": \"Info\", \"message\": \"Nudge sent to terminal Alice for task c0ce8037\" }, { \"timestamp\": \"10:30:44.987\", \"source\": \"MessageBroker\", \"level\": \"Trace\", \"message\": \"Message delivered from Bob to Alice\" } ] } curl curl \"http://localhost:5050/api/debug/logs?count=20&source=InboxMonitor&level=Info\" DELETE /api/debug/logs Clear all debug log entries. Response { \"message\": \"Debug logs cleared\", \"previousCount\": 1234 } curl curl -X DELETE http://localhost:5050/api/debug/logs POST /api/debug/pause Pause debug logging. New entries are silently discarded until resumed. Response { \"isPaused\": true } curl curl -X POST http://localhost:5050/api/debug/pause POST /api/debug/resume Resume debug logging. Response { \"isPaused\": false } curl curl -X POST http://localhost:5050/api/debug/re"},{"id":"search","t":"Code Search","x":"Fast code and file search powered by ripgrep (bundled as tools/rg.exe ). Endpoints are under /api/search . POST /api/search/content Search file contents using ripgrep regex. Returns matches with file paths, line numbers, and search statistics. Request { \"pattern\": \"class.*Service\", \"path\": \"H:\\\\DevLaptop\\\\ClarionPowerShell\\\\MultiTerminal\", \"caseInsensitive\": false, \"glob\": \"*.cs\", \"fileType\": null, \"maxCount\": 10, \"context\": 2, \"before\": 0, \"after\": 0, \"multiline\": false, \"fixedStrings\": false, \"filesWithMatches\": false, \"count\": false } Response { \"success\": true, \"matchCount\": 15, \"matches\": [ { \"filePath\": \"Services/RipgrepService.cs\", \"lineNumber\": 10, \"text\": \" public class RipgrepService\", \"line\": \"Services/RipgrepService.cs:10: public class RipgrepService\" } ], \"stats\": { \"matchedLines\": 15, \"matches\": 15, \"searchedFiles\": 80, \"elapsedMs\": 12.3 } } curl curl -X POST http://localhost:5050/api/search/content \\ -H \"Content-Type: application/json\" \\ -d '{\"pattern\":\"class.*Service\",\"path\":\"H:\\\\\\\\project\",\"glob\":\"*.cs\"}' POST /api/search/files Find files matching a glob pattern or file type filter. Request { \"path\": \"H:\\\\DevLaptop\\\\ClarionPowerShell\\\\MultiTerminal\", \"glob\": \"*.cs\", \"fileType\": null } Response { \"success\": true, \"fileCount\": 80, \"files\": [ \"H:\\\\DevLaptop\\\\ClarionPowerShell\\\\MultiTerminal\\\\MainForm.cs\", \"...\" ] } curl curl -X POST http://localhost:5050/api/searc"},{"id":"task-relationships","t":"Task Relationships","x":"Blocking and dependency relationships between tasks. Automatically creates inverse relationships. Endpoints are under /api/tasks/{taskId}/relationships . POST /api/tasks/{taskId}/relationships Add a relationship between two tasks. Automatically creates the inverse relationship (e.g., if A blocks B, then B is blocked_by A). Request Body { \"targetTaskId\": \"d4e5f6a7\", \"type\": \"blocks\", \"createdBy\": \"Alice\" } Field Type Required Description targetTaskId string Yes Target task ID type string Yes blocks , depends_on , related_to createdBy string Yes Who created the relationship Response { \"success\": true } curl curl -X POST http://localhost:5050/api/tasks/c0ce8037/relationships \\ -H \"Content-Type: application/json\" \\ -d '{\"targetTaskId\":\"d4e5f6a7\",\"type\":\"blocks\",\"createdBy\":\"Alice\"}' GET /api/tasks/{taskId}/relationships Get all relationships for a task. Response { \"success\": true, \"relationships\": [ { \"sourceTaskId\": \"c0ce8037\", \"targetTaskId\": \"d4e5f6a7\", \"type\": \"blocks\", \"createdBy\": \"Alice\" } ] } curl curl http://localhost:5050/api/tasks/c0ce8037/relationships DELETE /api/tasks/{taskId}/relationships/{relatedTaskId} Remove a relationship between two tasks (removes both directions). Response { \"success\": true } curl curl -X DELETE http://localhost:5050/api/tasks/c0ce8037/relationships/d4e5f6a7"},{"id":"task-files","t":"Task File Links","x":"Link files to tasks for code review context and agent orientation. Supports optional line ranges. Endpoints are under /api/tasks/{taskId}/files . POST /api/tasks/{taskId}/files Link a file to a task. Request Body { \"filePath\": \"H:\\\\DevLaptop\\\\ClarionPowerShell\\\\MultiTerminal\\\\Services\\\\TaskDatabase.cs\", \"description\": \"Core persistence layer being modified\", \"lineStart\": 100, \"lineEnd\": 250, \"addedBy\": \"Alice\" } Response { \"success\": true, \"fileCount\": 3 } curl curl -X POST http://localhost:5050/api/tasks/c0ce8037/files \\ -H \"Content-Type: application/json\" \\ -d '{\"filePath\":\"H:\\\\\\\\path\\\\\\\\to\\\\\\\\file.cs\",\"description\":\"Relevant file\",\"addedBy\":\"Alice\"}' GET /api/tasks/{taskId}/files Get all files linked to a task. Response { \"success\": true, \"files\": [ { \"filePath\": \"H:\\\\DevLaptop\\\\...\\\\TaskDatabase.cs\", \"description\": \"Core persistence layer\", \"lineStart\": 100, \"lineEnd\": 250, \"addedBy\": \"Alice\", \"addedAt\": \"2026-03-10T10:00:00Z\" } ] } curl curl http://localhost:5050/api/tasks/c0ce8037/files POST /api/tasks/{taskId}/files/unlink Unlink a file from a task. Request Body { \"filePath\": \"H:\\\\DevLaptop\\\\...\\\\TaskDatabase.cs\" } Response { \"success\": true } curl curl -X POST http://localhost:5050/api/tasks/c0ce8037/files/unlink \\ -H \"Content-Type: application/json\" \\ -d '{\"filePath\":\"H:\\\\\\\\path\\\\\\\\to\\\\\\\\file.cs\"}' GET /api/tasks/{taskId}/code-review Get code review diff data for all l"},{"id":"task-reports","t":"Task Reports","x":"Persisted agent reports (HTML/markdown) linked to kanban tasks. Generated by specialist agents (verifier, code-reviewer, security-auditor). Endpoints are under /api/tasks/{taskId}/reports . GET /api/tasks/{taskId}/reports List reports for a task (metadata only, no content). Query Parameters Param Type Default Description agentName string - Filter by agent name limit integer 50 Max reports to return Response { \"taskId\": \"c0ce8037\", \"count\": 2, \"reports\": [ { \"id\": \"rpt12345\", \"taskId\": \"c0ce8037\", \"agentName\": \"verifier\", \"reportType\": \"html\", \"verdict\": \"PASS\", \"score\": 95, \"createdAt\": \"2026-03-10T10:00:00Z\", \"createdBy\": \"Alice\" } ] } curl curl \"http://localhost:5050/api/tasks/c0ce8037/reports?agentName=verifier\" GET /api/tasks/{taskId}/reports/{reportId} Get full report content by ID. Response { \"id\": \"rpt12345\", \"task_id\": \"c0ce8037\", \"agent_name\": \"verifier\", \"report_type\": \"html\", \"report_content\": \"<h1>Verification Report</h1>...\", \"verdict\": \"PASS\", \"score\": 95 } curl curl http://localhost:5050/api/tasks/c0ce8037/reports/rpt12345 POST /api/tasks/{taskId}/reports Save a new agent report. Request Body { \"agentName\": \"verifier\", \"reportContent\": \"<h1>Verification Report</h1><p>All checks passed.</p>\", \"reportType\": \"html\", \"verdict\": \"PASS\", \"score\": 95, \"invocationId\": \"inv-abc123\", \"createdBy\": \"Alice\" } Response { \"success\": true, \"reportId\": \"rpt12345\" } curl curl -X P"},{"id":"agent-stats","t":"Agent Stats","x":"Aggregated agent performance statistics and invocation tracking. Endpoints are under /api/agents . GET /api/agents/stats Get aggregated performance stats per agent (invocation counts, average scores, verdicts). Response [ { \"agentName\": \"verifier\", \"totalInvocations\": 15, \"avgScore\": 87, \"passCount\": 12, \"failCount\": 3 } ] curl curl http://localhost:5050/api/agents/stats GET /api/agents/invocations List recent agent invocations with optional filters. Query Parameters Param Type Default Description agentName string - Filter by agent name taskId string - Filter by task limit integer 50 Max results (max 500) Response [ { \"id\": \"inv-abc123\", \"agentName\": \"verifier\", \"taskId\": \"c0ce8037\", \"invokedBy\": \"Alice\", \"modelUsed\": \"opus\", \"verdict\": \"PASS\", \"score\": 95, \"findingsCount\": 0, \"durationMs\": 45000, \"invokedAt\": \"2026-03-10T10:00:00Z\", \"completedAt\": \"2026-03-10T10:00:45Z\" } ] curl curl \"http://localhost:5050/api/agents/invocations?agentName=verifier&limit=20\" POST /api/agents/invocations Record a new agent invocation. Request Body { \"agentName\": \"verifier\", \"taskId\": \"c0ce8037\", \"invokedBy\": \"Alice\", \"modelUsed\": \"opus\", \"verdict\": \"PASS\", \"score\": 95, \"findingsCount\": 0, \"durationMs\": 45000, \"reportSummary\": \"All checks passed\" } Response { \"success\": true, \"invocationId\": \"inv-abc123\" } curl curl -X POST http://localhost:5050/api/agents/invocations \\ -H \"Content-Type: applicat"},{"id":"notifications","t":"Notifications","x":"Runtime notifications from Claude Code hooks. Stores events in the DB and forwards them to the in-process Multi-Connect gateway, which delivers Web Push (VAPID) notifications to your phone. Rate limited to 100/minute. Endpoints are under /api/notifications . POST /api/notifications Receive a Claude Code runtime notification. Stores in the DB, fires a broker event, and forwards to the in-process Multi-Connect gateway for Web Push delivery to the phone. Request Body { \"notification_type\": \"task_complete\", \"title\": \"Task completed\", \"message\": \"Alice finished 'Add dark mode'\", \"session_id\": \"abc123\", \"agent_name\": \"Alice\", \"cwd\": \"H:\\\\DevLaptop\\\\ClarionPowerShell\\\\MultiTerminal\" } Response { \"success\": true, \"id\": \"ntf12345\" } curl curl -X POST http://localhost:5050/api/notifications \\ -H \"Content-Type: application/json\" \\ -d '{\"notification_type\":\"task_complete\",\"title\":\"Task completed\",\"message\":\"Alice finished task\"}' GET /api/notifications Query notification history. Query Parameters Param Type Default Description limit integer 50 Max notifications (max 500) unreadOnly boolean false Only return unread notifications Response [ { \"id\": \"ntf12345\", \"notificationType\": \"task_complete\", \"title\": \"Task completed\", \"message\": \"Alice finished 'Add dark mode'\", \"agentName\": \"Alice\", \"readAt\": null, \"createdAt\": \"2026-03-10T10:00:00Z\" } ] curl curl \"http://localhost:5050/api/notificatio"},{"id":"owner-profile","t":"Owner Profile","x":"Owner identity and git configuration. Used by agents for git operations. Endpoints are under /api/owner-profile . GET /api/owner-profile Get the owner profile (git identity, GitHub config). Response { \"configured\": true, \"fullName\": \"Jane Smith\", \"email\": \"user@example.com\", \"gitHubUsername\": \"jhickey\", \"hasGitHubToken\": true, \"createdAt\": \"2026-02-01T10:00:00Z\", \"updatedAt\": \"2026-03-01T10:00:00Z\" } curl curl http://localhost:5050/api/owner-profile GET /api/owner-profile/github-token Get the GitHub token for agent use during git operations. Returns 404 if no token is stored. Response { \"token\": \"ghp_xxxx...\" } curl curl http://localhost:5050/api/owner-profile/github-token"},{"id":"companions","t":"Companions","x":"Status of configured companion processes (external services managed by MultiTerminal). Endpoints are under /api/companions . GET /api/companions/status Get the status of all configured companion processes. Response [ { \"name\": \"MCP Gateway\", \"status\": \"running\", \"pid\": 12345 } ] curl curl http://localhost:5050/api/companions/status"},{"id":"gateway","t":"MCP Gateway","x":"Query MCP Gateway server status and discovered tools. Reads from the gateway's SQLite database. Endpoints are under /api/gateway . GET /api/gateway/servers List all gateway backend servers with live connection status and tool counts. Response { \"servers\": [ { \"name\": \"sqlite\", \"connected\": true, \"enabled\": true, \"toolCount\": 12 } ], \"summary\": { \"total\": 5, \"connected\": 4, \"enabled\": 5, \"totalTools\": 45 } } curl curl http://localhost:5050/api/gateway/servers GET /api/gateway/tools List all discovered tools across all connected gateway backends. Filter by server or profile. Query Parameters Param Type Default Description server string - Filter by server name profile string - Filter by gateway profile Response { \"profile\": \"(all)\", \"totalTools\": 45, \"serverBreakdown\": [ { \"server\": \"sqlite\", \"toolCount\": 12 } ], \"tools\": [ { \"serverName\": \"sqlite\", \"toolName\": \"query\", \"description\": \"Execute a SQL query\" } ] } curl curl \"http://localhost:5050/api/gateway/tools?server=sqlite\" GET /api/gateway/tools/{server__toolname} Get a specific tool's full schema by namespaced name (format: server__toolname ). Response { \"serverName\": \"sqlite\", \"toolName\": \"query\", \"description\": \"Execute a SQL query\", \"inputSchema\": { ... } } curl curl http://localhost:5050/api/gateway/tools/sqlite__query"},{"id":"browser-tabs","t":"Browser Tabs","x":"Per-terminal tabbed browser (WebView2) management. All endpoints use POST with JSON bodies. Endpoints are under /api/browser-tabs . POST /api/browser-tabs/open Open a new browser tab in a terminal's HUD area. Request Body { \"terminalId\": \"Alice\", \"title\": \"Dashboard\", \"url\": \"file:///H:/docs/index.html\", \"content\": null } Response { \"success\": true, \"tabId\": \"tab-abc123\" } curl curl -X POST http://localhost:5050/api/browser-tabs/open \\ -H \"Content-Type: application/json\" \\ -d '{\"terminalId\":\"Alice\",\"title\":\"Dashboard\",\"content\":\"<h1>Hello</h1>\"}' POST /api/browser-tabs/update Update an existing browser tab's content, URL, or title. Request Body { \"terminalId\": \"Alice\", \"tabId\": \"tab-abc123\", \"title\": \"Updated Dashboard\", \"content\": \"<h1>Updated</h1>\" } Response { \"success\": true } curl curl -X POST http://localhost:5050/api/browser-tabs/update \\ -H \"Content-Type: application/json\" \\ -d '{\"terminalId\":\"Alice\",\"tabId\":\"tab-abc123\",\"content\":\"<h1>Updated</h1>\"}' POST /api/browser-tabs/close Close a browser tab. Request Body { \"terminalId\": \"Alice\", \"tabId\": \"tab-abc123\" } Response { \"success\": true } curl curl -X POST http://localhost:5050/api/browser-tabs/close \\ -H \"Content-Type: application/json\" \\ -d '{\"terminalId\":\"Alice\",\"tabId\":\"tab-abc123\"}' POST /api/browser-tabs/execute-script Execute JavaScript in a browser tab and return the result. Request Body { \"terminalId\": \"Alice\""},{"id":"terminal-stream","t":"Terminal Streaming","x":"WebSocket endpoint for real-time terminal I/O streaming. Binary frames carry raw VT/ANSI escape sequences; text frames carry JSON control messages. GET /api/terminal/{id}/stream WebSocket endpoint for streaming terminal I/O. Upgrades HTTP to WebSocket. Protocol: binary frames = raw terminal I/O, text frames = JSON control messages (resize, disconnect, status). Note This is a WebSocket endpoint. Use a WebSocket client, not curl. // JavaScript example const ws = new WebSocket(\"ws://localhost:5050/api/terminal/my-terminal/stream\"); ws.binaryType = \"arraybuffer\"; ws.onmessage = (e) => { /* handle terminal output */ }; GET /api/terminal/streams List active terminal streams with subscriber counts. Response { \"streams\": [ { \"terminalId\": \"Alice\", \"subscriberCount\": 2 }, { \"terminalId\": \"Bob\", \"subscriberCount\": 1 } ] } curl curl http://localhost:5050/api/terminal/streams"},{"id":"xaml","t":"XAML Preview","x":"Render WPF XAML to PNG images for visual preview without launching the app. Endpoints are under /api/xaml . POST /api/xaml/render Render a WPF XAML snippet to a base64-encoded PNG image. Runs on an STA thread for WPF rendering. Request Body { \"xaml\": \"<Border xmlns='http://schemas.microsoft.com/winfx/2006/xaml/presentation' Background='#1e1e2e' Padding='20'><TextBlock Text='Hello World' Foreground='White' FontSize='24'/></Border>\", \"width\": 520, \"height\": 400 } Field Type Required Default Description xaml string Yes - WPF XAML markup (must include xmlns) width integer No 520 Render width in pixels height integer No 400 Render height in pixels Response { \"success\": true, \"imageBase64\": \"iVBORw0KGgoAAAANSUhEUgAA...\", \"width\": 520, \"height\": 400 } curl curl -X POST http://localhost:5050/api/xaml/render \\ -H \"Content-Type: application/json\" \\ -d '{\"xaml\":\"<Border xmlns=...>...</Border>\",\"width\":520,\"height\":400}'"},{"id":"code-graph","t":"Code Graph","x":"Query the Roslyn-built C# code graph (symbols and their relationships). Endpoints are under /api/code-graph . Registered C# projects are indexed automatically by the CodeGraphWatcher background service — it sweeps and refreshes stale graphs shortly after app startup and re-indexes on edit, so you normally don't index by hand. Read endpoints return 503 {\"error\":\"CodeGraph not available\"} only before the project has been indexed (e.g. the brief window before the startup sweep completes, or for a directory that isn't a registered project). To index any directory immediately, use POST /api/code-graph/index (or the index_code_graph MCP tool). The callers , callees , impact , and inheritance endpoints accept either symbolId (preferred, from a search result) or symbolName . GET /api/code-graph/search Search symbols by name, with an optional type filter. Query Parameters Param Type Required Description query string Yes Symbol name to search for type string No Filter by symbol type: class , method , interface , etc. Response { \"success\": true, \"count\": 1, \"results\": [ { \"id\": 42, \"name\": \"MessageBroker\", \"type\": \"class\", \"filePath\": \"MCPServer/Services/MessageBroker.cs\", \"line\": 35 } ] } curl curl \"http://localhost:5050/api/code-graph/search?query=MessageBroker&type=class\" GET /api/code-graph/callers Get the direct callers of a symbol. Query Parameters Param Type Required Description sy"},{"id":"branch-metadata","t":"Branch Metadata","x":"Per-branch outcome labels (the one-line \"what this branch delivers\" shown on branch rows) and the task context an agent uses to draft them. Endpoints are under /api/branch-metadata/{projectId} . The project must be registered — unknown project IDs return 404 {\"error\":\"unknown project\"} . The branch name travels in the body (POST) or the branch query string (GET) rather than the URL path, so names containing / (the task/<id> convention) round-trip without route-escaping issues. POST /api/branch-metadata/{projectId}/outcome Upsert the outcome label for a branch. Request Body { \"branchName\": \"task/9f9c3141\", \"outcome\": \"Allow agents to search past sessions by meaning\", \"draftedBy\": \"Alice\" } Response { \"projectId\": \"proj-123\", \"branchName\": \"task/9f9c3141\", \"outcome\": \"Allow agents to search past sessions by meaning\", \"draftedBy\": \"Alice\", \"updatedAt\": \"2026-06-27T10:00:00Z\" } curl curl -X POST http://localhost:5050/api/branch-metadata/proj-123/outcome \\ -H \"Content-Type: application/json\" \\ -d '{\"branchName\":\"task/9f9c3141\",\"outcome\":\"Allow agents to search past sessions by meaning\",\"draftedBy\":\"Alice\"}' GET /api/branch-metadata/{projectId}/draft-context Get the task context an agent needs to draft an outcome for a branch (the agent does the rewrite; this only fetches context). Resolves the source task from originatingTaskId if supplied (must belong to the same project), otherwis"}]},{"u":"architecture.html","t":"Architecture","s":[{"id":"","t":"Architecture","x":"MultiTerminal is a WinForms desktop application (C#/.NET) with an integrated REST API, MCP server, and WebView2-based UI panels. This page describes the system layers, data flow, database schema, and key patterns."},{"id":"","t":"On This Page","x":"System Overview Critical Files Data Flow Database Schema The %APPDATA%\\multiterminal Data Folder MessageBroker Events Key Patterns Folder Map"},{"id":"overview","t":"System Overview","x":"The system is organized into five distinct layers, with the MessageBroker serving as the central hub connecting everything together. UI Host MainForm.cs · ~5.2K LOC Hosts the VS-style docking framework, owns the toolbar and terminal lifecycle, and wires every panel to the MessageBroker through C# events. Renders 11 WebView2 panels: TasksPanel Kanban board — create, claim and drag tasks across To Do / In Progress / Done; edit the plan and checklist. ChatPanel Inter-terminal messaging UI — point-to-point and broadcast, with persistent history. ActivityPanel Live activity feed of tool use, builds, and task changes across all terminals. ProfilePanel Team-member profiles — avatar, role, skills, and online/availability state. InboxPanel Notification center for checklist transitions, help requests, and alerts (unread badge). ProjectPanel Browse and edit registered projects: agents, MCP servers, named paths, prompts. LauncherPanel Launch app/agent processes and companion tools. OfficePanel Animated office visualization of spawned agents presence and activity. AgentPanel Read-only live transcript stream of a spawned team agent. DebugPanel Internal debug log (pause / resume / clear) for troubleshooting. FilePreviewPanel In-app preview of files — HTML, Markdown, images. Also in this layer: Terminal/ (ConPTY terminals rendered in WebView2), Docking/ (GridLayoutManager grid presets + layout"},{"id":"critical-files","t":"Critical Files","x":"These files contain the majority of the system's logic. Read them first when onboarding. File LOC Role MCPServer/Services/MessageBroker.cs ~5,512 Central hub. Routes all messages, caches tasks/terminals/profiles in ConcurrentDictionaries, delivers webhooks, fires 19 events. Everything flows through here. Services/TaskDatabase.cs ~4,621 Persistence. SQLite CRUD for 21+ tables: tasks, sessions, knowledge, reports, profiles, activity, attachments, and more. MainForm.cs ~5,162 UI host. Creates/docks panels, wires events between panels and MessageBroker, manages terminal lifecycle. MCPServer/Models/KanbanTask.cs ~500 Core model. All task properties: status, assignee, checklists, plan, helpers, stale tracking, continuation notes, plus all result types. Services/ProjectDatabase.cs ~1,100 Project persistence. SQLite CRUD for projects and all 6 association tables (agents, MCP servers, specialists, paths, prompts, skills). API/Controllers/TasksController.cs ~505 Tasks REST API. All task, checklist, inbox, and attachment endpoints. Largest controller."},{"id":"data-flow","t":"Data Flow","x":"Here is how a typical operation (e.g., creating a task) flows through the system."},{"id":"","t":"Agent Creates a Task","x":"1. Claude Code Agent Calls create_task(title=\"Fix bug\", ...) via MCP tool 2. MCP Server (Node.js) Translates to POST /api/tasks with JSON body 3. TasksController Validates request, calls _broker.CreateTask(...) 4. MessageBroker Creates KanbanTask object, adds to cache, calls _taskDb.SaveTask(...) , fires TasksUpdated event 5a. TaskDatabase Persists to SQLite tasks table 5b. MainForm (event handler) Receives TasksUpdated event, refreshes TasksPanel UI 5c. ActivityService Records activity event to feed"},{"id":"","t":"Checklist Item Transition","x":"1. Agent calls update_task_checklist taskId, itemIndex=0, newStatus=\"testing\", notes=\"Done implementing\" 2. MessageBroker.TransitionChecklistItem() Validates state machine: coding → testing allowed. Updates item status, appends notes, increments cycle count if cycling. 3a. TaskDatabase Saves updated checklist_json 3b. Inbox Notification Creates ready_for_testing inbox message for PM 3c. Escalation Check If cycleCount >= 3, creates escalation inbox message"},{"id":"","t":"Host-Controlled Memory Architecture","x":"MultiTerminal inverts the standard Claude Code context model. Instead of agents reading static files (CLAUDE.md, memory.md) and deciding what to remember, the host controls context injection through three mechanisms: Session continuity — hooks track session→agent mappings, auto-sync JSONL transcripts, and inject the agent's own last-session recap at startup Knowledge injection — hooks query SQLite at session start, rank entries by attention decay, and inject the most relevant knowledge before the agent sees any prompt Subprocess isolation — spawned agents receive a per-agent system prompt file and scoped settings, bypassing global CLAUDE.md and user-level hooks entirely The following sections detail each mechanism. Session Sync Pipeline (End-to-End) Every Claude Code session is automatically tracked and imported into the session database, preserving which agent ran it and providing session continuity across restarts. Phase 1: Session Start (Hook) 1. Claude Code starts a session Creates JSONL file: ~/.claude/projects/{folder}/{session-id}.jsonl 2. session-status-hook.js (SessionStart) Reads MULTITERMINAL_NAME env var + hookData.session_id . Writes (session_id, agent_name, is_active=1) to session_agent_map table. 3. Profile marked online Same hook upserts team_member_profiles with is_online=1 . Phase 2: Session End (Hook) 1. Claude Code session ends JSONL file is complete. sessio"},{"id":"database-schema","t":"Database Schema","x":"All data is stored under your per-user data folder, %APPDATA%\\multiterminal (typically C:\\Users\\<you>\\AppData\\Roaming\\multiterminal ). The primary database is multiterminal.db , which holds most tables."},{"id":"data-folder","t":"The %APPDATA%\\multiterminal Data Folder","x":"Everything MultiTerminal persists for the current user lives here — the databases, the configuration files, the bundled MCP server, and runtime logs. Nothing is written under the install directory, so the app can run from a read-only location and a single folder holds all your state. Databases Item Purpose multiterminal.db Primary store — tasks & checklists, sessions & lineage, knowledge, projects, code graph, profiles, and activity. Runs in SQLite WAL mode, so you'll also see transient multiterminal.db-wal and -shm sidecar files. messages.db Reliable inter-terminal message-delivery queue (retry + de-duplication), kept separate so delivery survives restarts independently. (Also has -wal / -shm sidecars.) Configuration & state files Item Purpose .mcp.json Registers the two stdio MCP servers ( multiterminal + mcp-gateway ). Claude Code is pointed at it with --mcp-config . Generated by the installer. settings.txt User/app settings ( key=value ). Per-install Multi-Connect and Presence overrides are written here and win over appsettings.json . layout.xml Saved docking layout — panel positions, sizes, and visibility (restored on next launch). .bak is the previous layout. companion-processes.json Companion processes MultiTerminal auto-launches on startup (e.g. the phone gateway). push-config.json Web-Push VAPID identity + your phones' push subscriptions (Multi-Connect notifications). "},{"id":"","t":"multiterminal.db - Core Tables","x":"tasks Primary kanban task storage. Column Type Description id TEXT PK 8-char hex GUID title TEXT NOT NULL Task title description TEXT Task description status TEXT NOT NULL todo, in_progress, done, suggestion assignee TEXT Claimed agent name created_by TEXT Creator name created_at DATETIME Creation timestamp updated_at DATETIME Last update timestamp priority TEXT low, normal, high sub_status TEXT active, paused (for in_progress tasks) paused_at DATETIME When task was paused checklist_json TEXT JSON array of checklist items plan TEXT Markdown implementation plan implementation_summary TEXT What was built (markdown) test_results TEXT Test outcomes (markdown) continuation_notes TEXT Session handoff context auto_status INTEGER Auto-derive status from checklist project_id TEXT FK to projects flagged_stale_at DATETIME When flagged as stale stale_level INTEGER 0=fresh, 1=7day, 2=14day stale_response TEXT User response to stale notification task_helpers Helper assignments for collaborative tasks. Column Type Description id TEXT PK Helper record ID task_id TEXT FK References tasks.id helper_name TEXT Helper agent name added_by TEXT Who added the helper added_at DATETIME When added terminal_activity Current state of each terminal. Column Type Description terminal TEXT PK Terminal name status TEXT idle, working, blocked activity TEXT Current activity description blocked_by TEXT What is blo"},{"id":"","t":"multiterminal.db - Session Lineage Tables","x":"session_lineage Tracks parent/child relationships between Claude Code sessions. Column Type Description id INTEGER PK Auto-increment session_id TEXT UNIQUE Session identifier parent_session_id TEXT Parent for lineage chaining task_id TEXT FK Linked kanban task agent_name TEXT Agent who ran the session session_type TEXT coding, review, testing, terminal summary TEXT Generated session summary session_file_path TEXT Path to JSONL transcript started_at TEXT Session start time ended_at TEXT Session end time session_messages Individual messages extracted from session JSONL files. Column Type Description id INTEGER PK Auto-increment session_id TEXT FK References session_lineage.session_id task_id TEXT Linked task (denormalized) agent_name TEXT Agent name (denormalized) message_index INTEGER Position in session role TEXT user or assistant content TEXT Message content tool_name TEXT Tool used (if any) timestamp TEXT Message timestamp session_messages_fts FTS5 virtual table for full-text search across session messages. Columns indexed: content , role , agent_name , tool_name . Content sourced from session_messages . session_agent_map Maps session IDs to agent names. Written by session-status-hook.js on SessionStart/SessionEnd. Used during auto-sync to resolve agent names and skip active sessions. Column Type Description session_id TEXT PK Claude Code session GUID agent_name TEXT Terminal"},{"id":"","t":"multiterminal.db - Knowledge Tables","x":"knowledge_entries Institutional memory: decisions, patterns, gotchas, anti-patterns. Column Type Description id INTEGER PK Auto-increment project_id TEXT Project scope (null = global) category TEXT decision, pattern, gotcha, anti_pattern, debug_insight, preference title TEXT Short summary title content TEXT Full knowledge content source_type TEXT manual, session, debug, review source_id TEXT Reference ID (session, task) source_agent TEXT Agent who contributed tags TEXT Comma-separated tags confidence TEXT confirmed, likely, uncertain superseded_by INTEGER ID of replacement entry last_referenced TEXT ISO timestamp of last access (search or injection). Used by attention decay ranking. reference_count INTEGER Total access count. Bumped on every search hit and session injection. knowledge_entries_fts FTS5 virtual table for full-text search across knowledge entries. Columns indexed: title , content , tags . Content sourced from knowledge_entries . code_digests Per-file summaries for fast agent orientation. Column Type Description id INTEGER PK Auto-increment project_id TEXT Project scope file_path TEXT Absolute path to source file file_hash TEXT SHA256 for staleness detection purpose TEXT One-sentence file description key_classes TEXT JSON array of class names key_methods TEXT JSON array of method names patterns TEXT Notable patterns gotchas TEXT Pitfalls and gotchas dependencies TE"},{"id":"","t":"multiterminal.db - Project Tables (ProjectDatabase.cs)","x":"projects (extended) Project registry with full metadata. Enhanced version with additional columns beyond the core record. Column Type Description id TEXT PK Project GUID name TEXT Project name description TEXT Project description path TEXT Source path source_path TEXT Source code location deploy_path TEXT Deploy output location build_output_path TEXT Build output directory build_command TEXT Build command deploy_command TEXT Deploy command launch_command TEXT Launch command project_type TEXT Project archetype current_version TEXT Current version string is_pinned INTEGER Pinned to dashboard icon TEXT Icon identifier icon_color TEXT Icon color team_lead TEXT Team lead name git_repo_url TEXT Git repository URL git_default_branch TEXT Default git branch git_auto_commit INTEGER Auto-commit enabled project_agents Agents assigned to a project. Column Type Description id INTEGER PK Auto-increment project_id TEXT FK References projects.id agent_name TEXT Agent name role TEXT Agent role preferred_model TEXT opus, sonnet, haiku project_mcp_servers MCP servers configured for a project. Column Type Description id INTEGER PK Auto-increment project_id TEXT FK References projects.id server_name TEXT Server name is_enabled INTEGER Enabled flag project_specialist_agents Specialist agents (devils-advocate, verifier, etc.) for a project. Column Type Description id INTEGER PK Auto-increment project"},{"id":"events","t":"MessageBroker Events","x":"The MessageBroker fires C# events that MainForm subscribes to for updating the UI. All events are thread-safe and marshaled to the UI thread. Event Payload When Fired MessageSent Message Inter-terminal message delivered TerminalRegistered TerminalInfo New terminal registers TerminalDisconnected TerminalInfo Terminal disconnects TasksUpdated List<KanbanTask> Any task created, updated, or deleted TaskClaimed TaskClaimedEventArgs Task assigned to an agent ActivityRecorded ActivityEvent Activity feed event recorded PlanUpdated PlanUpdateEventArgs Task plan created or modified ProjectsUpdated List<Project> Project list changed ProfilesUpdated List<TeamMemberProfile> Team profiles changed HelperSessionUpdated HelperSession Helper session state changed HelperMessageLogged HelperMessage Helper message logged InboxUpdated InboxUpdatedEventArgs Inbox message created or read OfficeAgentSpawned OfficeAgentInfo Agent walks into office panel OfficeAgentDeparted OfficeAgentInfo Agent leaves office panel AgentPanelCloseRequested string (transcript path) Subagent finished, close panel ReportSaved ReportSavedEventArgs Agent pipeline report saved for a task NotificationReceived NotificationEventArgs Push notification received from hooks BrowserTabRequested BrowserTabEventArgs Agent requested a browser tab in HUD SessionLineageUpdated string (task ID) Session imported or synced"},{"id":"patterns","t":"Key Patterns","x":""},{"id":"","t":"Adding a UI Panel","x":"Create {Name}Panel/{Name}PanelDocument.cs inheriting DockContent (set DockAreas , HideOnClose=true ) Create inner control with WebView2 or custom renderer Add Initialize(MessageBroker broker) and ApplyTheme(bool isDark) methods In MainForm: instantiate, call Initialize() , wire events, add toolbar toggle button Follow existing panels (TasksPanel, ActivityPanel) as templates"},{"id":"","t":"Adding a Backend Feature","x":"Add model to MCPServer/Models/ Add persistence to TaskDatabase.cs (table + CRUD methods + migration) Add routing to MessageBroker.cs (methods + events) Add MCP tool to MCPServer/Tools/ (or index.js ) if agents need access Add REST endpoint to API/Controllers/ if HTTP access needed"},{"id":"","t":"Adding an MCP Tool","x":"Add tool definition to the tools array in %APPDATA%\\multiterminal\\mcp\\index.js Add handler in the CallToolRequestSchema switch block in the same file Tool handler calls the REST API which delegates to MessageBroker which delegates to TaskDatabase Return formatted text result for the agent"},{"id":"","t":"Adding a REST Endpoint","x":"Add method to the appropriate controller in API/Controllers/ Add request model class if needed (same file or separate) Controller calls MessageBroker (for shared logic) or database directly (for reads) Update ToolsController.cs to include the new endpoint in the self-documenting list"},{"id":"","t":"Data Storage Patterns","x":"Checklists: JSON array in checklist_json column: [{\"item\":\"...\",\"status\":\"pending|coding|testing|done\",\"notes\":[{\"text\":\"...\",\"at\":\"...\",\"by\":\"...\"}],\"assignee\":\"...\",\"cycleCount\":0}] Plans: Markdown text in plan column Continuation notes: Free text in continuation_notes column (session handoff context) Skills/interests: JSON arrays in profile columns ( skills_json , interests_json ) Migrations: Manual column-check migrations in database constructors (uses PRAGMA table_info + ALTER TABLE ADD COLUMN )"},{"id":"","t":"Checklist State Machine","x":"+----------+ | pending | +----+-----+ | (start work) | +----v-----+ +--->| coding | testing->coding loop. At 3 cycles, escalation inbox notification is sent to PM."},{"id":"folder-map","t":"Folder Map","x":"Folder Purpose Key Files Services/ Business logic & SQLite persistence TaskDatabase, ProjectService, ProjectDatabase, ProjectContextService, ProjectJsonMigrationService, TerminalSpawner, SettingsService, KnowledgeDatabase, DebugLogService, TeamWatcherService, CompanionProcessManager, GatewayIntegrationService, OwnerProfileService, RipgrepService, TerminalStreamService MCPServer/Services/ MCP server services MessageBroker , PoolCoordinator, ActivityService, StaleTaskService, SpawnService, HttpWebhookService, SessionDiscovery, ComplexityDetector, SummaryService MCPServer/Models/ Data models (19 files) KanbanTask, Plan, Message, InboxMessage, TeamMemberProfile, TaskSummary, HelperSession, CodeDigest, KnowledgeEntry, ActivityEvent, TerminalInfo, TaskAttachment, ComplexityStats Models/ App-level models (8+ files) TerminalSessionInfo, SpawnedTeammate, Project, ProjectAgent, ProjectMcpServer, ProjectSpecialistAgent, ProjectPath, ProjectPromptEntry, ProjectSkill, DebugLogEntry API/Controllers/ REST endpoints (~25 controllers) TasksController, MessagingController, OfficeController, SpawnController, KnowledgeController, SessionLineageController, ProjectContextController, TeamController, DebugController, ToolsController, AgentPanelsController, AgentStatsController, BrowserTabsController, CompanionController, GatewayController, NotificationsController, OwnerProfileController, TaskReportsCo"},{"id":"","t":"Codebase Statistics","x":"~150 C# production files , ~30K+ lines of code 1 primary SQLite database (multiterminal.db) with 30+ tables 19 data models , ~90 MCP tools , ~25 REST controllers 11 UI panels (WebView2-based), 11 dialog windows REST API on port 5050, MCP server via Node.js (stdio transport)"}]},{"u":"branch-outcomes-wiki.html","t":"Branch Outcomes & Wiki","s":[{"id":"","t":"Branch Outcomes & Wiki","x":"Two metadata subsystems that label your work without cluttering it: branch outcomes attach a one-sentence capability statement to each branch, and the wiki generator auto-builds per-subsystem reference articles from the code graph."},{"id":"","t":"On This Page","x":"Branch outcomes Branch-outcome MCP tools Branch-outcome REST endpoints Wiki generator Wiki MCP tools Wiki REST endpoints The wiki manifest"},{"id":"outcomes","t":"Branch outcomes","x":"A branch's outcome is the user-facing capability the branch delivers — distinct from the commit subjects or task titles inside it. Where a commit log says \"fix null deref in exporter\" and \"add CSV column,\" the outcome says what the user gets: Allow users to export reports as CSV Each outcome is one short sentence (aimed at ≤ 15 words — these are tree-row labels, not paragraphs), stored per (project, branch) with the author ( draftedBy ) and an updatedAt timestamp. The UI uses it to label branches in the git panel without forcing that prose into commit messages. Outcomes are persisted in the branch_metadata table as an idempotent upsert keyed by (project_id, branch_name) — re-setting an outcome overwrites the prior value. Branch names keep their / (the project's task/<id> convention) because the branch name travels in the request body/query, never as a URL path segment."},{"id":"","t":"Drafting vs. setting","x":"Drafting and setting are deliberately separate steps. Drafting fetches the originating task's title and description plus a prompt hint; the calling agent rewrites that into the one-sentence capability. Setting persists the final text. The draft endpoint never writes — it only gathers context, and it treats task fields strictly as untrusted data."},{"id":"outcomes-tools","t":"Branch-outcome MCP tools","x":"Tool Purpose draft_branch_outcome Fetch the originating task's title/description + prompt hint so the agent can compose a one-sentence outcome. Read-only. set_branch_outcome Upsert the final outcome text for a (project, branch) pair. get_branch_outcomes List all stored outcomes for a project."},{"id":"outcomes-rest","t":"Branch-outcome REST endpoints","x":"All under /api/branch-metadata on http://localhost:5050 . The projectId must be a registered project; arbitrary ids are rejected to prevent phantom rows and cross-project leakage. # Draft context for an outcome (read-only) GET /api/branch-metadata/{projectId}/draft-context?branch=task/c0ce8037 # Persist an outcome (branchName in the body so \"/\" round-trips) POST /api/branch-metadata/{projectId}/outcome { \"branchName\": \"task/c0ce8037\", \"outcome\": \"Allow users to export reports as CSV\", \"draftedBy\": \"agent\" } # List all outcomes for a project GET /api/branch-metadata/{projectId}/outcomes A successful set returns the saved row: { \"projectId\": \"proj-123\", \"branchName\": \"task/c0ce8037\", \"outcome\": \"Allow users to export reports as CSV\", \"draftedBy\": \"agent\", \"updatedAt\": \"2026-06-27T10:30:00Z\" } Saving an outcome fires a BranchOutcomeUpdated event, which prompts the HUD git renderer to refresh its branch labels."},{"id":"wiki","t":"Wiki generator","x":"The wiki generator builds per- subsystem markdown articles from the code graph, the code digests, and parsed controller routes — then writes them under .claude/wiki/ . A subsystem is a coherent module that spans several files (e.g. \"Messaging\" = Message.cs + MessageBroker.cs + MessagingController.cs + the chat panel). The point is targeted session-start context: load a ~200-token index.md at the start of a session and fetch a specific ~500-token subsystem article only when you touch that area, instead of re-deriving structure from raw source every time. Each generated article aggregates: Key files with line counts and a one-line purpose pulled from the file's code digest. Key classes & methods (public/internal) with file:line references from the code graph. Routes parsed from controller [HttpGet] / [Route] attributes. External callers — symbols outside the subsystem that call into it, derived from the call graph. Gotchas aggregated from the root files' code digests."},{"id":"","t":"Prerequisite: an indexed code graph","x":"Articles are assembled from the code graph and code digests, so index the project first (see the Code Graph guide). Without an index, articles still render from the manifest but key classes, methods, routes, and callers will be sparse."},{"id":"wiki-tools","t":"Wiki MCP tools","x":"Tool Purpose generate_wiki Regenerate all articles for a project (or one, when a subsystem id is given). Writes .claude/wiki/*.md + index.md . list_wiki_articles List the articles currently on disk for a project (id, name, description, tags, generated timestamp) without regenerating. get_wiki_article Fetch the markdown body of a single article by id."},{"id":"wiki-rest","t":"Wiki REST endpoints","x":"All under /api/wiki on http://localhost:5050 . The projectRoot must resolve to an existing directory; subsystem ids are restricted to ^[A-Za-z0-9_-]{1,64}$ so they round-trip safely through the filesystem. # Regenerate every article (omit subsystemId for \"all\") POST /api/wiki/generate { \"projectRoot\": \"H:\\\\DevLaptop\\\\...\\\\MultiTerminal\", \"projectId\": \"proj-123\", \"subsystemId\": null } # List articles on disk GET /api/wiki/articles?projectRoot=H%3A%5CDevLaptop%5C...%5CMultiTerminal # Fetch one article's markdown GET /api/wiki/articles/{id}?projectRoot=H%3A%5CDevLaptop%5C...%5CMultiTerminal A full generate returns a per-article summary: { \"success\": true, \"count\": 12, \"articles\": [ { \"id\": \"messaging\", \"name\": \"Messaging\", \"classCount\": 4, \"methodCount\": 18, \"routeCount\": 6, \"fileCount\": 4, \"markdownBytes\": 5120 } ] }"},{"id":"wiki-manifest","t":"The wiki manifest","x":"The generator is driven by .claude/wiki/wiki-manifest.json , which declares each subsystem: its id, display name, description, tags, root files, and an optional controller glob. The manifest is a trusted, in-repo artifact (authored by maintainers, not request bodies). If no manifest exists, generate_wiki reports that none was found rather than guessing the project's structure. Generated articles and the index.md are plain markdown — diff-able, committable, and meant to be read by agents at session start."}]},{"u":"channels.html","t":"Channels (Messaging)","s":[{"id":"","t":"Channels (Messaging)","x":"MultiTerminal delivers agent-to-agent messages through Claude Code's native Channels transport. Each terminal runs a small channel server that pushes incoming messages straight into the session as structured <channel> events — replacing the older [cm] \"check messages\" nudge. Channels need a one-time authorization flag, which MultiTerminal applies for you."},{"id":"","t":"On This Page","x":"What channels are How a message flows The channel server Enabling channels (the required setting) Environment variables Sending & replying Legacy: the [cm] nudge"},{"id":"channels","t":"What channels are","x":"A channel is a first-class Claude Code transport for pushing messages into a running session. When another agent (or the desktop) sends you a message, it arrives inline as a structured event: <channel source=\"multiterminal\" from=\"Diana\" priority=\"normal\"> Can you take the API page? I'll start on presence. </channel> You react to it immediately and reply with the channel's tools — no polling, no terminal-injected reminders. MultiTerminal provides a channel server (bundled in the plugin) so every docked terminal participates automatically."},{"id":"flow","t":"How a message flows","x":"Each terminal's channel server starts up and registers its listen port with the MultiTerminal broker ( POST /api/messaging/register with its agent name + channelPort ). An agent calls send_message (or a skill does). The broker looks up the recipient's registered channelPort . The broker delivers the message over HTTP to that port. The recipient's channel server pushes it into the Claude Code session as a <channel> event. The receiving agent reads it and replies with the channel reply / send tools, which route back through the broker."},{"id":"server","t":"The channel server","x":"The server is bundled with the plugin at server/multiterminal-channel.mjs and declared in the plugin's plugin.json : \"mcpServers\": { \"multiterminal-channel\": { \"command\": \"node\", \"args\": [\"${CLAUDE_PLUGIN_ROOT}/server/multiterminal-channel.mjs\"] } }, \"channels\": [ { \"server\": \"multiterminal-channel\" } ] It runs as an MCP server (stdio) for the session, and in parallel opens a small HTTP listener that the broker delivers messages to. If its preferred port is busy it walks forward through the allowed range ( 8800 – 8899 ) until it finds a free one, then re-registers the actual port with the broker, so multiple terminals on one machine don't collide. The same channel also carries tool-permission prompts to the phone: when Claude needs approval to run a tool, the server forwards the request to your phone (via Multi-Connect ) so you can answer remotely — reply yes , no , or always with the short request id to approve, deny, or auto-approve that tool for the session."},{"id":"setting","t":"Enabling channels (the required setting)","x":"The channel server ships inside the plugin rather than from a published marketplace, so Claude Code treats it as a development (inline) channel . Development channels must be explicitly authorized — otherwise Claude Code will not load the channel server. MultiTerminal launches every terminal with two flags: # MultiTerminal applies these automatically when it spawns a terminal claude \\ --plugin-dir <path-to-multiterminal-plugin> \\ --dangerously-load-development-channels plugin:multiterminal@inline --plugin-dir loads the MultiTerminal plugin (hooks, skills, agents, and the channel server) for that session. --dangerously-load-development-channels plugin:multiterminal@inline authorizes the plugin's inline channel server. (Plugins loaded via --plugin-dir are sourced as name@inline .) For MultiTerminal terminals this is automatic — the launch builder adds both flags, so channels just work in any docked terminal. You only need to pass the flags yourself if you run Claude Code by hand (outside MultiTerminal) and want the same channel messaging."},{"id":"env","t":"Environment variables","x":"When MultiTerminal spawns a terminal it injects two of these — MULTITERMINAL_NAME and CHANNEL_PORT — so the channel server knows who it is and which port to listen on. The other two are not set by MultiTerminal; the channel server falls back to its own defaults: Variable Purpose Set by MT? Default MULTITERMINAL_NAME This terminal's agent name (e.g. Alice ) Yes unknown CHANNEL_PORT HTTP port the channel server listens on for incoming messages (MultiTerminal assigns a unique one per terminal, within 8800 – 8899 ) Yes 8800 MT_API_URL MultiTerminal REST API base URL used for registration/routing No — uses default http://localhost:5050 MULTITERMINAL_ID Intended for send_message routing, but effectively unused — the broker resolves terminals by agent name, so the server sends under MULTITERMINAL_NAME instead No — uses default (empty) So in practice only the agent name and the channel port come from the launcher. MT_API_URL defaults to the local REST API, and the empty MULTITERMINAL_ID is harmless because routing is name-based."},{"id":"using","t":"Sending & replying","x":"From an agent's point of view, channel messaging is just tools and events: Receive: messages arrive as <channel source=\"multiterminal\" from=\"…\"> events — treat them the same as any teammate message and act on them. Reply: use the channel reply tool (answer the sender) or send tool (message any agent by name). Broker tools: the broader MCP surface ( send_message , broadcast_message , get_messages ) still works and routes through the same broker. See MCP Tools ."},{"id":"legacy","t":"Legacy: the [cm] nudge","x":"Before channels, MultiTerminal surfaced inter-terminal messages with a [cm] (\"check messages\") nudge — a string injected into the terminal (originally via ConPTY) that prompted the agent to poll get_messages . That approach was indirect and easy to miss. Channels replace it with direct, structured delivery, so [cm] is now deprecated . You may still see references to the inbox-check hook (see Hooks ) for backward compatibility, but channels are the current mechanism."}]},{"u":"claude-code-internals-research.html","t":"Claude Code Internals Research Report","s":[{"id":"","t":"Executive Summary","x":"On March 31, 2026, Claude Code v2.1.88 was published to npm with a 59.8 MB source map file that exposed the full TypeScript source (1,902 files, 512K+ lines). The instructkr/claw-code repo is a clean-room Python/Rust reimplementation that preserves the architecture without copying proprietary code. This research examines the internals to optimize MultiTerminal's integration."},{"id":"","t":"Key Discoveries with Immediate Impact","x":"CLAUDE.md budget is 12,000 chars total — our project CLAUDE.md exceeds this and is being silently truncated Hook outputs via additionalContext enter context without truncation — we need to keep hook output minimal Hooks from multiple plugins are additive — explains potential double-firing issues MCP tools are deferred by default — only names loaded (~120 tokens), full schemas fetched via ToolSearch on demand Compaction preserves only ~12% of tokens — critical context must be explicitly marked for survival The channel warning can be suppressed via --dangerously-load-development-channels flag (already in LaunchCommandBuilder) CLAUDE_CODE_DISABLE_NONESSENTIAL_TRAFFIC breaks channels — it kills GrowthBook flag evaluation alongside telemetry"},{"id":"","t":"Hooks & Dispatch","x":""},{"id":"hooks-events","t":"Event Catalog (21+ Events)","x":"Phase Events Session setup SessionStart , InstructionsLoaded , ConfigChange User input UserPromptSubmit , CwdChanged Tool lifecycle PreToolUse , PermissionRequest , PostToolUse , PostToolUseFailure , Elicitation , ElicitationResult , FileChanged Agent lifecycle SubagentStart , SubagentStop , TeammateIdle , TaskCreated , TaskCompleted Session end PreCompact , PostCompact , Stop , StopFailure , SessionEnd , Notification Workspace WorktreeCreate , WorktreeRemove"},{"id":"hooks-dispatch","t":"Dispatch Rules","x":"All matching matcher groups fire — not just the first match Within each group, hooks execute sequentially in array order First blocking decision (exit code 2) stops the pipeline Hooks from plugins and settings are additive — they don't override each other Async hooks fire-and-forget; cannot block operations"},{"id":"hooks-data","t":"Data Passed to Hooks (stdin JSON)","x":"Common fields: session_id , transcript_path , cwd , permission_mode , hook_event_name PreToolUse adds: tool_name , tool_input PostToolUse adds: tool_response SubagentStop adds: success , agent_transcript_path Environment variables available: CLAUDE_SESSION_ID , CLAUDE_PROJECT_DIR , CLAUDE_ENV_FILE , CLAUDE_CODE_REMOTE , plus custom env block variables from settings.json."},{"id":"hooks-errors","t":"Error/Timeout Handling","x":"Exit Code Behavior 0 Success — parse stdout as JSON 2 Blocking error — stderr fed to Claude Other Non-blocking — Claude continues Timeout Non-blocking — Claude continues Crash Non-blocking — Claude continues Invalid JSON Non-blocking — Claude continues Default timeout: 10 minutes (configurable per-hook in seconds). Hook Output Protocol (PreToolUse) { \"hookSpecificOutput\": { \"permissionDecision\": \"allow|deny|ask\", \"updatedInput\": {\"field\": \"modified_value\"} }, \"systemMessage\": \"Explanation for Claude\" }"},{"id":"","t":"Context Window Management","x":""},{"id":"context-assembly","t":"System Prompt Assembly Order","x":"1. Intro section (agent identity, ~200 tokens) 2. Output style instructions 3. System section (core behavioral rules) 4. Doing tasks section (coding guidelines) 5. Actions section (reversibility/blast radius) ──────────────────────────────────────────── __SYSTEM_PROMPT_DYNAMIC_BOUNDARY__ (cache breakpoint) ──────────────────────────────────────────── 6. Environment section (model, cwd, date, platform) 7. Project context (CLAUDE.md discovery, git status) 8. Instruction files (all CLAUDE.md, budget-enforced) 9. Runtime config 10. Appended: skills, agents, plugins, hooks, MCP instructions Everything above the boundary (items 1-5) is static and cacheable . Everything below changes per-session ."},{"id":"context-claudemd","t":"CLAUDE.md Loading","x":"For each directory from root to cwd: {dir}/CLAUDE.md {dir}/CLAUDE.local.md {dir}/.claude/CLAUDE.md {dir}/.claude/instructions.md Budget enforcement: 4,000 chars per file, 12,000 chars total. Files exceeding limits are silently truncated. Our CLAUDE.md likely exceeds this. Loading priority: Managed policy > Project CLAUDE.md > User CLAUDE.md > Rules"},{"id":"context-layout","t":"Context Window Layout (~200K tokens)","x":"Component Typical Tokens Notes System prompt 4,200 Hidden, cached Auto memory (MEMORY.md) 680 Hidden Environment info 280 Hidden MCP tools (deferred names) 120 Hidden Skill descriptions 450 Hidden, dropped on compact ~/.claude/CLAUDE.md 320 Hidden Project CLAUDE.md 1,800 Hidden Startup overhead total ~7,850 ~3.9% of context File reads 1,100-2,400 each Dominates context Hook outputs 100-120 each No truncation! Bash outputs ~1,200 each Truncated at 30K chars"},{"id":"context-compaction","t":"Compaction","x":"Trigger: Auto when context approaches limit, or manual /compact [instructions] Preserves: Last 4 messages verbatim, CLAUDE.md (re-read from disk), auto memory, system prompt, MCP tools Drops/Summarizes: All older messages, full tool outputs, intermediate reasoning, skill descriptions Compression ratio: ~12% of original tokens retained Summary includes: Tools mentioned, recent requests, pending work, key files (up to 8), timeline"},{"id":"context-caching","t":"Prompt Caching","x":"Up to 4 cache breakpoints per API request (tools, system, messages) Minimum thresholds: Opus 4,096 tokens, Sonnet 2,048 tokens Tool definition changes invalidate all three cache levels Adding deferred tools via ToolSearch can break the cache if not handled carefully"},{"id":"","t":"MCP Integration","x":""},{"id":"mcp-naming","t":"Tool Naming Convention","x":"mcp__{normalized_server_name}__{normalized_tool_name} Normalization: Only a-z , A-Z , 0-9 , _ , - kept. All other chars replaced with _ . Special handling for claude.ai servers (collapsed underscores)."},{"id":"","t":"Server Transport Types","x":"Type Config Key Fields Stdio \"stdio\" (default) command, args, env SSE \"sse\" url, headers, oauth HTTP \"http\" url, headers, oauth WebSocket \"ws\" url, headers SDK \"sdk\" name ClaudeAI Proxy \"claudeai-proxy\" url, id"},{"id":"mcp-lifecycle","t":"Connection Lifecycle","x":"Discovery: Config files loaded User → Project → Local (last writer wins per server name) Lazy spawning: Servers not started until tools actually needed Initialization: JSON-RPC handshake with protocolVersion: \"2025-03-26\" Tool discovery: tools/list with pagination, tools indexed in BTreeMap Tool invocation: Lookup qualified name, ensure server ready, send tools/call with raw name No automatic reconnection: Crashed servers produce IO error on next call"},{"id":"mcp-deferred","t":"Deferred Tools System","x":"Core tools always present: bash, read_file, write_file, edit_file, glob_search, grep_search All other tools deferred: Listed by name only in <system-reminder> tags ToolSearch: Model calls this to fetch full schemas on demand ENABLE_TOOL_SEARCH=auto : Load full schemas upfront if they fit within 10% of context Config Merge: Last writer wins. If same server name in User and Project config, Project wins. Plugin MCP servers use prefix plugin:pluginName:serverName to avoid collisions."},{"id":"","t":"Plugin System","x":""},{"id":"plugin-types","t":"Plugin Types","x":"Type Location plugin.json Enablement CLAUDE_PLUGIN_ROOT Marketplace ~/.claude/plugins/cache/... Required enabledPlugins Cache directory Inline .claude/ in project or global Not required Automatic .claude/ directory Plugin Directory Structure plugin-name/ ├── .claude-plugin/ │ └── plugin.json # Manifest (required for marketplace) ├── CLAUDE.md # System prompt injection ├── .mcp.json # MCP server definitions ├── agents/ # Subagent definitions (.md) ├── skills/ # Skills (subdirs with SKILL.md) │ └── skill-name/ │ └── SKILL.md ├── hooks/ │ ├── hooks.json # Event handler configuration │ └── *.js # Hook scripts └── scripts/ # Shared utilities"},{"id":"plugin-hooks","t":"Hook Merging (Additive)","x":"All sources are merged additively: User settings hooks Project settings hooks Local settings hooks Plugin hooks (from each enabled plugin) No deduplication. If two plugins register hooks for the same event+matcher, both run. Execution order between plugins is not deterministic."},{"id":"","t":"Skill Namespacing","x":"Plugin skills are namespaced: pluginName:skillName (e.g., multiterminal:kanban-task ). Inline skills are NOT namespaced and could conflict."},{"id":"plugin-settings","t":"Settings Merge Order","x":"Last wins for scalars, deep merge for objects: ~/.claude.json (legacy) ~/.claude/settings.json (user) .claude.json (legacy project) .claude/settings.json (project) .claude/settings.local.json (local overrides)"},{"id":"","t":"Subagent & Teams Architecture","x":""},{"id":"agents-tiers","t":"Three Tiers of Multi-Agent","x":"Tier Mechanism Context Isolation Subagents (Agent tool) In-process, same session Fresh context window Optional git worktree Agent Teams (TeammateTool) Separate Claude Code processes Fully independent contexts tmux panes, file-based Coordinator Mode CLAUDE_CODE_COORDINATOR_MODE=1 One worker per CPU Workers get WORKER preamble"},{"id":"","t":"Built-in Subagent Types","x":"Type Purpose Permission Level general-purpose Full tool access (default) Parent's level Explore Search/research, fresh context ReadOnly Plan Planning mode, read-only tools ReadOnly Verification Build/test verification Parent's level claude-code-guide Help/guidance ReadOnly statusline-setup Terminal config WorkspaceWrite"},{"id":"agents-context","t":"Context Inheritance","x":"Subagents GET: System prompt, CLAUDE.md files, personal/project memory Subagents DON'T GET: Parent conversation history, tool results, file read cache The prompt string is the sole data channel from parent to subagent. Even trivial subagents consume ~60K tokens due to inherited system prompt and memory."},{"id":"","t":"Team Communication","x":"SendMessage tool: Peer-to-peer via filesystem mailboxes at ~/.claude/teams/{team}/messages/{session}/ Task coordination: File-based at ~/.claude/tasks/{team}/ Teammate modes: tmux (default), in-process, auto"},{"id":"agents-worktree","t":"Worktree Isolation","x":"isolation: \"worktree\" creates a temporary git worktree on a new branch Multiple agents can modify same files in parallel without conflicts No changes = auto-cleanup; changes = worktree path and branch returned to parent"},{"id":"","t":"Channels & Messaging","x":"A channel is an MCP server with experimental capabilities that can push events into Claude's conversation. Push events appear as <channel source=\"...\" from=\"...\">content</channel> XML tags. Channel Capability Declaration capabilities: { experimental: { 'claude/channel': {}, // Push notification listener 'claude/channel/permission': {}, // Permission relay } }"},{"id":"channels-warning","t":"The Channel Warning","x":"When a channel is not on the approved allowlist, Claude Code shows a confirmation prompt with \"Loading development channels\" text. Suppression options: CLI flag: --dangerously-load-development-channels server:multiterminal-channel MultiTerminal auto-accept: TerminalControl.cs detects the prompt text and sends keystroke \"1\""},{"id":"channels-permission","t":"Permission Relay Protocol","x":"Claude wants to run a tool requiring approval Claude Code generates a 5-letter request ID (alphabet: a-z minus 'l') Sends notifications/claude/channel/permission_request to channel server Channel forwards to remote user (e.g., your phone via Multi-Connect) User replies \"yes/no/always {id}\" Channel sends notifications/claude/channel/permission back Local terminal stays open simultaneously — first answer wins"},{"id":"channels-bridge","t":"Bridge / Remote Control","x":"31 TypeScript files in src/bridge/ Uses outbound HTTPS only — no inbound ports JWT-based auth with periodic refresh (every 3h55m) Known issues: disconnects every ~25 minutes, close code 1002 treated as permanent UDS Inbox (Feature-Gated, Not Shipped): Unix Domain Socket-based inter-session messaging. Still behind the UDS_INBOX feature flag."},{"id":"","t":"Permission & Security Model","x":""},{"id":"security-hierarchy","t":"5-Level Permission Hierarchy","x":"ReadOnly < WorkspaceWrite < DangerFullAccess < Prompt < Allow Tool Required Permission bash, Agent, REPL, PowerShell DangerFullAccess write_file, edit_file, NotebookEdit WorkspaceWrite read_file, glob, grep, WebFetch, WebSearch, Skill, ToolSearch ReadOnly Unknown tools DangerFullAccess (fail-closed) Config aliases: \"default\"/\"plan\"/\"read-only\" → ReadOnly, \"acceptEdits\"/\"auto\" → WorkspaceWrite, \"dontAsk\" → DangerFullAccess"},{"id":"security-bash","t":"Bash Security (23 Checks, 16 Modules)","x":"Category Checks Input sanitization Zero-width space, IFS manipulation, null byte injection, Unicode homoglyphs, shell metacharacters, command substitution nesting Command classification Read vs write, destructive commands, sed writes, network access, privilege escalation Mode enforcement Read-only blocks writes, workspace boundary, path validation, symlink traversal Environment Zsh builtins, shell enforcement, env var injection, PATH manipulation Execution Sandbox decision, background restrictions, timeouts, output limits"},{"id":"security-sandbox","t":"Sandbox (Linux Only)","x":"Uses unshare --user --map-root-user --mount --ipc --pid --uts --fork . Three modes: Off, WorkspaceOnly (default), AllowList. Not supported on Windows — falls back to non-sandboxed execution with only HOME/TMPDIR redirection."},{"id":"","t":"Auto Mode","x":"AI classifier that auto-approves tool calls appearing safe. Opt-in dialog required. Operates at WorkspaceWrite level but selectively auto-approves DangerFullAccess escalations."},{"id":"","t":"Denied Tool Handling","x":"When a tool call is denied, the denial reason is sent back to the model as an error tool result, allowing it to adapt rather than silently failing."},{"id":"","t":"Environment Variables & Feature Flags","x":""},{"id":"envvars-mt","t":"Most Useful for MultiTerminal","x":"Variable Purpose CLAUDE_AUTOCOMPACT_PCT_OVERRIDE Override compaction threshold percentage CLAUDE_CODE_AUTO_COMPACT_WINDOW Set auto-compact window size CLAUDE_CODE_SUBAGENT_MODEL Override model for subagents CLAUDE_CODE_PLAN_V2_AGENT_COUNT Control plan agent parallelism MCP_TIMEOUT MCP server connection timeout MCP_TOOL_TIMEOUT Individual tool call timeout MAX_MCP_OUTPUT_TOKENS Cap MCP tool output size ENABLE_TOOL_SEARCH auto/true/false — control deferred tool loading CLAUDE_CODE_SESSIONEND_HOOKS_TIMEOUT_MS SessionEnd hook timeout CLAUDE_CODE_PLUGIN_SEED_DIR Plugin seed directory override"},{"id":"","t":"Warning Suppressors","x":"DISABLE_COST_WARNINGS , DISABLE_INSTALLATION_CHECKS , DISABLE_AUTOUPDATER , CLAUDE_CODE_DISABLE_TERMINAL_TITLE , CLAUDE_CODE_DISABLE_GIT_INSTRUCTIONS , CLAUDE_CODE_DISABLE_CLAUDE_MDS"},{"id":"envvars-dangerous","t":"Dangerous: CLAUDE_CODE_DISABLE_NONESSENTIAL_TRAFFIC","x":"Kills GrowthBook flag evaluation alongside telemetry. Silently breaks: Channels, Remote Control, premium model access (Opus 4.6 1M), and all gated features. Use granular flags instead: DISABLE_AUTOUPDATER , DISABLE_ERROR_REPORTING , DISABLE_FEEDBACK_SURVEY ."},{"id":"envvars-flags","t":"Feature Flags","x":"Compile-time (can't enable externally): KAIROS (autonomous daemon), BUDDY (terminal pet), ULTRAPLAN (30-min planning) ANTI_DISTILLATION, UNDERCOVER_MODE, AUTO_MODE, UDS_INBOX, VOICE_MODE Runtime (tengu_* via GrowthBook): tengu_penguins_off — Fast Mode kill-switch tengu_amber_flint — Agent Teams gate tengu_cobalt_raccoon — auto-compact tengu_anti_distill_fake_tool_injection — anti-distillation Internal codenames: Tengu (Claude Code), Capybara (Claude 4.6 variant), Fennec (Opus 4.6), Penguin Mode (Fast Mode)"},{"id":"","t":"Actionable Recommendations for MultiTerminal","x":""},{"id":"recommendations-critical","t":"Critical Do Now","x":"1 CLAUDE.md is being silently truncated Budget is 12,000 chars total. Our project CLAUDE.md far exceeds this. Move reference tables (database schema, folder map, architecture diagram) into .claude/rules/ path-scoped files or skills that load on demand. Keep root CLAUDE.md to ~200 lines of critical conventions. 2 Hook output enters context without truncation Every additionalContext field from hooks adds tokens permanently. Audit all hooks — keep output minimal. Use stdout on exit 0 for logging (doesn't enter context). 3 Remove duplicate multiterminal-channel from .mcp.json Already done this session."},{"id":"recommendations-high","t":"High Priority","x":"4 Add compaction survival instructions Add to CLAUDE.md: \"When compacting, always preserve: active task ID, modified file list, current checklist state, test commands.\" 5 Consider ENABLE_TOOL_SEARCH=auto Our 80+ tools stay deferred by default (good), but some agents may benefit from preloading critical tool schemas. 6 Use MCP timeout env vars MCP_TOOL_TIMEOUT and MCP_TIMEOUT to tune timeouts for agents that call slow tools. 7 Implement worker preamble pattern When spawning non-coordinator agents, explicitly instruct them not to spawn sub-agents (prevents recursive spawning)."},{"id":"recommendations-medium","t":"Medium Priority","x":"8 Git worktree support for parallel agents Add worktree creation to TerminalSpawner.cs so parallel agents don't conflict on shared files. 9 MCP server health monitoring Surface MCP server health in our status bar. Claude Code has useMcpConnectivityStatus for UI notifications. 10 Plugin hook deduplication If MT and Clarion Assistant both register safety hooks for PreToolUse > Bash , the hook runs twice. Add idempotency checks. 11 Understand config merge order Project settings override user settings for MCP servers (last writer wins). Local settings override both. Use this for per-project customization."},{"id":"recommendations-low","t":"Low Priority / Future","x":"12 Explore in-process agent mode Claude Code's teammateMode: \"in-process\" runs teammates without separate terminals. Could reduce overhead for quick tasks. 13 Consider UDS Inbox integration When/if it ships publicly — direct peer-to-peer agent communication without REST API middleman. 14 Investigate auto-approve patterns The coordinatorHandler auto-approves for autonomous operation. Could build a more granular version via PreToolUse hooks. 15 Watch for open-sourcing If Anthropic open-sources Claude Code, many of these workarounds become direct code changes."},{"id":"","t":"Sources","x":""},{"id":"","t":"Primary","x":"H:/DevLaptop/Projects/claw-code/ — Clean-room Python/Rust reimplementation rust/crates/runtime/src/ — prompt.rs, compact.rs, mcp.rs, permissions.rs, config.rs src/reference_data/ — Archived tool/command/subsystem snapshots"},{"id":"","t":"Official Documentation","x":"code.claude.com/docs/en/context-window code.claude.com/docs/en/channels-reference code.claude.com/docs/en/agent-teams code.claude.com/docs/en/sub-agents platform.claude.com/docs/en/docs/build-with-claude/prompt-caching"},{"id":"","t":"Community Analysis","x":"Alex Kim: claude-code-source-leak analysis Victor Antos: \"I Read the Leaked Claude Code Source\" Sebastian Raschka: \"Claude Code's Real Secret Sauce\" DEV Community: Multiple technical breakdowns Reddit: r/ClaudeAI, r/LocalLLaMA, r/ClaudeCode, r/programming ccleaks.com: Architecture and hidden features documentation"}]},{"u":"code-graph.html","t":"Code Graph","s":[{"id":"","t":"Code Graph","x":"The code graph is a Roslyn-indexed map of the C# codebase — every class, method, property, and constructor, plus the relationships between them. Agents and users query it to find a symbol, trace who calls what, run an impact analysis before a change, and spot dead code, without reading every file."},{"id":"","t":"On This Page","x":"What the index captures Building & keeping the index fresh Practical workflows MCP tools REST API Storage"},{"id":"what","t":"1. What the index captures","x":"The indexer ( CSharpCodeGraphIndexer ) parses .cs files with Roslyn (Microsoft's official C# compiler API — it resolves real types and bindings, so call, override, and inheritance edges reflect what the compiler sees rather than what the text looks like) using a two-pass strategy — symbols first, then the relationships between them: Why it beats grep: a text search for a method name matches every string that happens to share it — comments, unrelated overloads, same-named members on other types. Because the graph resolves invocations through the semantic model, an edge like calls points at the actual method that runs, correctly distinguishing overloads and following overrides and inheritance — not a string match."},{"id":"","t":"Pass 1 — Symbols","x":"Each declaration becomes a symbol row capturing its accessibility, static / async / abstract modifiers, generic parameters, return type, parameter list, the type it belongs to, line number, and a one-line source preview. Symbol kinds: class , interface , struct , enum , delegate method , constructor , property event , field"},{"id":"","t":"Pass 2 — Relationships","x":"A second walk resolves edges between symbols using the semantic model: Relationship Meaning calls A method/property/constructor invokes another (includes object creation). inherits A type derives from a base class. implements A type implements an interface. overrides A method overrides a base method. uses_type A field, property, parameter, or return type references another type. subscribes A member subscribes to an event ( += ). handles A handler method is wired to an event. Generated and build output is skipped: obj/ , bin/ , node_modules/ , and .g.cs / .designer.cs / .AssemblyInfo.cs files."},{"id":"building","t":"2. Building & keeping the index fresh","x":"Indexing runs per directory. The indexer registers (or clears and rebuilds) a project, parses every non-excluded .cs file into a Roslyn compilation, runs the two passes inside a transaction, and records statistics (file count, symbol count, relationship count, duration). Re-running re-indexes that project in place. After any index, GET /api/code-graph/stats reports per-kind counts and the last-indexed timestamp."},{"id":"","t":"Indexing is automatic — the graph keeps itself fresh","x":"A background service, CodeGraphWatcher , keeps the graph current so you don't have to remember to re-index. It does three things: Heals on startup. When the app launches it sweeps every registered C# project and re-indexes any whose graph is stale — so a graph that sat untouched for weeks is brought up to date automatically. Re-indexes on edit. While the app runs it watches each registered project's .cs files. After a short quiet window (a debounce , ~12s by default) it re-indexes the project that changed. Rapid saves coalesce into a single re-index; build output ( obj/ , bin/ ) and generated files are ignored, so a build doesn't trigger churn. Picks up new projects mid-session. A project created or registered while the app is running (new-project wizard, create_project , or POST /api/projects ) is indexed straight away — no restart needed. A per-project freshness floor (5 min by default) suppresses redundant re-indexes, and a single coordinator ( CodeGraphIndexCoordinator ) serializes every index — automatic and manual alike — so two runs can never overlap and corrupt the graph."},{"id":"","t":"Manual indexing (still available)","x":"You rarely need to index by hand now, but you can force a refresh on demand with the index_code_graph MCP tool or POST /api/code-graph/index (see below) — useful to index a directory that isn't a registered project, or to refresh immediately rather than waiting for the debounce. Both paths run through the same coordinator as the watcher."},{"id":"","t":"Configuration","x":"The watcher is on by default and tuned with environment variables: Variable Default Effect MULTITERMINAL_CODEGRAPH_WATCH on Set to 0 / false / off to disable auto-indexing entirely (manual indexing still works). MULTITERMINAL_CODEGRAPH_DEBOUNCE_MS 12000 Quiet window after the last .cs change before a re-index fires (clamped to a 3–600s range). MULTITERMINAL_CODEGRAPH_MIN_INTERVAL_MS 300000 Per-project freshness floor — a project re-indexed more recently than this is skipped."},{"id":"workflows","t":"3. Practical workflows","x":""},{"id":"","t":"Worked example: who creates the MessageBroker?","x":"Find a symbol, then trace its callers. The watcher keeps the graph fresh, so step 1 (an explicit index) is usually unnecessary — it's shown here to force an immediate refresh and to demonstrate the tool. The MCP calls and representative (elided) results: // 1. (optional) Force an immediate index — normally the watcher handles this index_code_graph(directory: \"H:\\\\DevLaptop\\\\...\\\\MultiTerminal\", projectName: \"MultiTerminal\") → { \"success\": true, \"projectName\": \"MultiTerminal\", \"fileCount\": 156, \"symbolCount\": 7841, \"relationshipCount\": 24193, \"durationMs\": 9120 } // 2. Find the symbol (exact matches first, then substring) search_code_graph(query: \"MessageBroker\", type: \"class\") → results: [ { \"id\": 1422, \"name\": \"MessageBroker\", \"type\": \"class\", \"file_path\": \"MCPServer/Services/MessageBroker.cs\", \"line_number\": 19, \"accessibility\": \"public\" } ] // 3. Trace its callers (\"who creates / depends on this?\") get_symbol_callers(symbolName: \"MessageBroker\") // or symbolId: 1422 → results: [ { \"name\": \"MessageBroker\", \"member_of\": \"MultiTerminalRestServer\", \"call_file\": \"API/MultiTerminalRestServer.cs\", \"call_line\": 94 } ] The caller row points at the exact construction site — API/MultiTerminalRestServer.cs:94 , where the REST host does _broker = new MessageBroker(); — so you can jump straight to where the dependency lives (object creation is a calls edge). Resolve callees the same way w"},{"id":"","t":"Find a symbol","x":"Search by name (exact matches first, then substring), optionally filtered by kind. This returns the symbol's id, file, line, accessibility, signature, and source preview — the starting point for every other query."},{"id":"","t":"Trace callers and callees","x":"Given a symbol, list its direct callers (\"who depends on this?\") and direct callees (\"what does this reach?\"). Each result includes the call site's file and line."},{"id":"","t":"Impact analysis before a change","x":"Run a transitive blast-radius query — the recursive set of everything that (in)directly calls a symbol, with cycle detection and a depth cap (default 10). Do this before refactoring a hot method to see what you might break."},{"id":"","t":"Find dead code","x":"List public / internal methods and properties with no incoming calls edge — candidates for removal. Scope it to a single project if you like."},{"id":"","t":"Map a type's hierarchy","x":"Walk the inheritance/implementation tree to see everything that derives from or implements a class or interface."},{"id":"mcp-tools","t":"4. MCP tools","x":"Agents reach the graph through these MCP tools: Tool Purpose index_code_graph Force an index (or re-index) of a directory on demand. Registered projects are also indexed automatically by the watcher (see 2). search_code_graph Find symbols by name, with an optional kind filter. get_symbol_callers Direct callers of a symbol. get_symbol_callees Direct callees of a symbol. get_impact_analysis Transitive callers (blast radius). get_inheritance_tree Inheritance / implementation tree. get_dead_code Unreferenced public/internal members. get_file_symbols All symbols defined in a file."},{"id":"rest","t":"5. REST API","x":"The same operations are exposed under /api/code-graph (the MCP tools call these): Method & path Purpose GET /api/code-graph/search?query=&type= Search symbols by name (optional kind filter). GET /api/code-graph/callers?symbolId=&symbolName= Direct callers (resolve by id or name). GET /api/code-graph/callees?symbolId=&symbolName= Direct callees. GET /api/code-graph/impact?symbolId=&maxDepth= Transitive impact (default depth 10). GET /api/code-graph/inheritance?symbolId= Inheritance / implementation tree. GET /api/code-graph/dead-code?projectId= Unreferenced public/internal members. GET /api/code-graph/file-symbols?filePath= All symbols in a file. POST /api/code-graph/index Index a directory: body { directory, projectName } . GET /api/code-graph/stats Index statistics and last-indexed time. Callers/callees/impact/inheritance accept either a numeric symbolId or a symbolName (resolved to an id). When the graph hasn't been built yet the endpoints return 503 ."},{"id":"storage","t":"6. Storage","x":"The graph lives in the same SQLite database as the rest of MultiTerminal, in three core tables managed by CodeGraphDatabase and queried by CodeGraphQuery : Table Holds cg_projects One row per indexed project (name + optional .csproj path). cg_symbols Every extracted symbol with its metadata. cg_relationships The typed edges between symbols, with the source file and line of each edge. Callers, callees, impact, inheritance, and dead-code queries are SQL over these tables — the transitive ones use recursive CTEs with cycle detection — so results are fast and reproducible."}]},{"u":"deployment.html","t":"Deployment Guide","s":[{"id":"","t":"Deployment Guide","x":"How to build, deploy, configure, and maintain MultiTerminal on a Windows machine."},{"id":"prerequisites","t":"Prerequisites","x":""},{"id":"","t":"Required Software","x":"Software Version Purpose .NET 8 SDK 8.0+ Build and run the application (self-contained deployment includes runtime) WebView2 Runtime Evergreen Chromium rendering for all HTML panels (pre-installed on Windows 11) Node.js 18+ MCP server execution ( %APPDATA%\\multiterminal\\mcp\\index.js ) Claude Code CLI Latest Terminal agent sessions (installed via npm install -g @anthropic-ai/claude-code )"},{"id":"","t":"System Requirements","x":"OS: Windows 10 (1809+) or Windows 11, x64 only RAM: 4 GB minimum, 8 GB recommended (each WebView2 panel uses Chromium) Disk: ~400 MB for application, plus runtime data in %APPDATA% Network: Internet access for Claude Code API calls; localhost:5050 for REST API"},{"id":"build-process","t":"Build Process","x":""},{"id":"","t":"Building from Source","x":"MultiTerminal is built using MSBuild (via .NET SDK). The project targets net8.0-windows with self-contained deployment for x64. # Build in Release mode (self-contained, single output directory) dotnet publish -c Release -r win-x64 --self-contained true # Or using MSBuild directly msbuild MultiTerminal.csproj /p:Configuration=Release /p:RuntimeIdentifier=win-x64"},{"id":"","t":"Build Output","x":"The build produces output in: bin\\Release\\net8.0-windows\\win-x64\\publish\\ This folder contains the complete self-contained deployment (~385 MB, ~1,262 files). See Distribution for a complete file audit."},{"id":"","t":"Build via MCP Tool","x":"When working inside MultiTerminal, agents can trigger builds using the build_project MCP tool from the windows-build-runner server. This compiles the latest source code without needing to exit the application."},{"id":"deploy-workflow","t":"Deploy Workflow","x":""},{"id":"","t":"Important: Live Binary","x":"The running application is served from the Deploy folder ( H:\\DevLaptop\\ClarionPowerShell\\Deploy\\ ). You cannot overwrite files while the application is running. The deploy workflow requires closing the application first."},{"id":"","t":"deploy.ps1 Script","x":"The deployment script handles copying build output to the Deploy folder: Close MultiTerminal - Exit the running application completely Run deploy.ps1 - Copies build output from bin\\Release\\ to Deploy\\ Relaunch MultiTerminal - Start Deploy\\MultiTerminal.exe # From the source directory: .\\deploy.ps1 # Then relaunch: H:\\DevLaptop\\ClarionPowerShell\\Deploy\\MultiTerminal.exe"},{"id":"","t":"Agent Limitations","x":"Agents can trigger build_project to compile source code Agents cannot copy files to the Deploy folder (locked by running process) Only the owner can close the app, run deploy.ps1, and relaunch"},{"id":"configuration","t":"Configuration Files","x":""},{"id":"","t":"Application Configuration","x":"File Location Purpose MultiTerminal.runtimeconfig.json Deploy folder Specifies .NET 8 runtime version, GC settings, and thread pool configuration. Rarely needs modification. MultiTerminal.deps.json Deploy folder Auto-generated dependency manifest. Do not edit manually. MultiTerminal.dll.config Deploy folder Application settings (connection strings, feature flags). Edit to customize behavior."},{"id":"","t":"Claude Code Configuration","x":"File Location Purpose .claude/CLAUDE.md Project root Project instructions loaded into every agent's context (~16 KB). Contains architecture reference, patterns, and conventions. .claude/project.json Project root Project identity (unique ID, name, timestamps). Links the project to MultiTerminal's registry. .claude/settings.json Project root Project-level Claude Code settings (experimental features, etc.). .claude/settings.local.json Project root Local permission presets for MCP tools and shell commands. Not committed to git."},{"id":"","t":"Global Claude Configuration","x":"File Location Purpose CLAUDE.md ~/.claude/ User-level instructions applied to all projects (e.g., PowerShell preference, tool priorities). settings.json ~/.claude/ Global Claude Code settings (experimental features like agent teams). .mcp.json %APPDATA%\\multiterminal\\ MCP server registrations for the two stdio servers ( multiterminal , mcp-gateway ). Loaded via --mcp-config ; generated by the installer."},{"id":"databases","t":"Database Locations","x":"All databases are SQLite files created automatically on first run. Located in the user's AppData directory: Database Path Contents multiterminal.db %APPDATA%\\multiterminal\\multiterminal.db Main database (all in one file). Kanban tasks, checklists, plans, helpers, continuation notes, stale tracking. Team profiles, activity feed, inbox notifications, terminal registrations. Projects, agents, MCP config, specialist agents, paths, prompts, skills. Knowledge entries (6 categories), code digests, FTS5 index. Session lineage, session messages, session-agent maps, task reports, and the code graph. messages.db %APPDATA%\\multiterminal\\messages.db Inter-terminal message delivery queue: pending messages, retry counts, delivery timestamps, expiry."},{"id":"","t":"Database Management","x":"Backup: Copy the entire %APPDATA%\\multiterminal\\ folder Reset: Delete individual .db files to reset that subsystem (auto-recreated on next launch) Migrate: Copy .db files to a new machine's %APPDATA%\\multiterminal\\ Schema: Migrations run automatically; no manual schema updates needed Inspect: Use any SQLite browser (DB Browser for SQLite, or the sqlite MCP server)"},{"id":"mcp-setup","t":"MCP Server Setup","x":""},{"id":"","t":"Two MCP Servers (stdio)","x":"Claude Code connects to exactly two MCP servers, both over stdio. Neither is an HTTP endpoint. See MCP Architecture for the full design. multiterminal - a Node.js STDIO server ( %APPDATA%\\multiterminal\\mcp\\index.js ) that wraps the MultiTerminal REST API. It launches with command: \"node\" and translates each tool call into an HTTP request against http://localhost:5050/api/* (the REST API hosted by the running app). mcp-gateway - a .NET console app ( McpGateway.exe ) that proxies and aggregates any number of backend MCP servers (sqlite, mssql, everything-search, windows-build-runner, windowssnapit, etc.) behind a single connection. The REST API on port 5050 starts automatically when MultiTerminal launches; the multiterminal MCP server talks to it. There is no http://localhost:5050/mcp endpoint."},{"id":"","t":"Claude Code MCP Registration","x":"Both servers are registered in a single config file at %APPDATA%\\multiterminal\\.mcp.json , which Claude Code is pointed at via --mcp-config when MultiTerminal launches a terminal. Registration is by command (stdio), not by URL: # %APPDATA%\\multiterminal\\.mcp.json { \"mcpServers\": { \"mcp-gateway\": { \"type\": \"stdio\", \"command\": \"C:\\\\Program Files\\\\MultiTerminal\\\\mcp-gateway\\\\McpGateway.exe\", \"args\": [] }, \"multiterminal\": { \"type\": \"stdio\", \"command\": \"node\", \"args\": [\"C:\\\\Users\\\\<username>\\\\AppData\\\\Roaming\\\\multiterminal\\\\mcp\\\\index.js\"] } } } This file is generated by the installer's post-install.js with correct paths for the target machine; post-install.js also removes any legacy multiterminal entries from ~/.claude.json left over from older versions. Do not register an http://localhost:5050/mcp URL — that endpoint does not exist."},{"id":"","t":"Gateway Backend Servers","x":"The mcp-gateway server aggregates backend MCP servers, so Claude Code's connection count stays fixed at two while the backend set can grow. Typical backends: Backend Type Purpose sqlite stdio (Node.js) Direct SQLite database queries mssql stdio (Node.js) SQL Server database access (optional) everything-search stdio (Node.js) Instant file search via voidtools Everything index windows-build-runner stdio (Node.js) Build and compile projects from within agents windowssnapit stdio (Node.js) Screenshot capture and clipboard reading Backends are stored in the gateway's own SQLite database and grouped into profiles, not in .mcp.json . Manage them at runtime via the gateway's gateway__* tools or per-project from the Project Panel."},{"id":"claude-integration","t":"Claude Code Integration","x":""},{"id":"","t":".claude/ Folder Structure","x":".claude/ +-- CLAUDE.md (project instructions - loaded into agent context) +-- project.json (project identity and metadata) +-- settings.json (Claude Code settings) +-- settings.local.json (local permissions - not in git) +-- agents/ (specialist agent definitions - 8 files) | +-- code-reviewer.md | +-- debugger.md | +-- devils-advocate.md | +-- security-auditor.md | +-- session-distiller.md | +-- session-summarizer.md | +-- test-designer.md | +-- verifier.md +-- hooks/ (event hooks - 9 files) | +-- active-context-hook.js | +-- inbox-check-hook.js | +-- notification-hook.js | +-- pipeline-trigger-hook.js | +-- project-context-hook.js | +-- safety-hook.js | +-- session-status-hook.js | +-- subagent-office-hook.js | +-- task-to-agent-hook.js +-- skills/ (custom slash commands) +-- rules/ (additional behavioral rules) +-- messages/ (inter-session message store) +-- research/ (research artifacts)"},{"id":"","t":"Hooks (9 files)","x":"Claude Code hooks integrate terminal activity with MultiTerminal's services: Hook Purpose session-status-hook.js Injects active context (task, checklist, build status) at session start active-context-hook.js Auto-writes ACTIVE-CONTEXT.md after builds, checklist updates, and status changes project-context-hook.js Injects project context via MULTITERMINAL_PROJECT_ID at session start inbox-check-hook.js Delivers messages (legacy file-inbox path; Channels is the primary path now) task-to-agent-hook.js Routes task assignments to the correct agent/team subagent-office-hook.js Manages subagent lifecycle and office panel presence safety-hook.js Safety guardrails for destructive operations pipeline-trigger-hook.js Triggers CI/CD pipeline actions on specific events notification-hook.js Sends desktop notifications for important events"},{"id":"","t":"Environment Variables","x":"Variable Set By Purpose MULTITERMINAL_DOC_ID Terminal launch Unique document ID for terminal registration MULTITERMINAL_NAME Terminal launch Display name for the terminal identity (used in messaging and team roster) MULTITERMINAL_PROJECT_ID Terminal launch Project ID for context injection via startup hook CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS User config Enable native Claude Code team agent support (set to 1 )"},{"id":"installation","t":"Fresh Installation","x":""},{"id":"","t":"Option A: Inno Setup Installer (Recommended)","x":"The Inno Setup installer is the recommended installation method. It handles file placement, MCP server registration, and post-install configuration automatically: Run MultiTerminal-Setup.exe Follow the installer prompts to choose an installation directory The post-install script ( post-install.js ) registers MCP servers and creates configuration files Launch MultiTerminal from the Start Menu or desktop shortcut See Distribution — Installer for details on the installer scripts."},{"id":"","t":"Option B: Manual (Portable) Installation","x":"Step 1: Deploy Application Files # Create installation directory New-Item -ItemType Directory -Path \"C:\\Applications\\MultiTerminal\" -Force # Copy all files from the build output (or existing Deploy folder) Copy-Item -Path \"path\\to\\publish\\*\" -Destination \"C:\\Applications\\MultiTerminal\\\" -Recurse -Force Step 2: Install MCP Server Dependencies The MCP server is located at %APPDATA%\\multiterminal\\mcp\\index.js and requires Node.js dependencies: cd \"$env:APPDATA\\multiterminal\\mcp\" npm install Step 3: Deploy Claude Code Hooks Copy the 9 hook files from .claude/hooks/ to your project or global hooks directory: # Hook files: inbox-check-hook.js, project-context-hook.js, safety-hook.js, # subagent-office-hook.js, task-to-agent-hook.js, session-status-hook.js, # pipeline-trigger-hook.js, active-context-hook.js, notification-hook.js Edit hook files to update hard-coded paths to your installation directory. Step 4: Configure Claude Code Hooks Create ~/.claude/hooks.json with the hook event bindings. See Quick Start for the complete hooks.json template. Step 5: Register MCP Servers Create %APPDATA%\\multiterminal\\.mcp.json registering both stdio servers (Claude Code is pointed at it via --mcp-config ). Both are launched by command , not by URL: # %APPDATA%\\multiterminal\\.mcp.json { \"mcpServers\": { \"mcp-gateway\": { \"type\": \"stdio\", \"command\": \"path\\\\to\\\\McpGateway.exe\", \"args\": [] }, \"multite"},{"id":"verification","t":"Verification Checklist","x":""},{"id":"","t":"Post-Installation Verification","x":"MultiTerminal.exe launches without errors Database files created at %APPDATA%\\multiterminal\\ WebView2 panels load (Tasks, Chat, Activity panels render HTML) New Terminal button opens a working terminal with ConPty Claude Code can connect and use MCP tools ( list_terminals , list_tasks ) Activity feed shows tool usage events from Claude Code sessions Inter-terminal messaging works (register two terminals, send a message) Task creation and kanban board updates work Session persistence works (close and reopen - terminals restore)"},{"id":"troubleshooting","t":"Troubleshooting","x":"Issue Cause Solution Application won't start Missing runtime files Verify all files from critical files checklist exist in the Deploy folder WebView2 panels blank WebView2 Runtime not installed Install WebView2 Evergreen Runtime from Microsoft MCP tools not available in Claude Code MCP server not registered Verify %APPDATA%\\multiterminal\\.mcp.json contains the multiterminal and mcp-gateway stdio entries, and that the app (REST API on 5050) is running Port 5050 already in use Another instance running or port conflict Close other MultiTerminal instances; check with netstat -ano | findstr 5050 Database errors on startup %APPDATA%\\multiterminal folder missing or not writable Create the folder manually: mkdir %APPDATA%\\multiterminal better-sqlite3 module not found Node modules not installed for session history Run npm install in the %APPDATA%\\multiterminal\\mcp directory Hooks not executing hooks.json missing or paths incorrect Verify ~/.claude/hooks.json exists and all paths point to actual files Terminal shows blank screen ConPty initialization failure Check Debug panel for errors; ensure terminal.html exists in Deploy folder Messages not delivered Terminal not registered or webhook failure Ensure terminals call register_terminal at startup; check Debug panel for delivery errors Session restore fails Corrupted layout XML or missing session data Delete the layout XML file from %APPD"},{"id":"","t":"Debug Panel","x":"The built-in Debug panel (toolbar button: Debug) shows internal log messages that help diagnose issues with MCP server startup, WebView2 initialization, message routing, database operations, and session restore. Enable it when troubleshooting."}]},{"u":"distribution.html","t":"Distribution Package","s":[{"id":"","t":"Distribution Package","x":"Complete audit of all files included in the MultiTerminal distribution package."},{"id":"","t":"Package Overview","x":"Total Package Size ~385 MB Total File Count ~1,262 files Runtime Self-contained .NET 8 (Windows x64) Architecture x64 only Target OS Windows 10/11"},{"id":"","t":"System Requirements","x":"OS: Windows 10 (version 1809+) or Windows 11, x64 WebView2 Runtime: Required (pre-installed on Windows 11; download for Windows 10) Node.js 18+: Required for MCP server functionality Claude Code CLI: Required for terminal agent sessions Disk Space: ~400 MB for application + runtime data RAM: 4 GB minimum, 8 GB recommended (WebView2 panels use Chromium)"},{"id":"core-application","t":"1. Core Application","x":"The main executable and its direct dependencies. File Purpose Required MultiTerminal.exe Main executable (self-contained .NET 8 host) Yes MultiTerminal.dll Application assembly (all C# code) Yes MultiTerminal.deps.json Dependency graph for .NET runtime Yes MultiTerminal.runtimeconfig.json Runtime configuration (framework version, GC settings) Yes MultiTerminal.dll.config Application configuration (app settings) Yes WeifenLuo.WinFormsUI.Docking.dll DockPanelSuite - docking window framework Yes WeifenLuo.WinFormsUI.Docking.ThemeVS2015.dll VS2015 dark/light theme for DockPanelSuite Yes System.Data.SQLite.dll SQLite managed wrapper Yes SQLite.Interop.dll SQLite native interop library Yes"},{"id":"dotnet-runtime","t":"2. .NET Runtime (384 DLLs)","x":"The self-contained deployment includes the entire .NET 8 runtime. This eliminates the need for users to install .NET separately. Namespace Group Count Purpose System.* ~190 Core .NET Base Class Library: collections, IO, networking, security, threading, XML, LINQ, reflection, serialization Microsoft.AspNetCore.* ~86 ASP.NET Core web framework: HTTP server (Kestrel), MVC, routing, authentication, CORS, SignalR connections, diagnostics Microsoft.Extensions.* ~46 Dependency injection, configuration, logging, hosting, caching, HTTP client factory, options pattern Microsoft.* (other) ~12 CSharp runtime, WinForms designer, Visual Basic compatibility, JSInterop, diagnostics Runtime infrastructure ~50 coreclr.dll , clrjit.dll , hostfxr.dll , hostpolicy.dll , mscorlib.dll , GC, ETW, DAC, native helpers Key runtime infrastructure files File Role coreclr.dll Core CLR execution engine clrjit.dll JIT compiler clrgc.dll Garbage collector hostfxr.dll Host framework resolver hostpolicy.dll Host policy (assembly loading) mscorlib.dll Core library facade netstandard.dll .NET Standard compatibility shim System.Private.CoreLib.dll Core type system implementation createdump.exe Crash dump utility mscordaccore.dll Data access component (debugging) mscordbi.dll Debug interface"},{"id":"webview2","t":"3. WebView2 Runtime","x":"WebView2 provides the Chromium-based rendering engine for all HTML panels. The WebView2 Runtime must be installed on the system; these DLLs are the .NET bindings. File Purpose Microsoft.Web.WebView2.Core.dll Core WebView2 .NET bindings Microsoft.Web.WebView2.Core.xml XML documentation for Core Microsoft.Web.WebView2.WinForms.dll WinForms integration control Microsoft.Web.WebView2.WinForms.xml XML documentation for WinForms Microsoft.Web.WebView2.Wpf.dll WPF integration control (used by settings dialog) Microsoft.Web.WebView2.Wpf.xml XML documentation for WPF WebView2Loader.dll Native loader - finds and initializes WebView2 Runtime"},{"id":"","t":"WebView2 Runtime Note","x":"The WebView2 Runtime (Evergreen) must be installed separately on the target machine. Windows 11 includes it by default. For Windows 10, download from Microsoft's WebView2 download page . The DLLs above are only the .NET wrapper; the actual Chromium engine (~150 MB) lives in the system WebView2 Runtime installation."},{"id":"html-panels","t":"4. HTML Panels (14 files)","x":"Each UI panel is rendered via WebView2 using a self-contained HTML file with embedded CSS and JavaScript. File Panel Purpose ActivityPanel/panel.html Activity Panel Real-time activity feed showing tool usage, builds, and agent events AgentPanel/agent-panel.html Agent Panel Observe spawned Claude Code team agents and their transcript activity ChatPanel/chat-panel.html Chat Panel Inter-terminal messaging UI for point-to-point and broadcast chat Controls/TaskHudPanel/task-hud.html Task HUD Heads-up display overlay showing current task and checklist status FilePreviewPanel/file-preview.html File Preview Panel WebView2-based file preview for HTML, Markdown, images, and other file types Controls/TerminalStatusBar/statusbar.html Terminal Status Bar 3-row status bar: folder path, model/git info, context usage meter InboxPanel/inbox-panel.html Inbox Panel Notification center for task updates, messages, and checklist transitions OfficePanel/panel.html Office Panel Team office view showing terminal status and agent presence ProfilePanel/panel.html Profile Panel Team member profiles with specialties, availability, and avatars ProjectPanel/panel.html Project Panel Project management: registration, agent assignment, MCP config, paths StartScreen/start-screen.html Start Screen Welcome screen with project list and quick-launch options TaskLifecycleBoard/lifecycle-board.html Task Lifecycle Boar"},{"id":"localization","t":"5. Localization (13 Languages)","x":"Satellite assemblies for .NET runtime localization. Each folder contains translated resource DLLs for framework error messages and system strings. Folder Language cs/ Czech de/ German es/ Spanish fr/ French it/ Italian ja/ Japanese ko/ Korean pl/ Polish pt-BR/ Portuguese (Brazil) ru/ Russian tr/ Turkish zh-Hans/ Chinese (Simplified) zh-Hant/ Chinese (Traditional)"},{"id":"databases","t":"6. Database Files","x":"Databases are created at runtime in the user's AppData directory. They are not included in the distribution package. Database Location Purpose multiterminal.db %APPDATA%\\multiterminal\\multiterminal.db Main database (all in one file): kanban tasks, team profiles, activity feed, inbox, terminal registrations, helper sessions, projects, agents, MCP config, knowledge entries (6 categories) + code digests + FTS5 index, session lineage/messages, and the code graph messages.db %APPDATA%\\multiterminal\\messages.db Inter-terminal message delivery queue: queued messages with retry tracking and expiry"},{"id":"","t":"Database Notes","x":"All databases are SQLite and created automatically on first run Schema migrations run automatically when new columns or tables are needed To start fresh, delete the database files; the application will recreate them To migrate to a new machine, copy the %APPDATA%\\multiterminal\\ folder"},{"id":"configuration","t":"7. Configuration Files","x":"File Purpose Editable MultiTerminal.runtimeconfig.json Specifies .NET 8 framework version and runtime options (GC mode, thread pool) Advanced only MultiTerminal.deps.json Dependency manifest used by the .NET host to locate assemblies No (auto-generated) MultiTerminal.dll.config Application configuration file (connection strings, app settings) Yes"},{"id":"claude-integration","t":"8. Claude Integration","x":"The .claude/ folder in the project root configures Claude Code behavior for agents working in this project. Path Purpose .claude/CLAUDE.md Project instructions loaded into every agent's context at startup (~16 KB). Contains architecture reference, patterns, task-specific file guides. .claude/project.json Project identity (ID, name, timestamps). Used by MultiTerminal to track the project. .claude/settings.json Project-level Claude Code settings .claude/settings.local.json Local permission presets for MCP tools and commands (not committed to git) .claude/agents/ Specialist agent definitions (8 files): code-reviewer, debugger, devils-advocate, security-auditor, session-distiller, session-summarizer, test-designer, verifier .claude/hooks/ Claude Code hooks (9 files): inbox-check-hook.js, project-context-hook.js, safety-hook.js, subagent-office-hook.js, task-to-agent-hook.js, session-status-hook.js, pipeline-trigger-hook.js, active-context-hook.js, notification-hook.js .claude/skills/ Custom skill definitions (slash commands like /kanban-task, /new-project) .claude/rules/ Additional behavioral rules for agents"},{"id":"licenses","t":"9. Third-Party Licenses","x":"THIRD-PARTY-NOTICES.md in the repository root documents all third-party dependencies and their licenses. Key dependencies: Library License Purpose DockPanelSuite 3.1.0 MIT Dockable window framework (VS-style panels) Microsoft.Web.WebView2 BSD-style Chromium-based embedded browser control System.Data.SQLite Public Domain SQLite database engine for .NET .NET 8 Runtime MIT Self-contained runtime ASP.NET Core MIT Web framework for REST API"},{"id":"critical-files","t":"Critical Files Checklist","x":"These files must exist in the deployment directory or the application will not launch:"},{"id":"","t":"Launch-Critical Files","x":"MultiTerminal.exe - Entry point MultiTerminal.dll - Application code MultiTerminal.runtimeconfig.json - Runtime bootstrap MultiTerminal.deps.json - Assembly resolution coreclr.dll - CLR execution engine clrjit.dll - JIT compiler hostfxr.dll - Framework host resolver hostpolicy.dll - Assembly load policy System.Private.CoreLib.dll - Core type system WebView2Loader.dll - WebView2 native loader Microsoft.Web.WebView2.Core.dll - WebView2 bindings Microsoft.Web.WebView2.WinForms.dll - WinForms WebView2 control System.Data.SQLite.dll - Database engine SQLite.Interop.dll - Native SQLite WeifenLuo.WinFormsUI.Docking.dll - Panel docking"},{"id":"optional-files","t":"Optional Files (Size Reduction)","x":"These can be excluded to reduce package size if the related functionality is not needed: Category Approx. Size Impact of Removal Localization folders (13 languages) ~15 MB Framework error messages display in English only publish/ subfolder Variable Duplicate build output; can be removed if not using as staging area XML documentation files ( *.xml ) ~5 MB No IntelliSense for WebView2 APIs (development only) Debug symbols ( *.pdb ) ~2 MB No stack traces with line numbers in crash reports Microsoft.Web.WebView2.Wpf.dll ~100 KB WPF-based settings dialog will not work (WinForms dialogs unaffected) createdump.exe , mscordaccore*.dll , mscordbi.dll ~15 MB No crash dump generation or post-mortem debugging"},{"id":"directories","t":"Directory Structure","x":"Top-level layout of the Deploy folder: Deploy/ +-- MultiTerminal.exe (main executable) +-- MultiTerminal.dll (application assembly) +-- *.dll (384 runtime + framework DLLs) +-- *.json, *.config (configuration files) +-- ActivityPanel/ (activity feed HTML) +-- AgentPanel/ (agent observation HTML) +-- ChatPanel/ (messaging HTML) +-- Controls/ | +-- TaskHudPanel/ (task HUD overlay HTML) | +-- TerminalStatusBar/ (status bar HTML) +-- FilePreviewPanel/ (file preview HTML) +-- InboxPanel/ (notifications HTML) +-- OfficePanel/ (team office HTML) +-- ProfilePanel/ (team profiles HTML) +-- ProjectPanel/ (project management HTML) +-- StartScreen/ (welcome screen HTML) +-- TaskLifecycleBoard/ (task lifecycle HTML) +-- TasksPanel/ (kanban board HTML) +-- Terminal/ (terminal emulator HTML) +-- tools/ (bundled utilities: rg.exe for ripgrep code search) +-- runtimes/ (native runtime libraries) +-- cs/, de/, es/, fr/, ... (13 localization folders) +-- publish/ (staging build output)"},{"id":"installer","t":"Installer","x":"The installer/ directory in the source tree contains the Inno Setup installer configuration and supporting scripts: File Purpose installer/MultiTerminal.iss Inno Setup script defining the installer (file selection, registry, shortcuts) installer/build-installer.ps1 PowerShell script to compile the installer from the build output installer/post-install.js Node.js post-install hook: registers MCP servers, creates config files installer/post-uninstall.js Node.js post-uninstall hook: cleans up MCP registrations"}]},{"u":"features.html","t":"Features","s":[{"id":"","t":"Features","x":"Complete reference for every user-facing feature in MultiTerminal. The application is a Windows desktop host for multiple Claude Code terminal sessions with integrated project management, team coordination, and institutional memory."},{"id":"","t":"On This Page","x":"UI Panels (11 panels + controls) Terminal Management Kanban Board Git Worktree Isolation Messaging Project Management Team & Agent System Code Intelligence (Code Graph & Wiki) Institutional Memory Settings & Theme Dialogs Remote & Phone Access (Multi-Connect) Presence-Aware Routing Newer subsystems each have a dedicated guide: Git Worktrees · Multi-Connect · Presence Sensors · Code Graph · Branch Outcomes & Wiki ."},{"id":"ui-panels","t":"UI Panels (11 panels + controls)","x":"MultiTerminal uses a VS-style docking framework (DockPanelSuite). All panels can be toggled from the toolbar, dragged to dock at any edge, floated as windows, or auto-hidden as slide-out tabs."},{"id":"panel-tasks","t":"Tasks Panel (Kanban Board)","x":"Toolbar button: Tasks | HTML: TasksPanel/tasks-panel.html A full Kanban board with three columns: To Do , In Progress , and Done . Tasks are cards that display title, assignee, helper count, checklist progress, and priority. Drag-and-drop between columns changes task status. Click a card to view details, edit the plan, or manage the checklist. Key interactions: Click + New Task to create a task from the board Drag cards between columns to change status Click a card to expand details, plan, and checklist Priority badges color-code urgency Stale task indicators show tasks with no recent activity"},{"id":"panel-chat","t":"Chat Panel","x":"Toolbar button: Chat | HTML: ChatPanel/chat-panel.html Real-time messaging between terminal sessions. Agents and users can send point-to-point messages or broadcasts. The panel shows a conversation thread with sender names, timestamps, and message content. Key interactions: Select a recipient from the terminal list dropdown Type and send messages (Enter to send) Use \"Broadcast\" to send to all registered terminals Messages appear in real-time via WebSocket push Chat history persists across sessions (view via History button)"},{"id":"panel-activity","t":"Activity Panel","x":"Toolbar button: Activity | HTML: ActivityPanel/panel.html A real-time activity feed showing everything happening across all terminals. Events include tool usage (file reads, edits, bash commands), build events, subagent spawning, task status changes, and message sends. Key interactions: Events stream in real-time with terminal name, event type, and timestamp Filter by event type or terminal Color-coded event badges distinguish tool calls, builds, and errors Useful as a \"mission control\" view when running multi-agent workflows"},{"id":"panel-project","t":"Project Panel","x":"Toolbar button: Project | HTML: ProjectPanel/panel.html Manage projects registered with MultiTerminal. View and edit project details, assign agents, configure MCP servers, manage named paths, store prompts, and enable specialist agents. Key interactions: Browse registered projects with search and filter Edit project name, description, paths, build commands, and git settings Assign agents with roles and preferred models Configure MCP servers per project (enable/disable) Manage specialist agents (verifier, debugger, security auditor, etc.) Store reusable prompts and instructions"},{"id":"panel-profile","t":"Profile Panel","x":"Toolbar button: Profiles | HTML: ProfilePanel/panel.html Displays team member profiles for all registered agents. Each profile shows avatar, display name, specialties, current availability, and role description. Key interactions: View all team member profiles in a grid or list layout See agent specialties (e.g., \"backend\", \"documentation\", \"testing\") Check availability status (active, idle, offline) Profiles are created and updated by agents via MCP tools"},{"id":"panel-inbox","t":"Inbox Panel","x":"Toolbar button: Inbox | HTML: InboxPanel/inbox-panel.html Notification center for task updates, checklist transitions, message alerts, and system events. The inbox badge shows unread count on the toolbar button. Key interactions: View notifications grouped by task or type Click a notification to navigate to the related task or message Mark notifications as read individually or in bulk Checklist transition notes appear as inbox items automatically Reply to inbox items directly"},{"id":"panel-office","t":"Office Panel","x":"Toolbar button: Office | HTML: OfficePanel/panel.html An animated visualization of the team \"office\" showing agent presence and activity. Agents appear as characters in a pixel-art style office environment, with their status reflected in their visual state. Key interactions: See which agents are currently active (animated) or idle Visual representation of the team workspace Agent positions update based on registration and activity"},{"id":"panel-agent","t":"Agent Panel","x":"Toolbar button: Agent | HTML: AgentPanel/agent-panel.html Observe spawned Claude Code team agents. When native Claude Code teams are active, this panel streams the transcript of each agent's conversation in real-time via the TeamWatcherService. Key interactions: Select a team agent from the dropdown to observe their work Transcript streams in real-time (read-only observation) See agent tool calls, reasoning, and outputs Multiple agent panels can be opened simultaneously"},{"id":"panel-file-preview","t":"File Preview Panel","x":"Toolbar button: Preview | HTML: FilePreviewPanel/file-preview.html A WebView2-based panel for previewing files directly within MultiTerminal. Supports rendering of HTML, Markdown, images, and other file types without leaving the application. Key interactions: Preview files from the project directory Rendered output for supported file types (HTML, Markdown, images) Integrated with the terminal workflow for quick file inspection"},{"id":"panel-start","t":"Start Screen","x":"HTML: StartScreen/start-screen.html The welcome screen displayed when MultiTerminal launches with no restored session. Shows registered projects with quick-launch buttons, recent sessions, and getting-started guidance."},{"id":"panel-controls","t":"Terminal Controls","x":"Terminal Status Bar HTML: Controls/TerminalStatusBar/statusbar.html A 3-row status bar displayed below each terminal: Row 1: Current folder path Row 2: Model name, git branch, and status indicators Row 3: Context window usage meter (tokens used / max) Task HUD Toolbar button: HUD | HTML: Controls/TaskHudPanel/task-hud.html A heads-up display overlay on the active terminal showing the current task title, status, and checklist progress. Provides at-a-glance awareness of what the terminal is working on. Per-Terminal Browser Tabs Location: HUD area (tabbed WebView2 above terminal) | Source: Controls/HudTabContainer/ Each terminal has a tabbed browser area in its HUD where agents can open WebView2 tabs via MCP tools. Tabs can display URLs, raw HTML content, or full interactive web applications. Capabilities Open tabs: Load a URL or render raw HTML content ( open_browser_tab ) Update content: Change a tab's HTML, URL, or title on the fly ( set_browser_content ) Execute JavaScript: Run arbitrary JS in the tab and get the return value ( execute_browser_script ) Read DOM elements: Query elements by CSS selector and read text, attributes, or innerHTML ( get_browser_element_content ) Bidirectional messaging: Agent sends JSON to the page ( post_browser_message ); page sends JSON back via window.chrome.webview.postMessage() ( get_browser_messages ) Push notifications: When a page calls post"},{"id":"terminal-management","t":"Terminal Management","x":""},{"id":"","t":"ConPty Hosting","x":"Each terminal tab hosts a ConPty (Windows Console Pseudo-Terminal) instance rendered inside a WebView2 control. This provides a full terminal emulator experience with proper ANSI escape code support, colors, cursor positioning, and resize handling."},{"id":"","t":"Tab Creation & Management","x":"New Terminal: Click \"New Terminal\" in the toolbar to open a fresh terminal tab Tab Rename: Right-click a tab to rename it (sets the terminal's display identity) Tab Close: Close tabs individually; the terminal process is terminated Tab Reorder: Drag tabs to reorder within the dock panel Grid Layouts: Use the Grid Layout dropdown to arrange terminals in 2x2, 2x3, 3x2, horizontal, or vertical layouts"},{"id":"","t":"Status Bar (3-Row Layout)","x":"Each terminal has a status bar at the bottom rendered via WebView2: Row 1 (Folder): Current working directory path Row 2 (Model/Git): Active Claude model, git branch name, and dirty/clean indicator Row 3 (Context): Visual progress bar showing context window token usage"},{"id":"","t":"Session Persistence","x":"Terminal sessions are automatically saved and restored across application restarts: Terminal identity (name), working directory, and Claude Code session ID are persisted On restart, terminals are recreated with their previous identity and can resume Claude Code sessions Session history is stored in SQLite for long-term access The docking layout (panel positions, sizes, visibility) is saved as an XML layout file"},{"id":"","t":"Start Screen","x":"When launching with no saved session, the Start Screen panel displays registered projects. Click a project to open a terminal in that project's directory with its configuration pre-loaded."},{"id":"kanban-board","t":"Kanban Board","x":""},{"id":"","t":"Task & Checklist Lifecycle","x":"Tasks move through todo → in_progress → done , and each checklist item runs its own pending → coding → testing → done cycle (with coding testing looping when testing turns up a fix). Every transition carries a mandatory note that is delivered as an inbox notification. For the full state machines, the one-active-task rule, and the testing gate, the Kanban Workflow guide is the canonical reference."},{"id":"","t":"Plans","x":"Tasks can have a markdown plan field describing the implementation approach. Plans are written by agents during the planning phase and serve as the work specification."},{"id":"","t":"Helpers","x":"Additional agents can be assigned as \"helpers\" to a task. The helper system allows multiple agents to collaborate on a single task, each handling different aspects of the work."},{"id":"","t":"Continuation Notes","x":"Free-text field for session handoff context. When an agent's session ends mid-task, continuation notes capture the current state so the next session (or a different agent) can pick up where it left off."},{"id":"","t":"Stale Task Tracking","x":"Tasks with no recent activity are flagged as \"stale\" by the StaleTaskService. This helps identify blocked or abandoned work items that need attention."},{"id":"","t":"Priority System","x":"Tasks can be assigned priority levels that affect their visual presentation on the board. Higher-priority tasks are highlighted with color-coded badges."},{"id":"worktrees","t":"Git Worktree Isolation","x":"When worktree mode is enabled ( MULTITERMINAL_WORKTREE_MODE=on ), claiming a task automatically gives each agent its own git worktree, so multiple agents can work on different tasks — or different parts of the same task — without stepping on each other's files. Auto-create on claim: the assignee gets a canonical task/<id> branch; each helper gets task/<id>--<slug> Auto-merge & prune on done: work is committed, merged back to the trunk, and the worktree directory is removed HUD git panel rebinds to the active task's worktree as you switch tasks Clean cwd moves via EnterWorktree / ExitWorktree (Claude Code ≥ 2.1.157) Full walkthrough: Git Worktrees guide ."},{"id":"messaging","t":"Messaging","x":""},{"id":"","t":"Point-to-Point Chat","x":"Any registered terminal can send a direct message to any other registered terminal. Messages are routed through the MessageBroker and delivered to the recipient's terminal via webhook injection."},{"id":"","t":"Broadcasts","x":"A terminal can broadcast a message to all other registered terminals simultaneously. Broadcasts are used for team-wide announcements."},{"id":"","t":"Inbox Notifications","x":"The inbox system delivers notifications for: New messages directed at your terminal Task assignment changes (claimed, status updated) Checklist transitions with notes Helper assignments System events (stale task warnings)"},{"id":"","t":"Reliable Delivery","x":"Messages use a reliable delivery system backed by the messages.db database: Messages are queued in SQLite before delivery Failed deliveries are retried on a timer (every 2 seconds) Message deduplication prevents double-delivery Messages expire after a configurable TTL"},{"id":"","t":"Real-Time Delivery (Channels)","x":"When a message arrives for a terminal, it is delivered through Claude Code's native Channels transport: the message appears in the session as a structured <channel> event the agent reacts to immediately, and the agent replies with the channel's reply / send tools — no polling required. This replaces the older [cm] ConPTY \"check messages\" nudge. See Channels (Messaging) for how it works and the setting it requires."},{"id":"project-management","t":"Project Management","x":""},{"id":"","t":"Project Registration","x":"Projects are registered in SQLite with metadata including: Name, description, and primary path Source path and deploy path Build command Git repository URL, default branch, and auto-commit preference Pinned status for quick access"},{"id":"","t":"Context Service","x":"The ProjectContextService provides a single API call ( GET /api/projects/{id}/context ) that returns everything an agent needs to know about a project: core details, agents, MCP servers, specialist agents, named paths, prompts, and skills."},{"id":"","t":"Agent Assignment","x":"Projects can have named agents assigned with roles (lead, member) and preferred Claude models. This determines which agents are spawned when working on the project."},{"id":"","t":"MCP Configuration","x":"Each project can have MCP servers configured and enabled/disabled. The McpConfigService generates .mcp.json files from the registry for Claude Code consumption."},{"id":"","t":"Specialist Agents","x":"Projects can enable specialist agents with custom prompts: Verifier: Confirms work is genuinely complete after coding Devils Advocate: Scores plans 0-100, blocks bad approaches Test Designer: Generates acceptance criteria per checklist item Security Auditor: OWASP Top 10 scanning, injection detection Debugger: Root cause analysis when testing fails Code Reviewer: Quality, patterns, naming, and consistency review Session Distiller: Compresses session learnings into memory Session Summarizer: Generates session recaps from JSONL transcripts"},{"id":"","t":"New Project Wizard","x":"The /new-project skill provides a 13-step conversational wizard for registering new projects. It supports 5 archetypes: Clarion COM, WebView2, Clarion App, MT Feature, and Generic C#."},{"id":"team-agent-system","t":"Team & Agent System","x":""},{"id":"","t":"Native Claude Code Teams","x":"MultiTerminal supports Claude Code's native team agent system (requires CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS=1 ). Teams are created via TeamCreate , and agents are spawned as subagents that appear in the Agent Panel."},{"id":"","t":"Spawned Agents (AgentProcess)","x":"The TerminalSpawner service can launch Claude Code processes programmatically. Each spawned agent: Gets its own terminal with a unique identity Is registered in the messaging system automatically Can communicate with other terminals via MCP tools Has its transcript monitored by TeamWatcherService"},{"id":"","t":"TeamWatcherService","x":"Monitors JSONL transcript files produced by native team agents. Streams transcript events to the Agent Panel in real-time using a file-tailing approach (TranscriptTailer)."},{"id":"","t":"Agent Naming Convention","x":"System Format Example Use For MultiTerminal Plain name Alice, Diana Planning/design (interactive) Native Teams \"Agent \" prefix Agent Alice Coding sprints (parallel)"},{"id":"code-intelligence","t":"Code Intelligence (Code Graph & Wiki)","x":"MultiTerminal indexes your C# codebase so agents can reason about it structurally instead of grepping blindly."},{"id":"","t":"Code Graph","x":"A Roslyn-based two-pass indexer extracts symbols (classes, methods, properties, constructors) and relationships (calls, inherits, implements, overrides, references). Agents query it to find callers/callees, walk inheritance trees, run impact analysis before a change, and surface dead code. A background watcher keeps the graph fresh automatically — it heals stale graphs on startup and re-indexes projects as their .cs files change, so queries reflect current code without a manual re-index. Guide: Code Graph ."},{"id":"","t":"Wiki Generator & Branch Outcomes","x":"The wiki generator auto-writes per-subsystem articles from the code graph (stored under .claude/wiki/ ). Branch outcomes let you attach a one-sentence, user-facing capability statement to a branch so it reads as a feature, not a commit log. Guide: Branch Outcomes & Wiki ."},{"id":"institutional-memory","t":"Institutional Memory","x":"MultiTerminal implements a host-controlled memory system that replaces the traditional agent-controlled approach to context management."},{"id":"","t":"Why Host-Controlled?","x":"In a standard Claude Code setup, context comes from two agent-controlled sources: CLAUDE.md — a static file the agent reads every session, same content regardless of relevance memory.md — Claude's built-in memory where the agent decides what to store and recall This has three problems: (1) static content wastes tokens on irrelevant knowledge, (2) the agent chooses what to remember rather than what's proven useful, and (3) every agent sees the same global context regardless of role. MultiTerminal inverts this. The desktop host — via hooks that run before the agent sees any prompt — controls three things the agent used to control: What Before (Agent-Controlled) Now (Host-Controlled) Knowledge in context Agent reads static CLAUDE.md every session Hook queries SQLite, ranks by attention decay, injects top entries dynamically Rules each agent sees One global CLAUDE.md for all agents Per-agent system prompt file tailored to role ( --system-prompt-file ) Hooks & settings All agents inherit user-level hooks and settings Spawned agents scoped to project+local only ( --setting-sources project --setting-sources local ) The primary terminal (e.g., Alice) still uses CLAUDE.md for project-specific instructions, but knowledge injection and session continuity are handled by hooks. Spawned team agents bypass CLAUDE.md entirely and receive only their generated system prompt."},{"id":"","t":"Knowledge Base","x":"The knowledge base stores reusable insights organized into 6 semantic categories: Category Purpose Example decision Architectural and design decisions \"Chose SQLite over JSON files for project storage\" pattern Established coding patterns \"All panels follow Initialize(broker) + ApplyTheme(isDark) pattern\" gotcha Non-obvious pitfalls \"WebView2 init blocks UI thread if done in constructor\" anti_pattern Things to avoid \"Never use $env:VARNAME in Bash tool - gets mangled\" debug_insight Debugging discoveries \"SplitterMoved fires during restore, corrupting ratios\" preference User/team preferences \"Always use PowerShell syntax in terminal commands\""},{"id":"","t":"Confidence Levels","x":"Each knowledge entry has a confidence level: observed: Seen once, may need verification confirmed: Verified across multiple interactions deprecated: Superseded by newer knowledge"},{"id":"","t":"Attention Decay","x":"Knowledge entries that are actively referenced stay prominent; stale entries fade out. Each entry tracks: reference_count — incremented every time the entry is returned by a search or injected at session start last_referenced — timestamp of most recent access At session start, the session-status-hook.js ranks all knowledge entries using the decay formula: score = (reference_count + 1) / (days_since_last_referenced + 1) Injection is tiered by rank: Tier Rank Injection Full Top 10 Title + 200-character content preview Title-only Next 5 Title only (use query_knowledge for details) Available Rest Not injected — queryable on demand via MCP tool This ensures frequently-used knowledge stays in context while rarely-accessed entries don't waste tokens. Old entries that are still actively referenced retain high scores."},{"id":"","t":"Code Digests","x":"Compressed summaries of codebase structure that agents can query to understand the project without reading every file. Digests capture file purposes, key classes, and relationships."},{"id":"","t":"Session Lineage","x":"Tracks the chain of Claude Code sessions for a terminal identity, enabling agents to understand the history of work done on a project across multiple sessions."},{"id":"","t":"Full-Text Search","x":"The knowledge database supports full-text search across all entries, enabling agents to query institutional memory with natural language. Searches automatically bump the reference_count and last_referenced timestamp of returned entries, feeding the attention decay system."},{"id":"settings-theme","t":"Settings & Theme","x":""},{"id":"","t":"Dark / Light Theme","x":"Toggle between dark and light themes using the sun/moon button in the toolbar. The theme applies to: Main form and toolbar All docking panels All WebView2 HTML panels (via ApplyTheme callback) Terminal background and text colors"},{"id":"","t":"Font Settings","x":"The Settings dialog (WPF-based) allows configuring: Terminal font family and size Font changes propagate to all open terminals in real-time"},{"id":"","t":"Docking Layout","x":"Panel positions, sizes, and visibility are saved automatically when the application closes and restored on next launch. The layout is stored as an XML file."},{"id":"","t":"Grid Layout Presets","x":"The Grid Layout dropdown provides preset arrangements for terminal tabs: 2x2, 2x3, 3x2 grids 2 or 3 horizontal splits 2 or 3 vertical splits Reset to Tabs (single tabbed view)"},{"id":"","t":"Toolbar","x":"The main toolbar contains buttons for all panel toggles, layout controls, and settings: New Terminal | Project | Chat | History | Help | Activity | Tasks | Profiles | Inbox | Office | Debug | File Preview | Recent | Grid Layout | Theme | Settings | About"},{"id":"dialogs","t":"Dialogs","x":"Modal dialogs for specific operations: Dialog Purpose Opened Via Settings (WPF) Configure terminal font, size, and application preferences Toolbar gear button New Project (WPF) Register a new project with paths, build command, and git config Project panel \"New\" button Project Manager Browse, edit, and manage all registered projects Project panel Edit Project Edit details of a specific project Project Manager dialog Chat History View historical chat messages with search and filtering Toolbar \"History\" button Session Viewer Browse Claude Code session history and metadata Terminal context menu Identity Picker Select or create a terminal identity (name) for session resumption Terminal startup Rename Tab Rename a terminal tab (changes the display name) Right-click terminal tab Save Prompt Save a reusable prompt to the project's prompt collection Project panel Owner Profile (WPF) Manage owner identity, display name, avatar, and git configuration Toolbar profile button About Application version, build info, and credits Toolbar info button"},{"id":"remote-access","t":"Remote & Phone Access (Multi-Connect)","x":"The current, recommended way to reach MultiTerminal from your phone is Multi-Connect — an in-app gateway published over your private Tailscale network. It serves a mobile PWA for task access without exposing anything to the public internet. Set it up: open Settings → Multi-Connect (Detect Tailscale, Test, Copy hostname), or run the /multi-connect-setup skill, which brings the Tailscale node up, publishes the loopback gateway over HTTPS with tailscale serve , and prints your phone URL. Full walkthrough: Multi-Connect (Phone) guide . Mobile features include a kanban task board, terminal management, an interactive console, chat with voice input, and Web-Push notifications."},{"id":"","t":"Mobile Features (Phone PWA)","x":"Feature Description Task Board View and manage kanban tasks with checklist status Terminal Management List running terminals and spawn new ones from your phone Interactive Console Full xterm.js terminal via WebSocket — type commands from your phone Chat Messaging Send messages to agents with voice input (Web Speech API) Push Notifications Native phone notifications for task updates, messages, and alerts (Web Push API + VAPID) Live Commentary Optional TTS commentary on agent activity via edge-tts PWA Support Add to home screen, works offline-first with service worker Notifications flow from Claude Code hooks → NotificationsController → the active gateway → Web Push to subscribed phones."},{"id":"presence","t":"Presence-Aware Routing","x":"MultiTerminal can sense whether you're at your desk and route agent questions accordingly — to the desktop when you're present, or to phone-push when you've stepped away. At desk — mmWave radar (Apollo MSR-2 / ESP32-C3) detects you at the machine Nearby — a registered phone's BLE signal is above its threshold Away — neither; questions and elicitations relay to your phone Presence drives the remote-mode gate (debounced to avoid flapping). Setup and tuning: Presence Sensors guide ."}]},{"u":"getting-started.html","t":"Getting Started","s":[{"id":"","t":"Getting Started","x":"MultiTerminal is a Windows desktop host for running multiple Claude Code terminal sessions side by side, with a shared Kanban board, agent messaging, and institutional memory built in. This page walks you from first launch to your first task."},{"id":"","t":"On This Page","x":"What MultiTerminal Is First Launch & the Start Screen Register or Open a Project Open a Terminal with an Identity Run Your First Task The Toolbar at a Glance Next Steps"},{"id":"","t":"Install in a Few Steps","x":"Download and run the installer — the signed Windows installer ( MultiTerminalSetup , x64). Have the prerequisites in place — MultiTerminal needs the .NET 8 Desktop Runtime and the WebView2 runtime (WebView2 is already present on Windows 11; on Windows 10 you may need to install it). The installer also offers to set up Node.js 18+ and the Claude Code CLI, which the agent integration relies on. If the .NET runtime is missing, the installer bundles a self-contained copy, so it works either way. Launch it — on first run MultiTerminal opens the Start Screen (described below) with an empty project list. For the full requirements table, building from source, and MCP server registration, see the Deployment guide."},{"id":"what-it-is","t":"What MultiTerminal Is","x":"MultiTerminal is a desktop application (.NET 8, WinForms, WebView2) that hosts many terminal sessions in one window. Each terminal can run a Claude Code session that registers a named identity (for example, Alice ), so agents can message one another, claim tasks, and hand work off. Behind the window runs an embedded REST API (port 5050) and an MCP server that give those agents structured access to the Kanban board, knowledge base, and session history. You do not have to use multiple agents to get value from it — a single terminal plus the Kanban board is a perfectly good way to start. The multi-agent features are there when you want them. For installation, system requirements, and MCP server registration, see the Deployment guide. This page assumes the app is installed and focuses on what to do the first time you open it."},{"id":"first-launch","t":"First Launch & the Start Screen","x":"When you launch MultiTerminal, the Start Screen greets you with the list of projects already registered with the app. From here you can: Open one of your registered projects (a terminal opens rooted in that project's folder). Register a new project so MultiTerminal can track it. Open a plain terminal in any folder. On a clean install the project list is empty, so the first real step is to register a project."},{"id":"register-project","t":"Register or Open a Project","x":"A project is a folder MultiTerminal knows about. Registering it stores its path plus optional metadata — assigned agents, MCP servers, named paths, prompts, and skills — in the app's SQLite database. There are two ways to register one: The /new-project wizard — run inside a Claude Code terminal, this interactive wizard onboards either a brand-new project from an archetype (Clarion COM, WebView2, Clarion App, MT Feature, Generic C#) or an existing folder you already have on disk. The Project panel — toggle it from the toolbar (the Project button) to add, edit, and inspect projects through the UI. Once a project is registered it appears on the Start Screen and in the Project panel, and any terminal you open in it inherits its context."},{"id":"open-terminal","t":"Open a Terminal with an Identity","x":"Open a terminal by choosing a project on the Start Screen, or with the New Terminal toolbar button. Each terminal tab is a full ConPTY-based shell rendered in WebView2, so you can run Claude Code or any normal command. At terminal startup the Identity Picker dialog asks you to pick an existing name or create a new one. That choice registers the terminal's named identity (such as Alice ) with MultiTerminal and lets it resume the right session. The name is how the agent appears in the team roster, how it sends and receives messages, and how it claims tasks. A registered terminal is a teammate; an unregistered shell is just a shell. The dialog is one of several covered in Features ."},{"id":"first-task","t":"Run Your First Task","x":"The shared Kanban board is the heart of the workflow. Open it with the Tasks toolbar button; for the full board tour see Features — Kanban Board . A task moves through three top-level states — todo → in_progress → done — and carries a checklist, a plan, and continuation notes. A minimal first run looks like this: Create a task — click the + (Add task) button at the top of the To Do column and give it a clear title and description. Claim it — click the Claim button on the task's card so it is assigned to your identity. Claiming is required before you work — it records who owns the task. Make it active. Each assignee has only one active task at a time; setting this one active (via the set_task_active tool, which an agent calls as it starts work) automatically pauses any other active task you hold — the card then shows an active badge. Plan and break it down — click the card title to open its lifecycle board , write a short markdown plan, and add checklist items. Work each item: move it from pending to coding , then to testing with a note describing what you did. That is the whole loop in miniature. The full lifecycle — checklist state machine, who is allowed to mark an item done, helpers, and session handoff — is documented in the Kanban Workflow guide."},{"id":"toolbar","t":"The Toolbar at a Glance","x":"The top toolbar toggles the app's panels and a few global actions. From left to right: Button What it does New Terminal Opens a new terminal tab. Project Toggles the Project panel (project registry and settings). Chat Toggles the Chat panel for messaging between terminals. History Opens chat history. Activity Toggles the Activity feed of task changes, messages, and agent events. Tasks Toggles the Kanban board. Profiles Toggles team member profiles (avatars, specialties, availability). Inbox Toggles personal notifications. Office Toggles the agent office view of spawned teammates. Debug Toggles the Debug panel (logs and diagnostics). Preview Toggles the File Preview panel. Recent Drop-down of recently opened folders. Grid layout Drop-down of tiling presets (2/3 horizontal or vertical, reset to tabs). Theme Toggles dark / light theme. Help Opens this documentation site (book icon). Settings Opens the Settings dialog (gear icon). About Shows the About dialog (info icon). The Agent panel (live agent transcript) and other views are surfaced contextually rather than from this toolbar; see Features for the full panel tour."},{"id":"next-steps","t":"Next Steps","x":""},{"id":"","t":"Kanban Workflow","x":"The full task lifecycle: statuses, checklist state machine, helpers, and handoff notes."},{"id":"","t":"Deployment","x":"Install, system requirements, and MCP server registration."},{"id":"","t":"Knowledge & Sessions","x":"Store and recall institutional memory and search past work."},{"id":"","t":"MCP Guide","x":"How Claude Code agents talk to MultiTerminal through MCP tools."}]},{"u":"hooks.html","t":"Hooks","s":[{"id":"","t":"Hooks","x":"Hooks are how the MultiTerminal plugin injects identity and context into a Claude Code session and reacts to lifecycle events. The plugin's hooks/hooks.json maps Claude Code events to Node scripts that talk to the REST API on :5050 and the local SQLite databases — making each terminal aware of its task, its inbox, and its team."},{"id":"","t":"On This Page","x":"How hooks fire Event → hook mapping Identity & context injection Messaging & nudges Activity tracking Remote & presence relays Session lifecycle Workflow automation Safety"},{"id":"model","t":"How hooks fire","x":"Claude Code emits events at well-defined points in a session — when it starts, before and after each tool call, when the agent stops, before compaction, and so on. The plugin registers Node scripts against those events in hooks/hooks.json . Each entry has an optional matcher (which tools or session sub-types it applies to), a command ( node or powershell ), and a timeout . Scripts resolve their own path through ${CLAUDE_PLUGIN_ROOT} , so the plugin is relocatable. Synchronous hooks run inline — Claude waits for them. They can inject context (stdout becomes additional context) or, for PreToolUse , block a tool call. These carry a bounded timeout — short for most, but longer for the relays that wait on phone input ( ask-user-relay-hook and elicitation-relay-hook allow ~130s). Async hooks ( \"async\": true ) are fire-and-forget — activity recording, commentary, presence — so they never slow the agent down and fail silently if the API is unreachable. Almost every hook degrades gracefully: if the REST API or the SQLite native module isn't available, it exits 0 silently rather than breaking the session."},{"id":"events","t":"Event → hook mapping","x":"This is the actual wiring from hooks.json . Several events fan out to more than one script. Event Matcher Hook script(s) SessionStart (all) project-context-hook startup|resume|clear (PowerShell parallel-subagents reminder), session-status-hook compact session-compact-hook SessionEnd (all) session-status-hook, session-import-hook PreToolUse Edit|Write|Bash|Task activity-hook AskUserQuestion ask-user-relay-hook Task task-to-agent-hook Bash / Read / Write|Edit safety-hook mcp__sqlite__write_query|mcp__mssql__query safety-hook WebSearch|WebFetch research-cache-hook PostToolUse Edit|Write|Bash|Task activity-hook, commentary-hook task checklist/status/continuation + build active-context-hook, commentary-hook update_task_checklist pipeline-trigger-hook WebSearch|WebFetch / (all) research-cache-hook, inbox-check-hook (all) context-threshold-hook PostToolUseFailure (all) activity-hook, commentary-hook PreCompact (all) session-save-hook Elicitation (all) elicitation-relay-hook Stop (all) session-save-hook, inbox-check-hook SubagentStart / SubagentStop (all) subagent-office-hook, activity-hook (+ inbox-check on stop) TeammateIdle (all) subagent-office-hook UserPromptSubmit (all) inbox-check-hook, desktop-presence-hook, context-threshold-hook Notification (all) notification-hook The sections below group those scripts by what they do. (The companion pool-context.js and profile-status-hook.j"},{"id":"identity","t":"Identity & context injection","x":"These hooks make a fresh session immediately aware of who it is and what it's working on — the heart of why MultiTerminal terminals \"know things\" without you re-explaining."},{"id":"","t":"project-context-hook","x":"SessionStart. Auto-installs the plugin on first run for a project, then reads MULTITERMINAL_PROJECT_ID and injects the project's context. No-ops gracefully if the ID is unset or the API is down."},{"id":"","t":"session-status-hook","x":"SessionStart/SessionEnd. Marks the terminal's profile online or offline so the team roster and Office Panel reflect who is active."},{"id":"","t":"active-context-hook","x":"PostToolUse on task/build tools. Queries the REST API for current task state and rewrites ACTIVE-CONTEXT.md — no agent cooperation needed — so the next session can read exactly where work stood."},{"id":"","t":"pool-context","x":"SessionStart plan-context injector. Pulls the active plan and kanban task context from the task DB and formats it for injection at the top of the session."},{"id":"","t":"session-compact-hook","x":"SessionStart with matcher compact . Fires only after compaction and re-injects the critical rules + active task state that would otherwise be lost, so behavior survives a compact."},{"id":"messaging","t":"Messaging & nudges","x":""},{"id":"","t":"Agent-to-agent messaging now uses Channels, not the [cm] nudge","x":"Inter-agent message delivery has moved off the hook-based [cm] \"check messages\" nudge and onto Claude Code's native Channels transport — the plugin's multiterminal-channel MCP server pushes messages straight into the session as <channel> events. See Channels (Messaging) for the current mechanism. The inbox-check-hook below is documented as legacy ."},{"id":"","t":"inbox-check-hook (legacy)","x":"Legacy / superseded by Channels. Checks a file-based inbox ( %APPDATA%/multiterminal/inbox/<name>.json ) and injects any waiting teammate messages as context — the old [cm] \"check messages\" nudge, which relied on the agent then polling get_messages . Current builds deliver messages directly through Channels , which is now the primary path. It still runs as a file-based fallback, though — registered on UserPromptSubmit, PostToolUse, Stop, and SubagentStop — so a queued message is still surfaced even if the channel route misses it."},{"id":"","t":"notification-hook","x":"Notification event. Captures permission prompts, idle prompts, auth-success, and elicitation dialogs and POSTs them to the REST API for storage, a UI toast, and phone push via Multi-Connect. Async, fails silently."},{"id":"","t":"context-threshold-hook","x":"PostToolUse + UserPromptSubmit. Reads the terminal's context-window fill from the statusline stats file and, at/above the threshold ( MULTITERMINAL_CONTEXT_THRESHOLD , default 70%), injects an advisory nudge as plain context — escalating 🟡70 → 🟠80 → 🔴90. It is non-blocking (never decision:\"block\" ) and never clears for you: it tells the agent to finish its current step, write continuation notes ( update_task_continuation ), then call clear_my_context at a clean boundary the agent chooses. Debounced per band via a marker file; resets after a clear so a later climb re-nudges. Silent fast-exit below threshold or on any error."},{"id":"activity","t":"Activity tracking","x":""},{"id":"","t":"activity-hook","x":"PreToolUse, PostToolUse, PostToolUseFailure, SubagentStart/Stop. Records tool usage, build events, and subagent activity to the MultiTerminal activity feed. Always async — never blocks the agent."},{"id":"","t":"commentary-hook","x":"PostToolUse. Filters for interesting events (Edit, Write, Bash, Task, MCP tools) and forwards them to the \"Commentator\" agent over MT messaging, with rate-limiting. Async, fire-and-forget."},{"id":"","t":"subagent-office-hook","x":"SubagentStart/Stop and TeammateIdle. Triggers walk-in / exit / idle animations for native subagents in the Office Panel, tracking agent-id→name mappings (and cleaning up \"ghost\" agents from interrupted sessions)."},{"id":"remote","t":"Remote & presence relays","x":"These bridge a desktop Claude session to the phone (Multi-Connect), so prompts and questions can be answered remotely."},{"id":"","t":"desktop-presence-hook","x":"UserPromptSubmit. When a real desk keyboard prompt is submitted, flips remote-mode off (\"user is at the desk\"). Carefully detects channel-injected prompts from the phone and skips them so phone input doesn't toggle presence."},{"id":"","t":"ask-user-relay-hook","x":"PreToolUse on AskUserQuestion. In remote mode, converts the question + options into a form, sends it to the phone, polls for the answer, and blocks the tool call with the answer as the reason. Falls back to the normal terminal prompt when off or on timeout."},{"id":"","t":"elicitation-relay-hook","x":"Elicitation event. Forwards an MCP server's structured-input form to the phone, polls for the response, and returns it to Claude Code. Falls back to the default terminal dialog on timeout."},{"id":"","t":"stop-relay-hook (dormant)","x":"Ships in the folder but is not wired in hooks.json . When registered against Stop it would notify the phone that the agent has stopped and is waiting for input, so the phone user knows it's their turn to reply via the channel. Today the Stop event only fires session-save-hook and inbox-check-hook , so this script stays inert unless added to the registry — like pool-context.js and profile-status-hook.js above."},{"id":"lifecycle","t":"Session lifecycle","x":""},{"id":"","t":"session-save-hook","x":"PreCompact + Stop. Ensures ACTIVE-CONTEXT.md is fresh before context is lost — catching cases (compaction, agent stop) where no tool call would otherwise trigger active-context-hook."},{"id":"","t":"session-import-hook","x":"SessionEnd. Imports the session transcript into the MultiTerminal session-lineage system and links it to the terminal's active kanban task."},{"id":"","t":"session-compact-hook","x":"SessionStart (compact). Re-injects rules + task state after compaction — see Identity & context above; it bridges both groups."},{"id":"workflow","t":"Workflow automation","x":""},{"id":"","t":"pipeline-trigger-hook","x":"PostToolUse on update_task_checklist . When every checklist item reaches testing / done , it nudges the agent to auto-run the pipeline — both as a system reminder and as a harder-to-ignore channel message."},{"id":"","t":"task-to-agent-hook","x":"PreToolUse on Task. Intercepts general-purpose subagent spawns and redirects them through AgentProcess (piped I/O) so team coding agents are visible in the Agent Panel. Quick utility tasks (Explore, Plan, haiku) pass through natively."},{"id":"","t":"research-cache-hook","x":"PreToolUse + PostToolUse on WebSearch/WebFetch. Before: returns matching cached research from the knowledge base so the agent can skip redundant searches. After: auto-saves a summarized result for future agents, deduped by query hash. Never blocks."},{"id":"safety","t":"Safety","x":""},{"id":"","t":"safety-hook","x":"PreToolUse guard registered against Bash, Read, Write/Edit, and the SQL MCP tools ( mcp__sqlite__write_query , mcp__mssql__query ). It intercepts those calls to block outright (DENY) or gate dangerous operations — the guardrail that matters most in a multi-agent environment where one rogue command can do real damage. It's the only hook here whose job is to stop a tool call rather than observe or enrich it."}]},{"u":"index.html","t":"MultiTerminal","s":[{"id":"","t":"MultiTerminal","x":"Multi-agent coordination system for Claude Code New here? Start with Getting Started . WinForms Desktop App · .NET 8 · WebView2"},{"id":"","t":"Documentation","x":""},{"id":"","t":"Getting Started","x":"System requirements, installation, first launch walkthrough, and key concepts."},{"id":"","t":"Kanban Workflow","x":"The shipped task lifecycle: statuses, the checklist state machine, helpers, and handoff notes."},{"id":"","t":"Features","x":"Kanban board, messaging, projects, team agents, knowledge base, and more."},{"id":"","t":"REST API","x":"HTTP endpoints on port 5050 for tasks, messaging, projects, and tools."},{"id":"","t":"MCP Tools","x":"Model Context Protocol tools for Claude Code agent integration."},{"id":"","t":"Architecture","x":"System layers, data flow, database schema, and key design patterns."},{"id":"","t":"Distribution","x":"Packaging, publishing, and distributing MultiTerminal."},{"id":"","t":"Deployment","x":"Build process, deploy workflow, and environment configuration."},{"id":"","t":"Knowledge & Sessions","x":"Store and recall institutional memory; search past session transcripts and lineage."},{"id":"","t":"Branch Outcomes & Wiki","x":"Per-branch capability statements and the code-graph-driven wiki generator."},{"id":"","t":"Git Worktrees","x":"Per-task git worktree isolation: auto-create on claim, auto-merge and prune on done."},{"id":"","t":"Code Graph","x":"Roslyn-indexed symbols and relationships: callers, callees, inheritance, and search."},{"id":"","t":"Multi-Connect (Phone)","x":"Connect your phone to MultiTerminal over Tailscale — the current mobile access path."},{"id":"","t":"Presence Sensors","x":"At-desk vs nearby vs away routing that drives where remote questions are sent."},{"id":"","t":"Troubleshooting / FAQ","x":"Common issues and answers: terminals, MCP connectivity, ports, and data location."},{"id":"","t":"API Examples","x":"Worked curl, PowerShell, and Python examples against the REST API on port 5050."},{"id":"","t":"Feature Highlights","x":""},{"id":"","t":"11 UI Panels","x":"Kanban board, chat, activity feed, inbox, profiles, projects, start screen, agents, debug, file preview, and office — all in a dockable layout."},{"id":"","t":"REST API (Port 5050)","x":"Full HTTP API for tasks, messaging, projects, and self-documenting tool discovery."},{"id":"","t":"MCP Server","x":"Node.js MCP server exposes ~90 tools to Claude Code agents via the Model Context Protocol."},{"id":"","t":"Team Agents","x":"Spawn, monitor, and coordinate multiple Claude Code agent teammates from a single desktop."},{"id":"","t":"Knowledge Base","x":"Institutional memory system with code digests, session history, and queryable knowledge entries."},{"id":"","t":"Project Management","x":"SQLite-backed project registry with agents, MCP servers, paths, prompts, and skills per project."},{"id":"","t":"Quick Links","x":"Installation Kanban Board API Endpoints MCP Tool List Database Schema Build & Deploy MultiTerminal © 2026. See THIRD-PARTY-NOTICES.md for license information."}]},{"u":"kanban-workflow.html","t":"Kanban Workflow","s":[{"id":"","t":"Kanban Workflow","x":"MultiTerminal's task board is a two-level state machine: tasks move through three statuses, and each checklist item runs its own coding/testing cycle. This page describes the lifecycle exactly as it ships — the rules the app and its MCP tools actually enforce."},{"id":"","t":"On This Page","x":"Task Status & Sub-Status The One-Active-Task Rule The Checklist State Machine Who Marks an Item Done Plans & Continuation Notes Helpers File Traceability A Task, End to End"},{"id":"task-status","t":"Task Status & Sub-Status","x":"Every task has a top-level Status with one of three values: Status Meaning todo Created but not started. The default for a new task. in_progress Being worked on. done Complete. While a task is in_progress it also carries a SubStatus of either active (the task you are working on right now) or paused (started but set aside). A task can be claimed by an assignee — the identity that owns it — and records who created it. Tasks can also be linked to one another with relationships of type blocks , depends_on , or related_to , and carry a priority of urgent , normal (default), or low that influences whether claiming a task interrupts your current work or queues behind it. AutoStatus is a per-task flag you toggle from the Auto-status checkbox in a task's detail popover on the lifecycle board (it is saved on the task). While it is enabled, the task's top-level status is derived automatically from where its checklist items sit: all items still pending → todo ; any item in coding or testing → in_progress ; all items done → done . Turning AutoStatus off lets you set the status by hand."},{"id":"active-rule","t":"The One-Active-Task Rule","x":"An assignee may have only one active task at a time . Setting a task active (via set_task_active ) automatically pauses every other active task held by the same assignee and returns the list of what it paused. This keeps a single, unambiguous answer to what are you working on right now? — which is exactly what the auto-cd and worktree features rely on. Priority interacts with this rule when you claim a task: a normal or low priority task claimed while you already have active work is queued behind it rather than interrupting; the claim result reports that it was queued and what it is queued behind."},{"id":"checklist","t":"The Checklist State Machine","x":"A task's real work happens in its checklist. Each item is more than a checkbox — it has its own status and a trail of transition notes. The valid item statuses are: Item status Meaning pending Not started. coding Being implemented. testing Implementation complete, awaiting verification. done Verified and finished. The transition tool ( update_task_checklist ) enforces the state machine: pending → coding → testing → done , with cycling allowed between coding and testing when testing turns up something to fix. Notes are mandatory on the coding → testing , testing → coding , and testing → done transitions — you must say what you did or what needs fixing. Every transition appends a note to the item's history recording who made it, when , the transition (e.g. coding → testing ), and the text. The item also tracks a CycleCount that increments each time it bounces from testing back to coding ; once it reaches four or more, that testing → coding bounce posts an escalation notification to the Inbox so a stuck item gets attention instead of looping silently."},{"id":"testing-gate","t":"Who Marks an Item Done","x":"The coder drives an item up to testing with a note describing what was built. By team convention the testing → done transition is reserved for the PM / tester — the person verifying the work — not the coder who wrote it. This separation is the quality gate: the implementer says ready for verification, and someone else confirms it actually works before the item is closed. (The state machine permits the transition with a note; the only the tester closes it rule is the workflow discipline layered on top.) Working solo? You play both roles — coder and tester — on the same task. Nothing stops you moving testing → done yourself, but the gate is only as honest as you make it: actually verify the work before you close the item rather than rubber-stamping your own code."},{"id":"plan-notes","t":"Plans & Continuation Notes","x":"Two free-text fields keep a task self-documenting across sessions: Plan — a markdown field describing the approach and steps. Write it before you start coding so the checklist has a rationale behind it. Continuation notes — a short pick up here field for session handoffs. It captures the current file, checklist progress, what's next, and any blockers, and is read back when a later session resumes the task. It is updated as checklist items transition and at session end, so the next agent (or the next you) lands with context instead of a cold start. Tasks additionally support an implementation summary and test-results field used when a task is completed, plus structured review notes written by a human reviewer from the diff viewer."},{"id":"helpers","t":"Helpers","x":"A task's assignee can pull in helpers — other agents (often spawned sub-agents) added to the task to work alongside the assignee. Helpers are notified when added and can receive help requests from the assignee. Individual checklist items can also be assigned to a specific agent, so a helper owns just the items relevant to them while the assignee keeps the task as a whole."},{"id":"traceability","t":"File Traceability","x":"As work touches the codebase, link the files to the task with link_task_file . Each link records the file path, an optional description and line range, and who added it. Links can be task-scoped (the default, applying to the whole task) or scoped to a single checklist item, which drives per-item routing of review notes. The result is a durable record of exactly which files a task changed — useful for review, for the next session, and for tracing why a file changed months later."},{"id":"lifecycle","t":"A Task, End to End","x":"Putting the pieces together, the shipped lifecycle of a typical task looks like this: Create a task ( todo ) with a title and description. Claim it so it has an assignee — claiming before working is the rule that keeps ownership clear. Set it active , which pauses any other active task you hold. Plan the approach and add checklist items (all pending ). Code each item: pending → coding , then coding → testing with a note. Link the files you touched. Test : the tester/PM verifies and moves testing → done , or sends it back to coding with a note for a fix (incrementing the cycle count). When all items are done , the task reaches done — automatically under AutoStatus, or by hand otherwise. Throughout, continuation notes and linked files keep the task readable to whoever picks it up next. For where this board fits in the bigger picture, see Getting Started ; for the tools agents use to drive it, see the MCP Tools reference."}]},{"u":"knowledge-sessions.html","t":"Knowledge & Sessions","s":[{"id":"","t":"Knowledge & Sessions","x":"MultiTerminal remembers two kinds of things: knowledge — the durable decisions, patterns, and gotchas worth keeping — and sessions — the full transcripts of past work you can search back through. Both live in SQLite and are reachable from MCP tools, so an agent can store what it learns and recall what was done before."},{"id":"","t":"On This Page","x":"The Knowledge Base Storing Knowledge Recalling Knowledge & Attention Decay Session Memory & History Finding Past Work Lineage Chains"},{"id":"knowledge","t":"The Knowledge Base","x":"The knowledge base is institutional memory: short, titled entries capturing things the team has learned. It is stored in the knowledge_entries table and managed by KnowledgeDatabase , which shares the same SQLite file (and FTS5 full-text index) as the task board. Each entry has a category describing what kind of knowledge it is: Category Use it for decision A choice that was made and why. pattern A reusable approach that works here. gotcha A surprising trap or footgun to avoid. anti_pattern An approach that looks reasonable but should not be used. debug_insight A root cause or diagnosis worth remembering. preference A team or owner preference about how things are done. An entry also carries an optional project ID (null means the entry is global), comma-separated tags, the source it came from (manual, session, task, and similar), and a confidence level. Confidence has three values, set when adding: confirmed (the default), likely , and uncertain . Separately, an entry has a lifecycle state : it can later be deprecated , which retires it and excludes it from search results by default. Deprecation is a state change, not a confidence level — and it can point at the newer entry that supersedes it (via superseded_by ), so you can follow the chain."},{"id":"knowledge-store","t":"Storing Knowledge","x":"Add an entry with the add_knowledge MCP tool. It requires a title , the content , and a category ; everything else (project, tags, source, confidence) is optional. A good entry is a single, self-contained lesson with a title you would actually search for later — for example a gotcha titled WebView2 host objects must be added before navigation rather than a vague note. Capture knowledge at the moment you learn it — right after a tricky debug, a design decision, or discovering a constraint — while the detail is fresh. That is what makes it useful to the next agent who hits the same wall."},{"id":"knowledge-recall","t":"Recalling Knowledge & Attention Decay","x":"Search the base with query_knowledge , passing a free-text query and optionally a category, project, or tag filter. Search uses FTS5 full-text matching when available and falls back to a LIKE query otherwise; deprecated entries are left out unless you ask for them. Every time an entry is queried or injected into context, its reference count is bumped and its last referenced timestamp is updated. That feeds an attention-decay ranking used when surfacing the most relevant memory: score = (reference_count + 1) / (days_since_last_referenced + 1) Entries that are referenced often and recently rank highest; an entry that has not been touched in a long time decays toward the bottom even if it was once popular. The effect is that memory which is still being used stays prominent, while stale memory quietly recedes without having to be deleted."},{"id":"sessions","t":"Session Memory & History","x":"Beyond curated knowledge, MultiTerminal keeps the raw record of past work. Claude Code writes each session to a JSONL transcript on disk; SessionLineageService imports those transcripts into SQLite — a session_lineage record per session plus the extracted messages in session_messages , indexed for full-text search. A separate session-memory store additionally chunks transcripts and embeds them for semantic search. Importing happens a few ways: import_session brings in a single transcript and links it to a task; sync_sessions incrementally scans a Claude project folder and imports any sessions not already stored, skipping ones it has seen for a fast re-sync."},{"id":"sessions-search","t":"Finding Past Work","x":"There are two complementary ways to search the history, plus a shortcut for the most common need: Tool What it does search_session_history Full-text (FTS5, with LIKE fallback) search across imported session messages. Filter by task, role (user/assistant), agent, or free text. Best when you remember roughly what was said. search_session_memory Semantic search over transcript chunks using vector embeddings plus FTS5. Finds context by meaning, not just keywords — ask it a natural-language question like what was the WebView2 event bridge approach? get_latest_session Returns the most recent previous session for a project (with its cached summary, or recent messages if none), filterable by agent. Use it at session start to recall what was last worked on. Reach for search_session_history when you remember the words; reach for search_session_memory when you only remember the idea."},{"id":"lineage","t":"Lineage Chains","x":"Sessions are not isolated — they form lineage chains . When one session continues from another (an agent cycling through coding then review, or a session rolling over), the new session records the previous one as its parent. get_session_lineage walks that parent chain to reconstruct the full history of a task from root to leaf, and get_task_sessions lists every session linked to a task with its agent, type, and parent links. Together they let you replay how a piece of work actually unfolded across multiple sessions and agents. For the institutional-memory tools alongside the rest of the MCP surface, see the MCP Tools reference; for how all of this is wired together, see the Architecture overview."}]},{"u":"mcp-architecture.html","t":"MCP Architecture","s":[{"id":"","t":"MCP Architecture","x":"Technical documentation for the MCP (Model Context Protocol) subsystem. Covers the two-server design, gateway proxy architecture, configuration flow, and data storage."},{"id":"","t":"On This Page","x":"System Overview Configuration & Launch Flow MultiTerminal MCP Server MCP Gateway Gateway Database Schema Tool Routing & Aggregation Profile System Server Lifecycle & Recovery Installer Integration File Reference"},{"id":"overview","t":"System Overview","x":"Claude Code connects to exactly two MCP servers. One of those servers (the gateway) acts as a proxy, aggregating tools from any number of backend servers. This keeps the Claude Code connection count fixed while allowing unlimited MCP server expansion. Claude Code (in MultiTerminal terminal) | |-- --mcp-config %APPDATA%\\multiterminal\\.mcp.json | +-- mcp-gateway (McpGateway.exe) [.NET 8 console app] | | | +-- sqlite MCP server [backend, managed by gateway] | +-- mssql MCP server [backend, managed by gateway] | +-- any-other-mcp [backend, managed by gateway] | +-- gateway__* tools [self-management tools] | +-- multiterminal (index.js) [Node.js MCP server] | +-- REST API (localhost:5050) [MultiTerminal app] From Claude Code's perspective, it sees tools from all sources merged into two server connections. The gateway transparently proxies tool calls to the correct backend."},{"id":"config-flow","t":"Configuration & Launch Flow","x":"When MultiTerminal launches a terminal with Claude Code, the following happens: LaunchCommandBuilder constructs the Claude Code command line, adding --mcp-config pointing to %APPDATA%\\multiterminal\\.mcp.json McpConfigService writes an empty .mcp.json to the project folder (project-level servers are managed by gateway profiles, not static config) Claude Code starts and reads the --mcp-config file, connecting to both servers The mcp-gateway starts, reads its SQLite database, and spawns all enabled backend servers for the active profile The multiterminal server starts and connects to the REST API at localhost:5050"},{"id":"","t":"Configuration file","x":"The MCP configuration lives at %APPDATA%\\multiterminal\\.mcp.json : { \"mcpServers\": { \"mcp-gateway\": { \"type\": \"stdio\", \"command\": \"C:\\\\Program Files\\\\MultiTerminal\\\\mcp-gateway\\\\McpGateway.exe\", \"args\": [] }, \"multiterminal\": { \"type\": \"stdio\", \"command\": \"node\", \"args\": [\"C:\\\\Users\\\\...\\\\AppData\\\\Roaming\\\\multiterminal\\\\mcp\\\\index.js\"] } } } This file is generated by the installer's post-install.js script with correct paths for the target machine. It is not shipped as a static file."},{"id":"multiterminal-mcp","t":"MultiTerminal MCP Server","x":"The multiterminal server is a Node.js application that wraps the MultiTerminal REST API (port 5050) with MCP tool interfaces. It provides ~90 tools organized into categories: Category Tools Examples Task Management 14 list_tasks , create_task , update_checklist Messaging 7 send_message , broadcast_message , get_inbox Code Search 2 search_code (ripgrep), search_files Browser Tabs 7 open_browser_tab , set_browser_content , capture_browser_screenshot Projects 6 get_project , list_projects , update_project Session & Knowledge 8 search_session_history , query_knowledge , save_code_digest Build & Run 5 build_project , run_command , run_powershell_script"},{"id":"","t":"Key files","x":"File Location Role index.js %APPDATA%\\multiterminal\\mcp\\ Entry point, tool registration, stdio transport package.json %APPDATA%\\multiterminal\\mcp\\ Dependencies ( @modelcontextprotocol/sdk ) All tool calls are translated to HTTP requests against http://localhost:5050/api/* . The REST API is hosted by the MultiTerminal WinForms application via MultiTerminalRestServer.cs ."},{"id":"mcp-gateway","t":"MCP Gateway","x":"The gateway is a .NET 8 console application that implements the MCP protocol over stdio. It serves two purposes: Proxy: spawns backend MCP servers as child processes and aggregates their tools into its own tool list. Tool calls are routed to the correct backend transparently. Manager: exposes its own gateway__* tools for adding, removing, enabling, and disabling backend servers at runtime."},{"id":"","t":"Application architecture","x":"McpGateway.exe | Program.cs Entry point, DI container setup | Services/ | GatewayHostedService.cs MCP server host, tool routing, startup orchestration | BackendManager.cs Spawns/stops backend MCP processes, stdio communication | ProfileManager.cs Active profile tracking, server filtering | ToolAggregator.cs Merges tool lists from all connected backends | Tools/ | ServerManagementTools.cs gateway__list/add/remove/enable/disable_server | ProfileManagementTools.cs gateway__list/create/delete/set_profile | ImportTools.cs gateway__import_mcp_config, gateway__import_claude_config | Data/ GatewayDatabase.cs SQLite persistence (servers, profiles, associations)"},{"id":"","t":"Communication","x":"Upstream (Claude Code gateway): MCP protocol over stdio (stdin/stdout) Downstream (gateway backends): MCP protocol over stdio (each backend is a child process) Logging: stderr only, disabled by default. Set MCP_GATEWAY_DEBUG=1 to enable. Stdout is reserved for the MCP protocol. Any console output to stdout will corrupt the protocol stream. All logging must go to stderr."},{"id":"gateway-database","t":"Gateway Database Schema","x":"The gateway stores all configuration in SQLite at %APPDATA%\\multiterminal\\gateway\\gateway.db . The database is created automatically on first run."},{"id":"","t":"servers","x":"Registry of all MCP servers known to the gateway. Column Type Description id INTEGER PK Auto-increment ID name TEXT UNIQUE Server name (e.g., \"sqlite\", \"my-api\") command TEXT Executable to run (e.g., \"npx\", \"node\") args_json TEXT JSON array of command arguments env_json TEXT JSON object of environment variables is_enabled INTEGER 1 = enabled, 0 = disabled created_at TEXT ISO 8601 timestamp"},{"id":"","t":"profiles","x":"Named server groupings for different contexts. Column Type Description id INTEGER PK Auto-increment ID name TEXT UNIQUE Profile name (e.g., \"default\", \"web-dev\") is_active INTEGER 1 = currently active profile created_at TEXT ISO 8601 timestamp"},{"id":"","t":"profile_servers","x":"Many-to-many join between profiles and servers. Column Type Description profile_id INTEGER FK References profiles(id) server_id INTEGER FK References servers(id) Foreign keys are enforced. Deleting a profile cascades to remove its profile_servers entries."},{"id":"tool-routing","t":"Tool Routing & Aggregation","x":"When Claude Code requests the tool list, the gateway: Collects tools from all connected backend servers via ToolAggregator Prefixes each tool name with the server name (e.g., sqlite__read_query , mssql__query ) to avoid collisions Adds its own management tools ( gateway__list_servers , etc.) Returns the merged list to Claude Code When Claude Code calls a tool: GatewayHostedService receives the call If the tool starts with gateway__ , it's handled internally (server/profile/import tools) Otherwise, the prefix identifies the backend server, and the call is forwarded via BackendManager The backend's response is returned to Claude Code Claude Code calls: mssql__query(sql=\"SELECT 1\") | GatewayHostedService | prefix = \"mssql\" tool = \"query\" | BackendManager.CallTool(\"mssql\", \"query\", {sql: \"SELECT 1\"}) | mssql child process (stdio) | result returned to Claude Code"},{"id":"profiles","t":"Profile System","x":"Profiles control which backend servers are active. Only one profile is active at a time."},{"id":"","t":"Startup behavior","x":"Gateway reads gateway.db If no profiles exist, creates a default profile containing all servers If --profile <name> or MCP_GATEWAY_PROFILE is set, activates that profile Connects all enabled servers in the active profile"},{"id":"","t":"Runtime switching","x":"When gateway__set_profile is called: Disconnects servers not in the new profile Connects servers that are in the new profile but weren't connected Keeps servers that are in both profiles running Fires a tools/list_changed notification so Claude Code refreshes its tool list MultiTerminal's GatewayIntegrationService can sync project-specific profiles automatically. When you open a project, it activates the corresponding gateway profile, giving agents access to the right set of tools for that project."},{"id":"lifecycle","t":"Server Lifecycle & Recovery","x":""},{"id":"","t":"Backend startup","x":"Each backend server is spawned as a child process with a 30-second connection timeout . If a server fails to initialize within this window, it's marked as disconnected but remains registered."},{"id":"","t":"Crash recovery","x":"If a backend process crashes, the gateway detects the exit and attempts automatic restart: 3 retry attempts with exponential backoff (2s, 5s, 10s) If all retries fail, the server is marked as disconnected The server can be manually restarted via gateway__enable_server"},{"id":"","t":"Gateway shutdown","x":"When Claude Code closes the MCP connection (session end), the gateway: Sends shutdown signals to all backend child processes Waits briefly for graceful shutdown Terminates any remaining processes Exits cleanly"},{"id":"installer","t":"Installer Integration","x":"The Inno Setup installer handles MCP distribution and configuration:"},{"id":"","t":"What gets installed","x":"Component Install Location Contents MCP Gateway {app}\\mcp-gateway\\ McpGateway.exe + .NET dependencies (framework-dependent) MultiTerminal MCP %APPDATA%\\multiterminal\\mcp\\ index.js , package.json , node_modules\\"},{"id":"","t":"Post-install configuration","x":"The post-install.js script runs after file installation and: Generates %APPDATA%\\multiterminal\\.mcp.json with correct paths to both servers Removes any legacy MCP entries from ~/.claude.json (from older versions) Merges hooks into Claude Code's global settings.json Generates project-level .claude/project.json and settings.local.json"},{"id":"","t":"Uninstall cleanup","x":"The post-uninstall.js script: Deletes %APPDATA%\\multiterminal\\.mcp.json Removes legacy entries from ~/.claude.json Removes MCP server files from AppData Optionally deletes user data (databases) if the user confirms"},{"id":"","t":"Build process","x":"Run installer\\build-installer.ps1 to publish both projects and compile the installer: # Full build: publish + installer .\\build-installer.ps1 # Installer only (reuse last publish output) .\\build-installer.ps1 -SkipPublish The script publishes MultiTerminal (self-contained) and MCP Gateway (framework-dependent, win-x64) before invoking Inno Setup."},{"id":"file-reference","t":"File Reference","x":""},{"id":"","t":"Runtime files (end-user machine)","x":"Path Purpose %APPDATA%\\multiterminal\\.mcp.json MCP server config (loaded via --mcp-config ) %APPDATA%\\multiterminal\\mcp\\index.js MultiTerminal MCP server entry point %APPDATA%\\multiterminal\\gateway\\gateway.db Gateway SQLite database (servers, profiles) {app}\\mcp-gateway\\McpGateway.exe MCP Gateway executable"},{"id":"","t":"Source files (development)","x":"Path Purpose McpGateway/Program.cs Gateway entry point and DI setup McpGateway/Services/BackendManager.cs Backend MCP process lifecycle McpGateway/Services/GatewayHostedService.cs MCP server host and tool routing McpGateway/Data/GatewayDatabase.cs SQLite persistence layer MultiTerminal/Services/McpConfigService.cs Per-project MCP config generation MultiTerminal/Services/GatewayIntegrationService.cs Gateway profile sync for projects MultiTerminal/Services/LaunchCommandBuilder.cs Adds --mcp-config to Claude Code launch command MultiTerminal/installer/post-install.js Generates .mcp.json during installation MultiTerminal/installer/build-installer.ps1 Publish + compile installer script"},{"id":"","t":"Related Documentation","x":""},{"id":"","t":"MCP Guide","x":"End-user guide to understanding and using MCPs."},{"id":"","t":"MCP Tools Reference","x":"Full list of ~90 tools with parameters and examples."},{"id":"","t":"System Architecture","x":"Overall MultiTerminal architecture and data flow."},{"id":"","t":"Deployment","x":"Build process and deployment workflow. MultiTerminal © 2026. See THIRD-PARTY-NOTICES.md for license information."}]},{"u":"mcp-guide.html","t":"MCP Guide","s":[{"id":"","t":"MCP Guide","x":"MCP (Model Context Protocol) is how Claude Code agents interact with MultiTerminal. This guide explains what you'll see, how to manage your MCP servers, and how to bring your existing MCPs under one roof."},{"id":"","t":"On This Page","x":"What is MCP? What You See After Installation The Two Built-in Servers Your Existing MCPs Importing MCPs into the Gateway Managing Servers Using Profiles Troubleshooting"},{"id":"what-is-mcp","t":"What is MCP?","x":"MCP servers give Claude Code agents tools — the ability to do things beyond just generating text. Through MCP, agents can create tasks, send messages, search code, manage databases, and interact with external services. Think of MCP servers as plugins for Claude Code. Each server provides a set of tools that agents can call. MultiTerminal ships with two MCP servers that give agents full access to the MultiTerminal platform. New to MCP? You can skip the Your Existing MCPs and Importing MCPs sections below — the two built-in servers work out of the box with no configuration. Come back to them only when you want to bring your own MCP servers under one roof."},{"id":"what-you-see","t":"What You See After Installation","x":"After installing MultiTerminal, open a terminal and run /mcp in Claude Code. You'll see something like this: Your exact list will differ — the servers above the divider are whatever you already had configured. The point is that the two MultiTerminal built-ins ( mcp-gateway and multiterminal ) appear at the bottom. Manage MCP servers 5 servers your-existing-mcp-1 - connected your-existing-mcp-2 - connected your-existing-mcp-3 - connected Built-in MCPs (always available) mcp-gateway - connected multiterminal - connected Your existing MCPs are unchanged — they still work exactly as before. MultiTerminal adds two new servers below them. The two MultiTerminal servers are loaded automatically whenever you open a terminal through MultiTerminal. They won't appear in standalone Claude Code sessions outside of MultiTerminal."},{"id":"two-built-in-servers","t":"The Two Built-in Servers","x":"Server Purpose Example Tools multiterminal Core tools for tasks, messaging, code search, browser tabs, projects, and team coordination list_tasks , send_message , search_code , open_browser_tab mcp-gateway MCP proxy and manager — aggregates tools from other MCP servers and provides server/profile management gateway__list_servers , gateway__add_server , gateway__set_profile The multiterminal server is what agents use day-to-day — managing tasks, sending messages, searching your codebase. See the MCP Tools Reference for the full list of ~90 tools. The mcp-gateway server is your MCP management layer. It acts as a proxy: you register other MCP servers with the gateway, and it aggregates all their tools into a single connection. This gives you centralized control over which servers are active, organized by profiles."},{"id":"your-existing-mcps","t":"Your Existing MCPs","x":"If you already have MCP servers configured in Claude Code (in your ~/.claude.json or project-level .mcp.json files), they continue to work alongside MultiTerminal's servers. Nothing changes about your existing setup. Over time, you can choose to import your existing MCPs into the gateway. This is optional but gives you benefits: Centralized management — enable/disable servers without editing JSON files Profiles — switch between different server sets for different projects Visibility — see all your MCP servers and their status in one place Reliability — the gateway handles crash recovery and automatic reconnection"},{"id":"importing-mcps","t":"Importing MCPs into the Gateway","x":"To bring your existing MCPs under gateway management, use the import tools from any Claude Code terminal:"},{"id":"","t":"Import from Claude Code config","x":"This reads your ~/.claude.json and imports all MCP servers found there: gateway__import_claude_config()"},{"id":"","t":"Import from an .mcp.json file","x":"Point to any .mcp.json file to import its servers: gateway__import_mcp_config(configPath=\"C:/path/to/.mcp.json\") Importing is non-destructive — it copies server configurations into the gateway database. Your original config files are not modified. You can remove the originals later once you've confirmed everything works through the gateway."},{"id":"managing-servers","t":"Managing Servers","x":"Once servers are registered with the gateway, you can manage them using these tools: Tool What It Does gateway__list_servers Show all registered servers with connection status gateway__add_server Register a new MCP server (name, command, args) gateway__remove_server Unregister a server gateway__enable_server Enable a disabled server (starts it up) gateway__disable_server Disable a server without removing it"},{"id":"","t":"Adding a server manually","x":"gateway__add_server( name=\"my-database-mcp\", command=\"npx\", args=[\"-y\", \"@my-org/database-mcp\"], env={\"DB_URL\": \"postgresql://localhost/mydb\"} )"},{"id":"profiles","t":"Using Profiles","x":"Profiles let you define sets of servers for different contexts. For example, you might have a \"web-dev\" profile with database and API servers, and a \"data-science\" profile with notebook and visualization servers. Tool What It Does gateway__list_profiles Show all profiles and which is active gateway__create_profile Create a new profile with selected servers gateway__set_profile Switch the active profile (connects/disconnects servers as needed) gateway__delete_profile Remove a profile A default profile is created automatically and includes all registered servers. You can create additional profiles to customize which servers are available per project. MultiTerminal can automatically switch gateway profiles when you open different projects. Configure this in the project settings under MCP Servers."},{"id":"troubleshooting","t":"Troubleshooting","x":""},{"id":"","t":"MCP servers not showing up","x":"Make sure you're running Claude Code from within a MultiTerminal terminal. The MCP servers are loaded via the --mcp-config flag, which MultiTerminal sets automatically when launching terminals."},{"id":"","t":"Gateway shows \"disconnected\"","x":"Check that .NET 8 Runtime is installed. The gateway is a .NET application and requires the runtime. Run dotnet --list-runtimes to verify."},{"id":"","t":"Imported server won't connect","x":"Verify the server's command is available on your PATH. Use gateway__list_servers to check the connection status and error messages. The gateway retries failed connections automatically (up to 3 attempts with exponential backoff)."},{"id":"","t":"Want to debug gateway output","x":"Set the environment variable MCP_GATEWAY_DEBUG=1 to enable stderr logging from the gateway process."},{"id":"","t":"Next Steps","x":""},{"id":"","t":"MCP Tools Reference","x":"Full list of ~90 tools available to agents."},{"id":"","t":"MCP Architecture","x":"Technical deep-dive into how the MCP system works."},{"id":"","t":"Features","x":"Explore all MultiTerminal capabilities. MultiTerminal © 2026. See THIRD-PARTY-NOTICES.md for license information."}]},{"u":"mcp-tools.html","t":"MCP Tools Reference","s":[{"id":"","t":"MCP Tools Reference","x":"Reference for the MCP tools (~90) exposed to Claude Code agents via the MultiTerminal MCP server. Tools are called as mcp__multiterminal__<tool_name> from Claude Code. The per-category listing below covers the core set; some newer tools (worktrees, branch outcomes, wiki, code graph) are documented on their own pages. How it works: The MCP server ( %APPDATA%\\multiterminal\\mcp\\index.js ) wraps the REST API at http://localhost:5050 . Each tool call translates to one or more REST API calls."},{"id":"","t":"On This Page","x":"Task Management (16 tools) Task Relationships (3 tools) Task File Links (3 tools) Task Reports (2 tools) Messaging (8 tools) Team & Helpers (4 tools) Projects (6 tools) Knowledge Base (4 tools) Sessions (9 tools) Context Self-Management (2 tools) Browser Tabs (11 tools) Build & Run (5 tools) XAML (1 tool) Debug (6 tools) Code Search (2 tools)"},{"id":"task-management","t":"Task Management","x":""},{"id":"","t":"list_tasks","x":"List all kanban tasks from the MultiTerminal board. Parameters Name Type Required Description status string No Filter by status: all , todo , in_progress , done , suggestion . Default: all Returns Formatted text listing all tasks with ID, title, status, assignee, and priority. Example list_tasks(status=\"in_progress\")"},{"id":"","t":"create_task","x":"Create a new kanban task (ticket) on the MultiTerminal board. Parameters Name Type Required Description title string Yes Task title description string Yes Task description createdBy string Yes Your name status string No Initial status: todo , in_progress , done , suggestion . Default: todo priority string No Priority: low , normal , high . Default: normal Returns Task ID and confirmation message. Example create_task( title=\"Add dark mode\", description=\"Implement dark/light theme toggle in settings panel\", createdBy=\"Alice\", priority=\"normal\" )"},{"id":"","t":"update_task_status","x":"Update the status of a kanban task. Parameters Name Type Required Description taskId string Yes Task ID status string Yes New status: todo , in_progress , done , suggestion updatedBy string Yes Your name Returns Success confirmation. Example update_task_status(taskId=\"c0ce8037\", status=\"in_progress\", updatedBy=\"Alice\")"},{"id":"","t":"delete_task","x":"Delete a kanban task. Parameters Name Type Required Description taskId string Yes Task ID to delete deletedBy string Yes Your name Returns Success confirmation. Example delete_task(taskId=\"c0ce8037\", deletedBy=\"Alice\")"},{"id":"","t":"claim_task","x":"Claim/assign a kanban task to yourself or another team member. Parameters Name Type Required Description taskId string Yes Task ID to claim assignee string Yes Name of the person claiming the task Returns Success confirmation. May include a complexity suggestion if the task is detected as complex. Example claim_task(taskId=\"c0ce8037\", assignee=\"Alice\")"},{"id":"","t":"set_task_active","x":"Set a task as the active task, auto-pausing all other active tasks for the same assignee. Enforces the \"only one active task\" rule. Parameters Name Type Required Description taskId string Yes Task ID to set active updatedBy string Yes Your name Returns Success confirmation with list of auto-paused task IDs and titles. Example set_task_active(taskId=\"c0ce8037\", updatedBy=\"Alice\")"},{"id":"","t":"get_task_detail","x":"Get full task detail including checklist with notes history, continuation notes, plan, and summary. Shows checklist progress breakdown (done/coding/testing/pending counts). Parameters Name Type Required Description taskId string Yes Task ID Returns Formatted task detail with checklist summary, individual item statuses, notes history, plan, and continuation notes. Example get_task_detail(taskId=\"c0ce8037\")"},{"id":"","t":"update_task_checklist","x":"Transition a checklist item to a new status with mandatory notes. Enforces state machine: pending → coding → testing → done (cycling allowed between coding and testing ). Notes required for coding→testing , testing→coding , and testing→done transitions. Parameters Name Type Required Description taskId string Yes Task ID itemIndex number Yes Zero-based index of the checklist item newStatus string Yes New status: coding , testing , or done notes string Yes Transition notes (what was done or what needs fixing) updatedBy string Yes Your name Returns Item name, previous/new status, cycle count, and whether escalation was triggered (at 3 cycles). Example update_task_checklist( taskId=\"c0ce8037\", itemIndex=0, newStatus=\"testing\", notes=\"Implemented database schema and CRUD operations\", updatedBy=\"Alice\" )"},{"id":"","t":"update_checklist","x":"Replace all checklist items on a task. Use this to set up or edit the checklist items (not for transitioning status -- use update_task_checklist for that). Parameters Name Type Required Description taskId string Yes Task ID checklistJson string Yes JSON array of checklist items Returns Success confirmation. Example update_checklist( taskId=\"c0ce8037\", checklistJson='[{\"item\":\"Setup database\",\"status\":\"pending\",\"notes\":[]},{\"item\":\"Create API\",\"status\":\"pending\",\"notes\":[]}]' )"},{"id":"","t":"append_checklist_items","x":"Append items to a task's existing checklist without replacing it. Use this to add new items (e.g. to Pending) -- unlike update_checklist (full replace), you do not need to fetch and resend the existing list (no risk of mangling existing items when rebuilding them). New items default to status pending . The server is authoritative: it validates the status, ignores any caller-supplied notes/assignedTo/cycleCount, and serializes the write so a concurrent append/transition won't clobber it. Parameters Name Type Required Description taskId string Yes Task ID itemsJson string Yes JSON array of items to append. Each element may be a plain description string or an {item,status?} object. Returns Success confirmation with the number of items appended. Example append_checklist_items( taskId=\"c0ce8037\", itemsJson='[\"Add validation\",\"Write tests\"]' )"},{"id":"","t":"assign_checklist_item","x":"Assign a checklist item to a specific team agent. Set assignee to null to unassign. Parameters Name Type Required Description taskId string Yes Task ID itemIndex number Yes Zero-based index of the checklist item assignee string No Name of the agent to assign to, or null to unassign Returns Success confirmation. Example assign_checklist_item(taskId=\"c0ce8037\", itemIndex=2, assignee=\"Bob\")"},{"id":"","t":"update_task_plan","x":"Set or update the implementation plan for a task (markdown formatted). Parameters Name Type Required Description taskId string Yes Task ID plan string Yes Implementation plan (markdown) updatedBy string Yes Your name Returns Success confirmation. Example update_task_plan( taskId=\"c0ce8037\", plan=\"## Phase 1\\n- Create migrations\\n\\n## Phase 2\\n- Add endpoints\", updatedBy=\"Alice\" )"},{"id":"","t":"update_task_summary","x":"Update a task's implementation summary and/or test results (markdown formatted). Parameters Name Type Required Description taskId string Yes Task ID implementationSummary string No What was built/changed (markdown). Pass null to leave unchanged. testResults string No Test outcomes and verification (markdown). Pass null to leave unchanged. updatedBy string Yes Your name Returns Success confirmation. Example update_task_summary( taskId=\"c0ce8037\", implementationSummary=\"Added ThemeService with dark/light toggle\", testResults=\"All 12 unit tests passing\", updatedBy=\"Alice\" )"},{"id":"","t":"update_task_continuation","x":"Write continuation notes for session handoff. Describes where to pick up: current file, checklist progress, what's next, any blockers. Parameters Name Type Required Description taskId string Yes Task ID continuationNotes string Yes Continuation context for next session updatedBy string Yes Your name Returns Success confirmation. Example update_task_continuation( taskId=\"c0ce8037\", continuationNotes=\"Working on item 3 (API validation). Next: add input sanitization for title field.\", updatedBy=\"Alice\" )"},{"id":"","t":"get_checklist_item_images","x":"Get images attached to a checklist item. Returns base64-encoded image data that agents can visually analyze for context (e.g., screenshots of bugs, UI mockups, test results). Parameters Name Type Required Description taskId string Yes Task ID itemIndex number Yes Zero-based checklist item index Returns Array of base64-encoded images with MIME type and filename, or a message if no images are attached. Example get_checklist_item_images(taskId=\"c0ce8037\", itemIndex=0)"},{"id":"","t":"get_my_active_task","x":"Get YOUR active in-progress task (filtered by your agent name). Returns full task detail with checklist summary. Use this instead of list_tasks when you just need your current active task. Parameters Name Type Required Description agentName string Yes Your terminal/agent name (from MULTITERMINAL_NAME env var) Returns Full task detail with checklist summary, or a message if no active task exists. Example get_my_active_task(agentName=\"Alice\")"},{"id":"","t":"get_my_pickable_tasks","x":"Get tasks you can work on: your assigned in-progress tasks + unassigned todo tasks available to claim. Returns a compact formatted list. Use this instead of list_tasks when browsing for work. Parameters Name Type Required Description agentName string Yes Your terminal/agent name (from MULTITERMINAL_NAME env var) Returns Compact list of pickable tasks with ID, title, status, priority, and your relationship to each (assigned, helper, or available). Example get_my_pickable_tasks(agentName=\"Alice\")"},{"id":"task-relationships","t":"Task Relationships","x":""},{"id":"","t":"add_task_relationship","x":"Add a blocking/dependency relationship between two tasks. Types: blocks (A blocks B), depends_on (A depends on B), related_to (informational). Automatically creates the inverse relationship. Parameters Name Type Required Description sourceTaskId string Yes Source task ID (the task you're adding a relationship FROM) targetTaskId string Yes Target task ID (the task you're adding a relationship TO) type string Yes Relationship type: blocks , depends_on , related_to createdBy string Yes Your name Returns Success confirmation. Example add_task_relationship(sourceTaskId=\"c0ce8037\", targetTaskId=\"d4e5f6a7\", type=\"blocks\", createdBy=\"Alice\")"},{"id":"","t":"remove_task_relationship","x":"Remove a relationship between two tasks (removes both directions). Parameters Name Type Required Description sourceTaskId string Yes One of the two related task IDs targetTaskId string Yes The other related task ID Returns Success confirmation. Example remove_task_relationship(sourceTaskId=\"c0ce8037\", targetTaskId=\"d4e5f6a7\")"},{"id":"","t":"get_task_relationships","x":"Get all relationships for a task (blocks, depends_on, related_to). Parameters Name Type Required Description taskId string Yes Task ID to get relationships for Returns List of relationships with source/target task IDs, type, and creator. Example get_task_relationships(taskId=\"c0ce8037\")"},{"id":"task-files","t":"Task File Links","x":""},{"id":"","t":"link_task_file","x":"Link a file to a task so agents know which files are relevant. Supports optional line ranges and descriptions. Parameters Name Type Required Description taskId string Yes Task ID to link file to filePath string Yes Absolute file path addedBy string Yes Your name description string No Why this file is relevant lineStart number No Start line number lineEnd number No End line number Returns Success confirmation with file count. Example link_task_file( taskId=\"c0ce8037\", filePath=\"H:\\\\DevLaptop\\\\...\\\\TaskDatabase.cs\", addedBy=\"Alice\", description=\"Core persistence layer being modified\", lineStart=100, lineEnd=250 )"},{"id":"","t":"unlink_task_file","x":"Remove a file link from a task. Parameters Name Type Required Description taskId string Yes Task ID filePath string Yes File path to unlink Returns Success confirmation. Example unlink_task_file(taskId=\"c0ce8037\", filePath=\"H:\\\\DevLaptop\\\\...\\\\TaskDatabase.cs\")"},{"id":"","t":"get_task_files","x":"Get all files linked to a task. Parameters Name Type Required Description taskId string Yes Task ID Returns List of linked files with paths, descriptions, line ranges, and who linked them. Example get_task_files(taskId=\"c0ce8037\")"},{"id":"task-reports","t":"Task Reports","x":""},{"id":"","t":"save_task_report","x":"Save an agent report (HTML/markdown) linked to a kanban task. Use after generating a specialist agent report (verifier, code-reviewer, security-auditor) to persist it for future reference. Parameters Name Type Required Description taskId string Yes Kanban task ID this report belongs to agentName string Yes Agent that generated the report (e.g. verifier, code-reviewer) reportContent string Yes Full report content (HTML or markdown) reportType string No Report format: html or markdown . Default: html verdict string No Report verdict (e.g. PASS, FAIL, PASS WITH NOTES) score number No Numeric score 0-100 invocationId string No Agent invocation ID (links to agent_invocations table) createdBy string No Who saved the report Returns Success confirmation with report ID. Example save_task_report( taskId=\"c0ce8037\", agentName=\"verifier\", reportContent=\"<h1>Verification Report</h1><p>All checks passed.</p>\", verdict=\"PASS\", score=95 )"},{"id":"","t":"get_task_reports","x":"List reports saved for a kanban task. Returns metadata (no content) -- use the reportId with the REST API to fetch full content. Parameters Name Type Required Description taskId string Yes Kanban task ID agentName string No Filter by agent name limit number No Max reports to return. Default: 50 Returns List of report metadata with IDs, agent names, verdicts, scores, and timestamps. Example get_task_reports(taskId=\"c0ce8037\", agentName=\"verifier\")"},{"id":"messaging","t":"Messaging","x":""},{"id":"","t":"list_terminals","x":"List all active terminals (teammates) connected to MultiTerminal. Parameters None. Returns Formatted list of terminals with name, ID prefix, and last active time. Example list_terminals()"},{"id":"","t":"register_terminal","x":"Register your terminal with MultiTerminal to send/receive messages. Parameters Name Type Required Description name string Yes Your terminal name docId string Yes Unique document ID for this terminal Returns Terminal ID for use in subsequent messaging calls. Example register_terminal(name=\"Alice\", docId=\"session-abc123\")"},{"id":"","t":"send_message","x":"Send a message to another terminal. Parameters Name Type Required Description fromTerminalId string Yes Your terminal ID to string Yes Recipient terminal name message string Yes Message content Returns Delivery confirmation with sender and recipient names. Example send_message(fromTerminalId=\"a1b2c3d4\", to=\"Bob\", message=\"Can you review my PR?\")"},{"id":"","t":"broadcast_message","x":"Broadcast a message to all terminals. Parameters Name Type Required Description fromTerminalId string Yes Your terminal ID message string Yes Message content Returns Delivery confirmation with recipient count. Example broadcast_message(fromTerminalId=\"a1b2c3d4\", message=\"Build is ready for testing!\")"},{"id":"","t":"get_messages","x":"Get messages for your terminal. Messages are consumed on read. Parameters Name Type Required Description terminalId string Yes Your terminal ID Returns Formatted list of messages with sender, content, and timestamp. Example get_messages(terminalId=\"a1b2c3d4\")"},{"id":"","t":"get_inbox","x":"Get inbox messages for a user. Shows notifications for items ready for testing, escalations, task completions, and helper requests. Parameters Name Type Required Description userId string Yes User ID to get inbox for (e.g., the owner's first name) unreadOnly boolean No Only show unread messages. Default: false limit number No Max messages to return. Default: 50 Returns Formatted inbox with message type, summary, task context, and read/reply status. Example get_inbox(userId=\"Owner\", unreadOnly=true)"},{"id":"","t":"mark_inbox_read","x":"Mark an inbox message as read, or mark all messages as read for a user. Parameters Name Type Required Description messageId string No Specific message ID to mark as read userId string No Mark ALL messages as read for this user Returns Success confirmation. Example mark_inbox_read(messageId=\"abc12345\") mark_inbox_read(userId=\"Owner\")"},{"id":"","t":"reply_to_inbox","x":"Reply to an inbox message with notes or feedback. Parameters Name Type Required Description messageId string Yes Inbox message ID to reply to replyText string Yes Your reply text Returns Success confirmation. Example reply_to_inbox(messageId=\"abc12345\", replyText=\"Looks good, marking as done\")"},{"id":"team","t":"Team & Helpers","x":""},{"id":"","t":"get_team_roster","x":"Get the team roster for a project with merged profile data (preferred_model, agent_instructions, role, skills). Use this to discover which agents to spawn for a team assembly workflow. Parameters Name Type Required Description projectPath string Yes Absolute path to the project directory Returns Project name and array of agents with name, model, role, skills, and online status. Example get_team_roster(projectPath=\"H:\\\\DevLaptop\\\\ClarionPowerShell\\\\MultiTerminal\")"},{"id":"","t":"add_helper","x":"Add a helper to a kanban task. Helpers assist with the task without being the primary assignee. Parameters Name Type Required Description taskId string Yes Task ID to add helper to helper string Yes Name of the helper to add addedBy string Yes Your name Returns Success confirmation with helper count. Example add_helper(taskId=\"c0ce8037\", helper=\"Bob\", addedBy=\"Alice\")"},{"id":"","t":"remove_helper","x":"Remove a helper from a kanban task. Parameters Name Type Required Description taskId string Yes Task ID to remove helper from helperName string Yes Name of the helper to remove Returns Success confirmation with remaining helper count. Example remove_helper(taskId=\"c0ce8037\", helperName=\"Bob\")"},{"id":"","t":"get_owner_profile","x":"Get the owner's profile (git identity, GitHub username, token status). Use when you need git user.name/email for commits or GitHub username for repo operations. Parameters None. Returns Owner profile with fullName, email, gitHubUsername, hasGitHubToken, and timestamps. Example get_owner_profile()"},{"id":"projects","t":"Projects","x":""},{"id":"","t":"list_projects","x":"List all registered projects with summary info (name, path, type, version, lead). Parameters None. Returns Formatted list of projects with key metadata. Example list_projects()"},{"id":"","t":"get_project","x":"Get a project with all associations (agents, MCP servers, specialists, paths, prompts, skills). Returns the full project context. Parameters Name Type Required Description projectId string Yes Project ID (GUID). Use list_projects to find IDs. Returns Full project context including all 7 association tables. Example get_project(projectId=\"proj-123-456\")"},{"id":"","t":"update_project","x":"Update one or more project fields. Parameters Name Type Required Description projectId string Yes Project ID fields object Yes Object of field names to values. Accepted keys: deployPath , buildCommand , projectType , description , icon , iconColor , teamLead , gitRepoUrl , gitDefaultBranch , gitAutoCommit , currentVersion , isPinned Returns Success confirmation. Example update_project( projectId=\"proj-123\", fields={\"deployPath\": \"C:\\\\Deploy\", \"buildCommand\": \"dotnet build\"} )"},{"id":"","t":"add_project_agent","x":"Add or update an agent assignment on a project. Parameters Name Type Required Description projectId string Yes Project ID agentName string Yes Agent name (e.g., \"Alice\", \"Bob\") role string No Agent role (e.g., \"backend\", \"frontend\", \"fullstack\") preferredModel string No Preferred Claude model: opus , sonnet , haiku Returns Success confirmation. Example add_project_agent(projectId=\"proj-123\", agentName=\"Alice\", role=\"backend\", preferredModel=\"sonnet\")"},{"id":"","t":"remove_project_agent","x":"Remove an agent from a project. Parameters Name Type Required Description projectId string Yes Project ID agentName string Yes Agent name to remove Returns Success confirmation. Example remove_project_agent(projectId=\"proj-123\", agentName=\"Alice\")"},{"id":"","t":"add_project_association","x":"Add an association to a project. Type determines what to add: mcp_server , specialist , path , prompt , or skill . Each type requires different fields. Parameters Name Type Required Description projectId string Yes Project ID type string Yes Association type: mcp_server , specialist , path , prompt , skill serverName string * (mcp_server) MCP server name isEnabled boolean No (mcp_server, specialist, skill) Whether enabled. Default: true agentType string * (specialist) Agent type, e.g., \"devils-advocate\", \"verifier\" customPrompt string No (specialist) Optional override prompt pathType string * (path) Category: source, deploy, build_output, docs, etc. pathValue string * (path) Filesystem path value description string No (path) Optional description promptType string * (prompt) Category: system, user, context, workflow promptText string * (prompt) Prompt text content displayOrder number No (prompt) Sort order. Default: 0 skillName string * (skill) Skill name * Required based on the type selected. Returns Success confirmation. Example // Add an MCP server add_project_association(projectId=\"proj-123\", type=\"mcp_server\", serverName=\"sqlite-mcp\") // Add a specialist agent add_project_association(projectId=\"proj-123\", type=\"specialist\", agentType=\"verifier\") // Add a path add_project_association(projectId=\"proj-123\", type=\"path\", pathType=\"deploy\", pathValue=\"C:\\\\Deploy\", description=\"P"},{"id":"","t":"remove_project_association","x":"Remove an association from a project. Type determines what to remove. Each type uses a different identifier. Parameters Name Type Required Description projectId string Yes Project ID type string Yes Association type: mcp_server , specialist , path , prompt , skill serverName string * (mcp_server) Server name to remove agentType string * (specialist) Agent type to remove pathId number * (path) Path ID to remove (from get_project response) promptId number * (prompt) Prompt ID to remove (from get_project response) skillName string * (skill) Skill name to remove * Required based on the type selected. Returns Success confirmation. Example remove_project_association(projectId=\"proj-123\", type=\"mcp_server\", serverName=\"sqlite-mcp\")"},{"id":"knowledge","t":"Knowledge Base","x":""},{"id":"","t":"query_knowledge","x":"Search the institutional knowledge base for decisions, patterns, gotchas, and anti-patterns. Uses FTS5 full-text search. Parameters Name Type Required Description query string Yes Search text category string No Filter: decision , pattern , gotcha , anti_pattern , debug_insight , preference projectId string No Filter by project ID tags string No Comma-separated tags to filter by limit number No Max results. Default: 20 Returns Formatted list of matching knowledge entries with title, content, category, tags, and confidence. Example query_knowledge(query=\"SQL injection\", category=\"gotcha\", limit=10)"},{"id":"","t":"add_knowledge","x":"Add a knowledge entry to institutional memory. Parameters Name Type Required Description title string Yes Short title summarizing the entry content string Yes Full content of the knowledge entry category string Yes decision , pattern , gotcha , anti_pattern , debug_insight , preference projectId string No Project ID (null for global) sourceType string No How discovered: manual , session , debug , review . Default: manual sourceId string No Reference ID of source (session ID, task ID) tags string No Comma-separated tags confidence string No confirmed , likely , uncertain . Default: confirmed Returns Success confirmation with entry ID. Example add_knowledge( title=\"Always escape single quotes in PowerShell\", content=\"Use Replace(\\\"'\\\", \\\"''\\\") before interpolating values into PowerShell commands to prevent injection.\", category=\"gotcha\", tags=\"security,powershell,injection\", confidence=\"confirmed\" )"},{"id":"","t":"get_code_digest","x":"Get pre-analyzed summary of a source file. Returns null if no digest exists or if the digest is stale. Parameters Name Type Required Description filePath string Yes Absolute path to the source file projectId string No Project ID includeStale boolean No Return stale digests too. Default: false Returns File digest with purpose, key classes, key methods, patterns, gotchas, dependencies, and line count. Example get_code_digest(filePath=\"H:\\\\DevLaptop\\\\...\\\\MessageBroker.cs\")"},{"id":"","t":"save_code_digest","x":"Save or update a code digest for a source file. Parameters Name Type Required Description projectId string Yes Project ID this file belongs to filePath string Yes Absolute path to the source file fileHash string Yes SHA256 hash for staleness detection purpose string No One-sentence description of what this file does keyClasses string No JSON array of key class names keyMethods string No JSON array of key method/function names patterns string No Notable patterns used gotchas string No Gotchas and pitfalls dependencies string No JSON array of key dependencies lineCount number No Number of lines in the file digestModel string No Model used to generate digest. Default: haiku Returns Success confirmation with digest ID. Example save_code_digest( projectId=\"proj-123\", filePath=\"H:\\\\DevLaptop\\\\...\\\\MessageBroker.cs\", fileHash=\"abc123def456\", purpose=\"Central hub routing all messages between terminals\", keyClasses='[\"MessageBroker\"]', keyMethods='[\"SendMessage\",\"RegisterTerminal\",\"CreateTask\"]', lineCount=4254 )"},{"id":"sessions","t":"Sessions","x":""},{"id":"","t":"import_session","x":"Import a Claude Code session JSONL transcript file and link it to a kanban task. Extracts all messages, stores them in SQLite with FTS5 full-text search indexing, and creates a lineage record. Parameters Name Type Required Description sessionFilePath string Yes Absolute path to the Claude Code session JSONL file taskId string Yes Kanban task ID this session belongs to agentName string Yes Name of the agent who ran this session parentSessionId string No Parent session ID for chaining agent cycles sessionType string No Semantic label: coding , review , testing Returns Session ID and message count. Example import_session( sessionFilePath=\"C:\\\\Users\\\\<username>\\\\.claude\\\\projects\\\\...\\\\abc123.jsonl\", taskId=\"c0ce8037\", agentName=\"Alice\", sessionType=\"coding\" )"},{"id":"","t":"get_task_sessions","x":"Get all imported session lineage records for a kanban task. Returns session metadata including agent, type, timestamps, and parent chain links. Parameters Name Type Required Description taskId string Yes Kanban task ID Returns List of session records with metadata. Example get_task_sessions(taskId=\"c0ce8037\")"},{"id":"","t":"get_session_lineage","x":"Get the full lineage chain for a session, ordered from root to leaf. Walks the parent_session_id chain to reconstruct the full history of agent cycling. Parameters Name Type Required Description sessionId string Yes Session ID to retrieve the lineage chain for Returns Ordered chain of session records from root to leaf. Example get_session_lineage(sessionId=\"def456\")"},{"id":"","t":"sync_sessions","x":"Incrementally sync Claude Code session JSONL files from disk to SQLite. Scans a Claude project folder for unimported sessions and imports them. Skips already-imported sessions. Parameters Name Type Required Description claudeProjectPath string Yes Absolute path to the Claude project folder agentName string No Default agent name. Default: Unknown taskId string No Task ID for unlinked sessions. Default: __unlinked__ Returns Import summary: imported, skipped, failed, total counts. Example sync_sessions( claudeProjectPath=\"C:\\\\Users\\\\<username>\\\\.claude\\\\projects\\\\H--DevLaptop-...\", agentName=\"Alice\", taskId=\"c0ce8037\" )"},{"id":"","t":"search_session_history","x":"Full-text search across imported session messages. Uses SQLite FTS5 when available, falls back to LIKE search. Parameters Name Type Required Description taskId string No* Kanban task ID to search within query string No* Search text to find role string No Filter: user or assistant agentName string No Filter by agent name limit number No Max results. Default: 50 * At least one of taskId or query required. Returns Matching session messages with context. Example search_session_history(taskId=\"c0ce8037\", query=\"FTS5\", role=\"assistant\")"},{"id":"","t":"search_session_memory","x":"Semantic (hybrid FTS5 + vector-similarity) search over session transcript chunks. Finds context by meaning rather than exact keywords -- ask a natural-language question. Use this when you remember the idea but not the wording; use search_session_history when you remember the words. Parameters Name Type Required Description query string Yes Natural-language search text projectPath string No Limit results to a project path topK number No Max results to return (1-100). Default: 10 agentName string No Filter by agent name Returns Ranked transcript chunks with session ID, terminal name, project path, chunk text, and relevance score. Example search_session_memory(query=\"what was the WebView2 event bridge approach?\", topK=5)"},{"id":"","t":"get_latest_session","x":"Get the most recent session for a project, including cached summary and recent messages if no summary exists. Use at session start to get context from the previous session. Parameters Name Type Required Description projectPath string Yes Filesystem path to the project agentName string No Filter by agent name (e.g. \"Alice\"). Returns the most recent session for this specific agent. Returns Session metadata, cached summary, and optionally recent messages for lazy summary generation. Example // Get latest session across all agents get_latest_session(projectPath=\"H:\\\\DevLaptop\\\\ClarionPowerShell\\\\MultiTerminal\") // Get latest session for a specific agent get_latest_session(projectPath=\"H:\\\\DevLaptop\\\\ClarionPowerShell\\\\MultiTerminal\", agentName=\"Alice\")"},{"id":"","t":"update_session_summary","x":"Save a generated summary for a session. Called after an agent generates a recap of a previous session's work. Parameters Name Type Required Description sessionId string Yes Session ID to update summary string Yes Generated summary text Returns Success confirmation. Example update_session_summary( sessionId=\"def456\", summary=\"Implemented knowledge base with FTS5 search and code digest system\" )"},{"id":"","t":"get_unsummarized_sessions","x":"Get sessions that have no cached summary for a project. Used at session start to batch-generate missing summaries. Parameters Name Type Required Description projectPath string Yes Filesystem path to the project limit number No Max sessions to return. Default: 10 Returns List of sessions without summaries, with session IDs, agent names, and timestamps. Example get_unsummarized_sessions(projectPath=\"H:\\\\DevLaptop\\\\ClarionPowerShell\\\\MultiTerminal\", limit=5)"},{"id":"context","t":"Context Self-Management","x":"Tools that let an agent see and manage its own context window. When context crosses a threshold (default 70%), the context-threshold-hook injects an advisory nudge; the agent then writes continuation notes and clears at a clean point of its own choosing. /clear is recoverable — the SessionStart( source=clear ) flow rebuilds the agent from its continuation notes + session summary."},{"id":"","t":"check_my_context","x":"Check YOUR terminal's live context-window fill (plus rate-limit quota and token usage). Returns contextPct 0–100 — the signal for whether it's a good time to wrap up and clear. Reads the same statusline stats the HUD status bar shows. Parameters Name Type Required Description agentName string No Your terminal/agent name. Omit to use $MULTITERMINAL_NAME . docId string No Terminal docId. Omit to use $MULTITERMINAL_DOC_ID , or the newest stats file for the name. Returns Context percentage with a recommendation (wrap-up vs headroom, relative to MULTITERMINAL_CONTEXT_THRESHOLD , default 70), plus 5h/7d quota, token total/cost, and staleness. Returns \"not reporting\" if the terminal hasn't written stats yet. Example check_my_context(agentName=\"Alice\")"},{"id":"","t":"clear_my_context","x":"Clear YOUR OWN context by submitting /clear into your terminal (types /clear + Enter). ⚠️ This wipes the conversation. Write continuation notes first ( update_task_continuation ) — SessionStart then rebuilds you from those notes + the session summary. Call it only at a clean continuation point you chose, and as the last action of your turn. Parameters Name Type Required Description agentName string No Your terminal/agent name. Omit to use $MULTITERMINAL_NAME . acknowledge boolean No Two-step guard. Without it, the tool returns a notes-first reminder instead of clearing. Set true to actually clear. Returns A reminder (first call) or a confirmation that /clear was submitted (with acknowledge=true ). Example // 1. write notes, then: clear_my_context(agentName=\"Alice\", acknowledge=true)"},{"id":"browser","t":"Browser Tabs","x":"Per-terminal tabbed browser (WebView2) in the HUD area. Agents can open tabs with URLs or raw HTML, execute JavaScript, read DOM elements, exchange messages bidirectionally with the page, and capture screenshots. Enables interactive dashboards, live previews, mini-apps, and visual debugging."},{"id":"","t":"open_browser_tab","x":"Open a new browser tab in your terminal's HUD area. Provide either a URL to navigate to, or raw HTML content to display. Parameters Name Type Required Description terminalId string Yes Your terminal ID or name (from register_terminal) title string Yes Tab title displayed in the tab strip url string No URL to navigate to (optional if content provided) content string No Raw HTML content to display (optional if url provided) Returns Tab ID string used to reference this tab in subsequent calls. Example // Open a tab with raw HTML open_browser_tab(terminalId=\"Alice\", title=\"Dashboard\", content=\"<h1>Hello</h1>\") // Open a tab with a URL open_browser_tab(terminalId=\"Alice\", title=\"Docs\", url=\"file:///H:/docs/index.html\")"},{"id":"","t":"set_browser_content","x":"Update an existing browser tab's content, URL, or title. Parameters Name Type Required Description terminalId string Yes Your terminal ID or name tabId string Yes Tab ID returned from open_browser_tab url string No New URL to navigate to content string No New HTML content to display title string No New tab title Returns Confirmation message. Example set_browser_content(terminalId=\"Alice\", tabId=\"abc123\", content=\"<h1>Updated</h1>\")"},{"id":"","t":"close_browser_tab","x":"Close a browser tab in your terminal. Parameters Name Type Required Description terminalId string Yes Your terminal ID or name tabId string Yes Tab ID to close Returns Confirmation message. Example close_browser_tab(terminalId=\"Alice\", tabId=\"abc123\")"},{"id":"","t":"execute_browser_script","x":"Execute JavaScript in a browser tab and return the result. Use this to interact with page content, click buttons, read values, modify the DOM, or run any client-side code. Parameters Name Type Required Description terminalId string Yes Your terminal ID or name tabId string Yes Tab ID returned from open_browser_tab script string Yes JavaScript code to execute. The return value of the last expression is returned as the result. Returns The return value of the executed script (serialized as a string). Example // Read a value from the page execute_browser_script(terminalId=\"Alice\", tabId=\"abc123\", script=\"document.getElementById('status').textContent\") // Modify the page execute_browser_script(terminalId=\"Alice\", tabId=\"abc123\", script=\"document.body.style.background = '#1e1e2e'\")"},{"id":"","t":"get_browser_console_logs","x":"Get console log messages (log, warn, error, info) from a browser tab. Useful for debugging JavaScript in pages you've loaded. Parameters Name Type Required Description terminalId string Yes Your terminal ID or name tabId string Yes Tab ID returned from open_browser_tab limit number No Maximum number of log entries to return (most recent first). Default: all. Returns Array of console log entries with level, message, and timestamp. Example get_browser_console_logs(terminalId=\"Alice\", tabId=\"abc123\", limit=10)"},{"id":"","t":"get_browser_element_content","x":"Read the content of a DOM element by CSS selector. Returns text content, innerHTML, or other properties. Parameters Name Type Required Description terminalId string Yes Your terminal ID or name tabId string Yes Tab ID returned from open_browser_tab selector string Yes CSS selector (e.g., #myId , .myClass , div.content > p:first-child ) property string No Element property to read: textContent (default), innerHTML , outerHTML , value , className , id , or any attribute name Returns The requested property value of the matched element. Example // Read text of a heading get_browser_element_content(terminalId=\"Alice\", tabId=\"abc123\", selector=\"h1\") // Read innerHTML of a container get_browser_element_content(terminalId=\"Alice\", tabId=\"abc123\", selector=\"#results\", property=\"innerHTML\")"},{"id":"","t":"post_browser_message","x":"Send a JSON message to a browser tab's page. The page receives it via window.chrome.webview.addEventListener('message', e => { /* e.data */ }) . Use for bidirectional communication between agent and page JavaScript. Parameters Name Type Required Description terminalId string Yes Your terminal ID or name tabId string Yes Tab ID returned from open_browser_tab data object Yes JSON data to send to the page. Available as e.data in the message event handler. Returns Confirmation message. Example // Send a command to the page post_browser_message(terminalId=\"Alice\", tabId=\"abc123\", data={\"type\": \"update\", \"cpu\": 47, \"status\": \"running\"}) // Page receives it: // window.chrome.webview.addEventListener('message', e => { // console.log(e.data.type); // \"update\" // console.log(e.data.cpu); // 47 // });"},{"id":"","t":"get_browser_messages","x":"Get messages sent from a browser tab's page via window.chrome.webview.postMessage() . Pages use this to send data back to the agent. Returns buffered messages with timestamps. Parameters Name Type Required Description terminalId string Yes Your terminal ID or name tabId string Yes Tab ID returned from open_browser_tab limit number No Maximum number of messages to return (most recent). Default: all. Returns Array of messages sent from the page, each with data and timestamp. Example // Page sends: window.chrome.webview.postMessage({type: \"click\", id: \"btn1\"}) // Agent reads: get_browser_messages(terminalId=\"Alice\", tabId=\"abc123\")"},{"id":"","t":"capture_browser_screenshot","x":"Capture a PNG screenshot of a browser tab's content. Returns base64-encoded image data. Parameters Name Type Required Description terminalId string Yes Your terminal ID or name tabId string Yes Tab ID returned from open_browser_tab Returns Base64-encoded PNG image data of the tab's visible content. Example capture_browser_screenshot(terminalId=\"Alice\", tabId=\"abc123\")"},{"id":"","t":"list_webmcp_tools","x":"List WebMCP tools registered by a page in a browser tab. Pages use navigator.modelContext.registerTool() to expose structured tools. Returns tool names, descriptions, and input schemas. Use this before invoke_webmcp_tool to see what's available. Parameters Name Type Required Description terminalId string Yes Your terminal ID or name tabId string Yes Tab ID returned from open_browser_tab Returns Array of registered tool definitions with names, descriptions, and input schemas. Example list_webmcp_tools(terminalId=\"Alice\", tabId=\"abc123\")"},{"id":"","t":"invoke_webmcp_tool","x":"Invoke a WebMCP tool registered by a page in a browser tab. The page must have registered the tool via navigator.modelContext.registerTool() . Use list_webmcp_tools first to discover available tools and their input schemas. Parameters Name Type Required Description terminalId string Yes Your terminal ID or name tabId string Yes Tab ID returned from open_browser_tab toolName string Yes Name of the WebMCP tool to invoke (from list_webmcp_tools) input object No Input parameters for the tool, matching the tool's inputSchema Returns The tool's return value as defined by the page. Example invoke_webmcp_tool( terminalId=\"Alice\", tabId=\"abc123\", toolName=\"search_results\", input={\"query\": \"SQL injection\", \"limit\": 10} )"},{"id":"build","t":"Build & Run","x":"Windows build tools integrated from the Windows Build Runner. Auto-detect and build projects, run commands, batch files, and PowerShell scripts."},{"id":"","t":"build_project","x":"Auto-detect and build a project (.sln, .csproj, .vbproj, etc.). Locates MSBuild or dotnet automatically. Parameters Name Type Required Description projectPath string Yes Path to project file or directory containing the project configuration string No Build configuration. Default: Release platform string No Platform to build for. Default: Any CPU additionalArgs string No Additional MSBuild/dotnet arguments processToKill string No Name of process to terminate before build copyOutputTo string No Destination path to copy build output to after success timeout number No Timeout in ms. Default: 600000 (10 min) Returns Build output with stdout, stderr, exit code, and build tool used. Example build_project( projectPath=\"H:\\\\DevLaptop\\\\ClarionPowerShell\\\\MultiTerminal\", configuration=\"Release\", processToKill=\"MultiTerminal\" )"},{"id":"","t":"find_build_tools","x":"Find installed build tools (MSBuild, dotnet, etc.). Parameters Name Type Required Description tool string No Specific tool to find: msbuild , dotnet , all . Default: all Returns List of found build tools with paths and versions. Example find_build_tools(tool=\"msbuild\")"},{"id":"","t":"run_command","x":"Execute a Windows command directly and return its output. Parameters Name Type Required Description command string Yes Windows command to execute workingDirectory string No Working directory for execution timeout number No Timeout in ms. Default: 300000 (5 min) processToKill string No Process to terminate before execution copyOutputTo string No Copy output to this path after success Returns Command output with stdout, stderr, and exit code. Example run_command(command=\"dir /b *.cs\", workingDirectory=\"H:\\\\DevLaptop\\\\MyProject\")"},{"id":"","t":"run_batch_file","x":"Execute a Windows batch file and return its output. Parameters Name Type Required Description batchFile string Yes Path to the batch file to execute workingDirectory string No Working directory for execution timeout number No Timeout in ms. Default: 300000 (5 min) processToKill string No Process to terminate before execution copyOutputTo string No Copy output to this path after success Returns Batch file output with stdout, stderr, and exit code. Example run_batch_file(batchFile=\"H:\\\\DevLaptop\\\\build.bat\", workingDirectory=\"H:\\\\DevLaptop\\\\MyProject\")"},{"id":"","t":"run_powershell_script","x":"Execute a PowerShell script and return its output. Parameters Name Type Required Description scriptFile string Yes Path to the PowerShell script to execute workingDirectory string No Working directory for execution timeout number No Timeout in ms. Default: 300000 (5 min) processToKill string No Process to terminate before execution copyOutputTo string No Copy output to this path after success Returns Script output with stdout, stderr, and exit code. Example run_powershell_script(scriptFile=\"H:\\\\DevLaptop\\\\deploy.ps1\")"},{"id":"xaml-tools","t":"XAML","x":""},{"id":"","t":"render_xaml","x":"Render a WPF XAML snippet to a PNG image and return it as base64. Use this to preview XAML UI layouts, dialogs, and controls without launching the app. The XAML must have a root element (e.g. Border, Grid, StackPanel) with xmlns declarations. Parameters Name Type Required Description xaml string Yes WPF XAML markup (must include xmlns declarations) width number No Render width in pixels. Default: 520 height number No Render height in pixels. Default: 400 Returns Base64-encoded PNG image of the rendered XAML. Example render_xaml( xaml=\"<Border xmlns='http://schemas.microsoft.com/winfx/2006/xaml/presentation' Background='#1e1e2e'><TextBlock Text='Hello' Foreground='White'/></Border>\", width=520, height=400 )"},{"id":"debug","t":"Debug","x":""},{"id":"","t":"debug_logs","x":"Read debug log entries from MultiTerminal with filtering. Use to check system behavior, trace message delivery, monitor services. Parameters Name Type Required Description count number No Number of entries. Default: 50 , max: 500 offset number No Skip entries for pagination. Default: 0 source string No Filter by component (e.g., \"InboxMonitor\", \"MessageBroker\") level string No Filter: Trace , Info , Warning , Error search string No Text search within messages (case-insensitive) Returns Formatted log entries with timestamp, source, level, and message. Example debug_logs(count=20, source=\"InboxMonitor\", level=\"Info\")"},{"id":"","t":"debug_clear","x":"Clear all debug log entries. Parameters None. Returns Confirmation with previous entry count. Example debug_clear()"},{"id":"","t":"debug_pause","x":"Pause debug logging. New entries will be silently discarded until resumed. Parameters None. Returns Confirmation of paused state. Example debug_pause()"},{"id":"","t":"debug_resume","x":"Resume debug logging after a pause. Parameters None. Returns Confirmation of resumed state. Example debug_resume()"},{"id":"","t":"debug_status","x":"Get debug log status: entry count, paused state, max capacity. Parameters None. Returns Status object with count, isPaused, and maxCapacity. Example debug_status()"},{"id":"","t":"debug_log_files","x":"List all available debug log files from previous sessions, most recent first. Each session creates a timestamped log file that persists across restarts. Parameters None. Returns List of log file paths with timestamps and sizes. Example debug_log_files()"},{"id":"search","t":"Code Search","x":"Fast code and file search powered by ripgrep (bundled as tools/rg.exe ). Provides regex search across codebases with structured results."},{"id":"","t":"search_code","x":"Search file contents using ripgrep. Returns matching lines with file paths and line numbers. Supports regex patterns, glob filtering, file type filtering, context lines, and more. Parameters Name Type Required Description pattern string Yes Regex pattern to search for (or literal string if fixedStrings is true) path string Yes Directory or file path to search in caseInsensitive boolean No Case insensitive search (default: false) multiline boolean No Enable multiline matching where . matches newlines fixedStrings boolean No Treat pattern as literal string, not regex glob string No Glob pattern to filter files (e.g. \"*.cs\", \"*.{ts,tsx}\") fileType string No File type to search (e.g. \"cs\", \"js\", \"py\") maxCount number No Maximum matches per file (0 = unlimited) context number No Lines of context before and after each match before number No Lines of context before each match after number No Lines of context after each match filesWithMatches boolean No Only return file paths that contain matches count boolean No Only return match counts per file Returns Formatted text with match count, stats (files searched, elapsed time), and matching lines as filepath:line:text . Example search_code(pattern=\"class.*Service\", path=\"H:\\\\project\", glob=\"*.cs\", context=2)"},{"id":"","t":"search_files","x":"Find files matching a glob pattern using ripgrep. Fast file discovery across directories. Parameters Name Type Required Description path string Yes Directory to search in glob string No Glob pattern to match file names (e.g. \"*.cs\", \"test_*.py\") fileType string No File type filter (e.g. \"cs\", \"js\", \"py\") Returns File count and list of matching file paths. Example search_files(path=\"H:\\\\project\", glob=\"*.cs\")"}]},{"u":"multi-connect.html","t":"Multi-Connect (Phone)","s":[{"id":"","t":"Multi-Connect (Phone)","x":"Multi-Connect is the current, recommended way to reach MultiTerminal from your phone: an in-process gateway that serves a mobile PWA, published securely over your private Tailscale network. There is no separate companion app and no public web server — just MultiTerminal and your tailnet."},{"id":"","t":"On This Page","x":"Prerequisites How it works Quickstart (the setup skill) On your phone The Multi-Connect settings tab Configuration surface Security model REST endpoints Troubleshooting"},{"id":"prereqs","t":"1. Prerequisites","x":"Multi-Connect publishes MultiTerminal over your private Tailscale network rather than the public internet, so before you start you need: A Tailscale account with both this PC and your phone signed in to the same tailnet . The phone reaches the PC over that shared private network — nothing is exposed publicly. MagicDNS enabled on the tailnet (Tailscale admin console → DNS). The whole https://<host>.ts.net scheme depends on it — without MagicDNS there is no friendly hostname for the phone to open, only a raw tailnet IP. MultiTerminal installed and running on the PC, with a phone username and password set (see the settings tab — login is disabled until both are changed from their defaults)."},{"id":"how-it-works","t":"2. How it works","x":"MultiTerminal hosts the phone experience itself. A second, independent ASP.NET Kestrel listener — the MultiRemoteGatewayHost — runs in-process on a loopback port (default 5100 ) and serves a Progressive Web App (PWA — an installable web app that gets a home-screen icon and can receive push notifications) plus the API the phone needs. It is completely separate from MultiTerminal's unauthenticated :5050 REST API, so it can carry its own session-auth pipeline without contaminating the desktop API. Public reachability comes from Tailscale serve , which terminates TLS on your tailnet and forwards requests to the loopback gateway. The gateway trusts the X-Forwarded-Proto=https header from the loopback proxy and issues Secure session cookies accordingly."},{"id":"","t":"Request path","x":"Phone (PWA over Tailscale) → Tailscale serve (HTTPS, on <host>.ts.net) → MultiRemoteGatewayHost (loopback :5100, in MultiTerminal.exe) → MultiTerminal services (in-process — no extra HTTP hop) Because the gateway calls MultiTerminal's services in-process, the phone gets the same task board, project list, team roster, chat/inbox, interactive terminal console (over WebSocket), and Web Push notifications that the desktop uses — with no proxy round-trips. The only remaining outbound hop is the off-box Cloudflare permission relay — a small Cloudflare-hosted message relay that forwards agent permission prompts to your phone and your tap-to-approve answer back, for cases where the phone is off the tailnet. It is optional and off-box: if you do not configure a relay base URL, MultiTerminal simply does not use it."},{"id":"quickstart","t":"3. Quickstart (the setup skill)","x":"The fastest path is the /multi-connect-setup skill. It is mostly automatic — the only manual step is a single browser login to Tailscale. Run it and it will: Detect (or install) Tailscale on this machine. Bring the node up — you complete one browser sign-in to your tailnet. Publish the loopback gateway over HTTPS with tailscale serve (forwarding to http://localhost:5100 ). Detect this node's MagicDNS hostname and write it back into the Multi-Connect config via the loopback POST /api/multi-connect/config . Verify the gateway answers on /health and print the final phone URL. Before the phone can log in: set a phone username and password (see the settings tab below). Login is deliberately disabled — the gateway returns 503 — until both auth credentials are changed away from their default placeholder values, so the app never sits open on your tailnet with changeme/changeme ."},{"id":"phone","t":"4. On your phone","x":"Once the skill (or the settings tab) has published the gateway and you have a phone username/password set, the phone side is a one-time setup in the mobile browser: On your phone, open https://<your-host>.ts.net in the browser (use the exact URL the skill printed, or the one the Copy button puts on your clipboard). The phone must be signed in to the same tailnet. Log in with the username and password you configured in the Multi-Connect settings tab. (If login returns 503 , the credentials are still at their defaults — set them first.) Add to Home Screen to install the PWA — on iOS Safari via the Share menu → Add to Home Screen ; on Android Chrome via the ⋮ menu → Install app / Add to Home screen . You then get a home-screen icon that launches the app full-screen. Allow notifications when prompted. This is what lets agent questions, permission prompts, and task/error alerts reach you as Web Push while you are away from the desk. For push to work end-to-end the gateway also needs a VAPID keypair configured (VAPID is the Voluntary Application Server Identification keypair that authorizes Web Push to your phone — the VAPID subject and keys in the config are what identify MultiTerminal as the legitimate sender). The skill and settings tab manage these; you normally only set the VAPID subject."},{"id":"settings-tab","t":"5. The Multi-Connect settings tab","x":"Everything the skill writes can also be configured by hand in Settings → Multi-Connect . The tab is the self-service surface — no JSON editing required: Control What it does Detect Tailscale Probes Tailscale (runs tailscale status --json ) and fills in this node's hostname, install/running state, and backend state. Test connection Checks that the in-process gateway answers on its /health endpoint. Copy Copies the computed phone URL ( https://<host>.ts.net ) to the clipboard. Load / Save (OK) Loads the effective config and persists changes. Each field shows its effective value and source (settings / appsettings / default) so you never edit on top of a hidden value. Clicking OK restarts the gateway in-process so that restart-required fields (gateway port, VAPID subject, notification secret, relay base URL) take effect without relaunching MultiTerminal."},{"id":"config","t":"6. Configuration surface","x":"Each per-install value resolves settings.txt (the Multi-Connect tab) → appsettings.Local.json → committed appsettings.json → built-in default . Per-install values and secrets belong in the tab or in the gitignored appsettings.Local.json — never in the committed appsettings.json . Field Default Purpose Gateway port 5100 Loopback port the in-process gateway listens on. Keep tailscale serve aligned to it. (restart-required) Tailscale enabled false Whether Tailscale fronting is in use for this install. Tailscale hostname unset This node's MagicDNS name (e.g. desktop.tailXXXX.ts.net ). Filled by Detect / the skill. Tailscale serve port 443 The HTTPS port Tailscale serve publishes on. Drives the phone URL. Phone auth username changeme Phone-login username. Login disabled until non-default. Phone auth password changeme Secret (DPAPI-protected at rest). Login disabled until non-default. Notification secret empty Secret shared with the push endpoint; when set, MultiTerminal attaches the matching X-MT-Secret on every forward. (restart-required) VAPID subject unset The sub claim for Web Push (a mailto: address or an http(s) URL). (restart-required) Relay base URL unset Base URL of the Cloudflare permission relay used for phone approvals. (restart-required) Relay API key empty Secret (DPAPI-protected) sent as the relay X-API-Key . The three secrets — phone password, notification secret, re"},{"id":"security","t":"7. Security model","x":"Loopback-only config. The /api/multi-connect/* endpoints are mounted only on the :5050 loopback REST host and are explicitly excluded from the :5100 phone gateway, so they are never reachable over Tailscale. Each action also rejects any non-loopback remote IP. Secrets are never returned raw. GET /api/multi-connect/config reports each secret only as an isSet boolean plus its source ( settings / appsettings / unset ) — the cleartext value is never sent to any caller. CSRF / cross-origin guard. Both the GET and the POST require a local, non-browser caller (an Origin / Sec-Fetch-Site check). A malicious page in a loopback browser is refused, while local tooling and the setup skill (which send no Origin) pass. Fail-closed phone login. The gateway returns 503 for login until both auth username and password are set to non-default values, so it never accepts the committed placeholders behind Tailscale. Secure cookies via forwarded headers. The gateway trusts X-Forwarded-Proto only from loopback (the Tailscale serve proxy), and issues HttpOnly , SameSite=Strict , Secure session cookies."},{"id":"rest","t":"8. REST endpoints","x":"The loopback configuration surface (used by the settings tab and the setup skill) lives under /api/multi-connect on :5050 : Method & path Purpose GET /api/multi-connect/config Effective per-install config. Secrets reported as is-set booleans with their source; carries a stable schemaVersion . POST /api/multi-connect/config Validates then persists. Cleared fields are removed (never stored as \"\" ); returns 400 on bad input with no partial write. Echoes the new effective config plus applied / restartRequired markers. GET /api/multi-connect/tailscale-status Typed Tailscale probe backing the tab's Detect button (installed / running / backend state / hostname / error). Per-field POST semantics: null (omitted) leaves a value unchanged, an empty string clears it, and any other value sets it. This lets the tab send an untouched secret as null so it never overwrites a stored secret with a placeholder."},{"id":"troubleshooting","t":"9. Troubleshooting","x":"The most common phone-setup snags and where to look: Symptom Likely cause & fix Phone can't reach https://<host>.ts.net at all Tailscale/MagicDNS: confirm the phone is signed in to the same tailnet and up, and that MagicDNS is enabled. Verify tailscale serve is running on the PC and the hostname matches what the Detect button reports. 503 at login Auth is still default/disabled. The gateway fails closed until both the phone username and password are changed away from changeme . Set them in the settings tab, then retry. Logged in, but no push notifications Check that you tapped Allow on the notification permission prompt (re-grant it in the phone's site settings if you dismissed it), and that a VAPID subject/keys are configured on the gateway. For the broader FAQ, see Troubleshooting / FAQ . For the deep configuration reference and hosting model, see docs/multiremote-gateway.md ."}]},{"u":"plugin.html","t":"Plugin & Distribution","s":[{"id":"","t":"Plugin & Distribution","x":"The MultiTerminal plugin is the unit that packages the skills, agents, hooks, and the bundled MCP/channel server and ships them to Claude Code. The desktop app hosts the data and UI; the plugin gives every Claude Code agent its skills, hooks, and messaging surface. This page covers the manifest, the directory layout, and how the plugin is distributed through the marketplace."},{"id":"","t":"On This Page","x":"What the plugin is The plugin.json manifest Directory layout The bundled channel server & vendored binary Distribution via the marketplace Installing & updating Plugin vs. the desktop app"},{"id":"what","t":"What the plugin is","x":"A Claude Code plugin is a self-contained bundle that Claude Code loads to extend an agent's behavior. The MultiTerminal plugin packages four things into one installable unit: Skills — 15 slash commands that orchestrate the kanban/review workflow (see Skills & Commands ). Agents — 9 specialist subagents the workflow skills dispatch for review, debugging, and session work. Hooks — lifecycle scripts that inject identity/context and react to session events (see Hooks ). An MCP/channel server — the bundled multiterminal-channel server that bridges agent-to-agent messaging into Claude Code as native channel events. Agent rules — a top-level CLAUDE.md carrying the agent behavioral instructions (kanban workflow, MCP tools, messaging, task terminology). Installing the plugin is what turns a plain Claude Code session into a MultiTerminal-aware agent — one that knows its identity, its task, its messages, and its team."},{"id":"manifest","t":"The plugin.json manifest","x":"Every plugin is described by .claude-plugin/plugin.json . MultiTerminal's declares the name, version, author, and — importantly — the bundled MCP server and channel: { \"name\": \"multiterminal\", \"description\": \"Multi-agent coordination system for Claude Code. Hooks, skills, and agents for kanban task management, review pipelines, team orchestration, and session lifecycle.\", \"version\": \"1.0.0\", \"author\": { \"name\": \"ClarionLive\", \"email\": \"noreply@multiterminal.dev\" }, \"mcpServers\": { \"multiterminal-channel\": { \"command\": \"node\", \"args\": [\"${CLAUDE_PLUGIN_ROOT}/server/multiterminal-channel.mjs\"] } }, \"channels\": [ { \"server\": \"multiterminal-channel\" } ] } The mcpServers block makes Claude Code launch the bundled channel server (via node , resolved through ${CLAUDE_PLUGIN_ROOT} so the path is install-location independent), and the channels block registers that server as a native messaging channel. Skills and agents are discovered by convention from the skills/ and agents/ directories; hooks are wired separately in hooks/hooks.json — they don't need to be re-listed in the manifest."},{"id":"layout","t":"Directory layout","x":"The plugin root contains these top-level entries: Path Contents .claude-plugin/plugin.json The manifest (name, version, MCP server, channel). skills/<name>/SKILL.md The 15 skills, each in its own folder with frontmatter + instructions (some carry a references/ subfolder). agents/*.md The 9 specialist agent definitions, plus report-template.html (the shared review-report template). hooks/hooks.json + hooks/*.js The hook registry and its Node scripts (plus _sqlite.js for native-module resolution and migration/policy notes). server/ multiterminal-channel.mjs (the channel MCP server), its package.json , and node_modules . vendor/ Vendored node_modules — notably the prebuilt better-sqlite3 native binary the hooks depend on. CLAUDE.md Agent behavioral rules shipped to every session."},{"id":"server","t":"The bundled channel server & vendored binary","x":"The plugin bundles its runtime dependencies so a clean install needs no build toolchain on the typical target."},{"id":"","t":"multiterminal-channel.mjs","x":"A Channels MCP server (one per terminal) that bridges MultiTerminal's agent-to-agent messaging into Claude Code. It listens on an HTTP port for incoming messages, pushes them into the session as <channel> events, and exposes send / reply tools so Claude can message back — the current transport, which replaced the legacy [cm] ConPTY nudge (see Channels ). It reads CHANNEL_PORT , MULTITERMINAL_NAME , MULTITERMINAL_ID , and MT_API_URL from the environment and depends on @modelcontextprotocol/sdk ."},{"id":"","t":"vendor/ — better-sqlite3","x":"DB-backed features (profiles, session lifecycle, activity, the kanban board) use the native better-sqlite3 module. A prebuilt binary for win32-x64 is checked into git verbatim under vendor/node_modules/better-sqlite3 , so hooks resolve it automatically with no npm install . On a mismatched runtime (different Node ABI, or non-Windows/ARM) the binary won't load and DB features disable for the session — the rest of the plugin still works. Fixes: rebuild it, use a global install, or point MT_BETTER_SQLITE3 at an explicit build."},{"id":"marketplace","t":"Distribution via the marketplace","x":"The plugin ships through a Claude Code marketplace — a small repository that advertises one or more installable plugins. The marketplace root holds .claude-plugin/marketplace.json plus the plugins themselves under plugins/ : { \"name\": \"multiterminal-marketplace\", \"description\": \"MultiTerminal plugins for Claude Code multi-agent coordination\", \"owner\": { \"name\": \"ClarionLive\" }, \"plugins\": [ { \"name\": \"multiterminal\", \"description\": \"Multi-agent coordination system for Claude Code. ...\", \"source\": \"./plugins/multiterminal\", \"category\": \"productivity\" } ] } The marketplace points at the plugin via a relative source path, so the marketplace repo and the plugin travel together. A user adds the marketplace once, then installs (or later updates) the plugin from it."},{"id":"install","t":"Installing & updating","x":"From the marketplace README, the install flow is: # Add the marketplace, then install the plugin claude plugin marketplace add ClarionLive/multiterminal-marketplace claude plugin install multiterminal@multiterminal-marketplace # Later, to pull updates claude plugin marketplace update multiterminal-marketplace Or use the interactive /plugin menu inside Claude Code and pick multiterminal from the multiterminal-marketplace source. Requirements: a recent Claude Code version — one that supports the args-array hook form ( args: string[] ) and plugin channels, Node.js 18+ on PATH (hooks and the channel server run under Node), and for the bundled DB binary, a win32-x64 runtime (other platforms work after a one-line npm rebuild )."},{"id":"relationship","t":"Plugin vs. the desktop app","x":"MultiTerminal has two halves that work together: The desktop app (the WinForms host) owns the data and the UI — it runs the REST API on :5050 , the SQLite databases, the kanban board, the panels, and the Office/Agent visualizations. The plugin gives the Claude Code agents their surface — the skills they run, the hooks that inject identity/context, the specialist agents, and the channel server for messaging. Its hooks and the channel server reach the app over the same :5050 REST API and the shared SQLite stores. In short: the app is where the work and the team live; the plugin is what makes each Claude Code session a participating member of that team. Neither requires you to hand-wire the other — installing the plugin and running the app is enough for a session to find its identity, task, inbox, and teammates. For the data side, see Architecture ; for the messaging internals, see MCP Architecture and Distribution ."}]},{"u":"presence.html","t":"Presence Sensors","s":[{"id":"","t":"Presence Sensors","x":"Presence-based routing makes MultiTerminal self-driving about where it interrupts you. A real mmWave sensor (and, optionally, your phone's Bluetooth) decides whether you're at your desk — and MultiTerminal automatically routes agent questions and notifications to your desktop when you're present and to phone push when you're away. No human or agent in the loop."},{"id":"","t":"On This Page","x":"The three presence states How states drive routing Debounce & graceful degradation Configuration The MQTT signal contract Hardware & setup"},{"id":"states","t":"1. The three presence states","x":"A pure, deterministic state machine ( PresenceStateMachine ) models three states from the latest sensor signals: State Condition AtDesk The mmWave radar reports occupancy at the desk zone. This is the primary gate — present means at the desk, full stop. Nearby mmWave is absent, but a registered phone's Bluetooth (BLE) is still in range — a fresh BLE presence flag is ON, or its RSSI (Bluetooth signal strength in dBm — a negative number where closer to 0 means nearer; the #1 calibration gotcha) is at or above that device's calibrated threshold. Away mmWave is absent and no registered phone is in range (or BLE is degraded / the sensor is offline). The mmWave radar is the authoritative signal. BLE is only consulted to distinguish Nearby from Away when mmWave already reports the desk as empty."},{"id":"routing","t":"2. How states drive routing","x":"The presence adapter maps the committed state onto MultiTerminal's binary remote-mode gate — MessageBroker.IsRemoteMode / SetRemoteMode . When remote mode is on, every phone-push path (permission prompts, agent questions and elicitations, task and error notifications) routes to the phone; when off, they stay on the desktop. State Remote mode Notifications go to AtDesk false Desktop Nearby false Desktop (v1: Nearby behaves as AtDesk) Away true Phone push v1 routing collapses Nearby into AtDesk (desktop-only), per the Owner decision. The machine still tracks Nearby as a distinct state; switching to true three-state routing later is a change to a single mapping method ( PresenceRouting.ToRemoteMode ). While presence is enabled it is the authoritative source of remote mode: a manual Local/Remote pill toggle is re-corrected on the next presence evaluation, not left latched."},{"id":"debounce","t":"3. Debounce & graceful degradation","x":"To keep brief movements from thrashing your routing, a desired state must persist for a debounce window before it commits — default 5 seconds (the first state commits immediately). Combined with the radar's absence timeout and your walk time, expect roughly 10–15 seconds to switch. The machine degrades safely when it can't fully trust its inputs: BLE stale or unavailable (no fresh phone signal within the staleness window, default 30 seconds ) → it collapses to mmWave-only: desk occupied = AtDesk, otherwise Away. Sensor / bridge offline (reported via the MQTT Last-Will topic — the Last-Will-and-Testament is the message the broker publishes on the sensor's behalf if it drops its connection) → the retained readings are treated as untrustworthy and the machine returns the safe default, Away (so notifications reach your phone rather than getting pinned to a dead desktop)."},{"id":"config","t":"4. Configuration","x":"Presence is configured through the Presence tab in Settings (and persisted via SettingsService ). It is off by default so it never hijacks the manual remote-mode pill until you opt in and calibrate."},{"id":"","t":"Enabling presence in MultiTerminal","x":"Open Settings → Presence and turn it on — or set presence.enabled=1 directly in %APPDATA%\\multiterminal\\settings.txt . If you edit settings.txt by hand, do it while MultiTerminal is stopped — the running app owns the file and rewrites it from memory, so a live edit gets clobbered. Restart MultiTerminal. The adapter only starts at launch, so the toggle takes effect on the next start. For the full hardware-to-routing walkthrough — flashing firmware, the Mosquitto broker, calibrating the desk zone, and the BLE/IRK capture — see the prominent setup guide at docs/presence/SETUP-GUIDE.md . Setting Key / default Notes Enabled Set presence.enabled to 1 to enable; default is off ( 0 or unset) Gates whether the adapter runs at all. Config blob presence.config (compact JSON) Holds MQTT, debounce, staleness, and the registered phones. Debounce debounceSeconds = 5 Hysteresis window before a state commits. BLE staleness bleStaleSeconds = 30 Age beyond which a phone signal is ignored. MQTT broker 127.0.0.1:1883 , prefix mt/presence , QoS 1 Where the adapter subscribes for sensor signals. Registered phones per device: deviceId , label , rssiThreshold (default -75 dBm), os Each phone has its own calibrated RSSI threshold; readings at or above it count as in-range."},{"id":"mqtt","t":"5. The MQTT signal contract","x":"The sensor publishes flat topics under the configured prefix (default mt/presence ); the adapter subscribes to <prefix>/# and normalizes each message: Topic Payload Meaning mt/presence/desk/occupancy ON / OFF mmWave occupancy — the primary AtDesk gate. mt/presence/status online / offline Sensor availability (Last-Will). Anything not \"online\" degrades to Away. mt/presence/ble/<deviceId>/rssi integer dBm (e.g. -67 ) Per-phone Bluetooth signal strength. mt/presence/ble/<deviceId>/presence ON / OFF Per-phone in-range flag (authoritative over raw RSSI when fresh). Routing readiness is established only by the first desk/occupancy message — a retained status or BLE reading delivered first won't transiently flip you to phone-push before real occupancy data arrives. You can confirm the live routing flag with GET /api/remote-mode , which returns {\"remote_mode\": false} at the desk and true when away."},{"id":"","t":"How do I know it's working?","x":"Without watching the status-bar pill, you can check the routing flag directly: curl http://localhost:5050/api/remote-mode # {\"remote_mode\": false} ← at the desk # {\"remote_mode\": true} ← away Sit at the desk and confirm it reads false ; step away past the debounce window and confirm it flips to true . For an end-to-end check that publishes occupancy over MQTT and asserts the flip headlessly, run the bundled smoke test docs/presence/presence-smoke-test.ps1 ( pwsh -File docs\\presence\\presence-smoke-test.ps1 )."},{"id":"hardware","t":"6. Hardware & setup","x":"The reference build uses an Apollo Automation MSR-2 multisensor — internally an ESP32-C3 paired with an HLK-LD2410B 24 GHz mmWave radar. mmWave (rather than PIR) is the point: it detects you sitting still at your desk. Any ESP32 + LD2410 board works with minor pin changes. The sensor runs ESPHome firmware and publishes to a local Mosquitto MQTT broker. The end-to-end walkthrough — ESPHome install, Mosquitto with a LAN listener, firewall rule, flashing the firmware, enabling presence in MultiTerminal, calibrating the desk zone, and the gotchas hit along the way — lives in docs/presence/SETUP-GUIDE.md . The firmware config ( docs/presence/msr2-presence.yaml ) and a headless smoke test ( docs/presence/presence-smoke-test.ps1 ) are alongside it. Optional phone proximity (the Nearby distinction) adds a BLE tracker per phone, publishing mt/presence/ble/<id>/presence and /rssi ; register each phone with a calibrated RSSI threshold in the presence config. Because iOS and Android randomize their BLE MAC, devices are matched by IRK (Identity Resolving Key — a per-phone key that lets the tracker still recognize a device whose MAC keeps rotating) — see the setup guide for the one-time capture."}]},{"u":"skills.html","t":"Skills & Commands","s":[{"id":"","t":"Skills & Commands","x":"The MultiTerminal plugin ships 15 skills — slash commands that orchestrate the agent workflow — and 9 specialist agents that the workflow skills dispatch for review, debugging, and session work. Each skill is invoked as /<name> ; each agent is spawned automatically by the pipeline and project-management skills."},{"id":"","t":"On This Page","x":"What skills are Workflow skills Setup & onboarding skills Utility & intel skills Specialist agents"},{"id":"what","t":"What skills are","x":"A skill is a packaged instruction set Claude Code loads on demand when you type /<name> (or when the model recognizes a matching intent). Each lives in skills/<name>/SKILL.md inside the plugin, with a frontmatter name / description the model uses to decide when to invoke it. Intent matching means you don't have to type the slash command at all — saying \"act as PM\" or \"dispatch these tickets\" pulls in /program-management , and \"verify the build\" pulls in /verifier-multiterminal , because those phrases match the skill's description. Skills are instructions for the agent to execute — they drive the Bash, PowerShell, MCP, and Task tools — not standalone scripts. The 15 skills fall into three groups: the workflow skills that run the kanban lifecycle, the setup/onboarding skills that bootstrap projects and connectivity, and the utility/intel skills that handle profiles, briefings, and verification."},{"id":"workflow","t":"Workflow skills","x":"These five drive the day-to-day task lifecycle — from picking work, through single- and multi-ticket coordination, to the post-coding review gates. Command What it does When to use /session-start Lightweight startup menu. Establishes identity, registers the session in the lifecycle pipeline, reads active context, and presents quick choices (continue task, new task, pick task, just chat). No heavy loading until you pick. Auto-runs at the start of every session; the entry point that routes you into the heavier workflows. /kanban-task Orchestrates a single ticket's full lifecycle: auto-detects current state, guides planning/coding/testing cycles, enforces completion gates, and writes continuation notes for clean session handoffs. Working one ticket end-to-end, resuming after context ran out, or checking your current task state. /project-management Orchestrates the full development lifecycle — task dashboard, planning, team assembly, code review, build verification, and testing. Tiered SMALL/MEDIUM/LARGE workflows scale ceremony to task complexity. Picking up new work, managing agents, or coordinating multi-step development (options 2–3 of the start menu). /program-management Coordinates a multi-ticket program as a PM — sequences 2+ related tickets across agents, runs quality-gate cycles, and triages findings across cycles. Distinct from /kanban-task 's single-ticket scope. \"Act as"},{"id":"setup","t":"Setup & onboarding skills","x":"These five bootstrap projects into MultiTerminal, stand up the remote/phone connectivity stack, and rebuild context after a clear. Command What it does When to use /new-project Interactive onboarding wizard with two modes: Create New (scaffold folders from an archetype — Clarion COM, WebView2, Clarion App, MT Feature, Generic C# — init git, register) or Add Existing (point at a folder, auto-discover details, confirm, register). Starting a brand-new project, or registering an existing folder so MultiTerminal can track it. /multiterminal-addproject The lower-level path: creates .claude/project.json in the current directory and registers it in the central MultiTerminal registry. Quickly registering the current working directory as a project without the full wizard. /multi-connect-setup Guided, mostly-automatic phone connectivity via Tailscale: detects/installs Tailscale, brings the node up (one manual browser login), publishes the loopback gateway over HTTPS with tailscale serve , writes the hostname back into the Multi-Connect config, and prints the phone URL. Windows only. Connecting a phone to MultiTerminal or configuring remote/Multi-Connect access. /start-servers Starts the remote-access server stack — the HTTP bridge that relays prompts, questions, and permission requests to your phone (see Multi-Connect ), Caddy (HTTPS), and optionally the TTS server — checking which ports "},{"id":"utility","t":"Utility & intel skills","x":"These five cover profiles, the daily intelligence/briefing pipeline, the Claude Code internals search, and build verification. Command What it does When to use /profile A friendly front-end for updating your team-member profile — personal info, skills, interests, avatar — auto-detecting the calling agent from MULTITERMINAL_NAME so you never specify identity manually. Filling in or updating your team profile without raw MCP calls. /daily-digest Runs the bundled DailyDigest fetch script — a data-collection helper that gathers raw AI/Claude-ecosystem data from GitHub, Reddit, HN, and the web — then summarizes the results into an actionable morning briefing. \"Daily digest\" / \"morning briefing\" / \"what happened today in AI\". /daily-intel A four-phase intelligence pipeline: digest triage (action items → suggestion tasks), version watch (new Claude Code CLI releases via npm), KB update (fetch + append changelog), and an Owner push notification with the summary. Can be cron-triggered daily. Daily automated intel, or manually to process the digest and check for CLI updates. /claude-code-search Searches the Claude Code internals knowledge base — architecture, tools, commands, state management, and hidden features distilled from a source-code analysis. Looking up how Claude Code itself works (tools, slash commands, the query engine, state). /verifier-multiterminal Verifies MultiTerminal c"},{"id":"agents","t":"Specialist agents","x":"The plugin's agents/ directory defines 9 specialist subagents . These aren't invoked by slash command — they're dispatched automatically by the workflow skills: /pipeline fans out the review gates, and /project-management / /program-management spawn the planning, design, and session agents at the right lifecycle step. Most run on Opus; each ships with a constrained tool set scoped to its job. (The folder also contains report-template.html , a shared HTML report template the review agents render into — it is a template, not an agent.)"},{"id":"","t":"verifier","x":"Quality gate that validates coding work is actually complete before it reaches the tester. Builds the project and confirms the implementation is present. First gate in the pipeline."},{"id":"","t":"code-reviewer","x":"Reviews code quality, patterns, naming, duplication, and consistency with codebase conventions. Runs after the verifier passes — fills the gap between completeness and security checks."},{"id":"","t":"security-auditor","x":"Scans code changes for security vulnerabilities — OWASP Top 10, injection, XSS, and architecture-specific risks. Runs during the code-review phase or on demand."},{"id":"","t":"debugger","x":"Root-cause analyst for failed tests and bugs. Traces data flow, identifies the root cause, and produces targeted fix instructions when testing reveals failures."},{"id":"","t":"devils-advocate","x":"Challenges plans and proposals before coding begins. Scores proposals, finds flaws, and blocks bad ideas during the planning phase."},{"id":"","t":"test-designer","x":"Designs test criteria for checklist items so coders know what \"done\" looks like and testers know what to verify. Used when building checklists after planning."},{"id":"","t":"session-summarizer","x":"Generates concise session recaps from raw session messages. Spawned at session start when no cached summary exists, and saves the summary to SQLite for reuse."},{"id":"","t":"session-distiller","x":"Compresses session learnings into persistent memory files. Used at session end or when asked to distill/save what was learned this session."},{"id":"","t":"session-reviewer","x":"Disabled. Was a session-context specialist, but the underlying session-history database went stale — the agent file is shipped but flagged not-for-use pending a review ticket."}]},{"u":"troubleshooting.html","t":"Troubleshooting / FAQ","s":[{"id":"","t":"Troubleshooting / FAQ","x":"Concrete fixes for the issues you are most likely to hit: port conflicts on 5050, MCP tools not connecting, database location and backup, resetting the docking layout, frozen terminals, the WebView2 runtime, and where the logs live."},{"id":"","t":"On This Page","x":"Key paths & ports at a glance REST API / port 5050 conflicts MCP tools not connecting Database location & backup Resetting the docking layout Frozen terminal / respawn WebView2 runtime Phone / Multi-Connect won't connect Code-graph search returns 503 Where to see logs"},{"id":"paths","t":"Key paths & ports at a glance","x":"What Where REST API http://localhost:5050 (loopback only) MCP server (Node.js) %APPDATA%\\multiterminal\\mcp\\ (entry point index.js ) Main database %APPDATA%\\multiterminal\\multiterminal.db Message queue database %APPDATA%\\multiterminal\\messages.db Startup error log %APPDATA%\\multiterminal\\startup-error.log Worktrees (when enabled) <project>\\.claude\\worktrees\\ On Windows, paste %APPDATA%\\multiterminal straight into the File Explorer address bar to open that folder."},{"id":"port","t":"REST API / port 5050 conflicts","x":"MultiTerminal hosts its REST API on localhost:5050 . Every MCP tool and panel talks to that port, so a conflict breaks task, chat, and code-graph operations across the app. Symptoms: the app launches but tasks/chat never load; MCP tools time out or return connection errors. Check what owns the port (PowerShell): Get-NetTCPConnection -LocalPort 5050 -State Listen | Select-Object LocalAddress, OwningProcess Get-Process -Id (Get-NetTCPConnection -LocalPort 5050 -State Listen).OwningProcess Fixes: A stale MultiTerminal process is the usual culprit — fully exit any prior instance (check the system tray and Task Manager) before relaunching. If a genuinely unrelated process owns 5050, stop it, then relaunch MultiTerminal. Confirm the API is healthy once the app is up: curl http://localhost:5050/health should return {\"status\":\"healthy\",\"port\":5050} ."},{"id":"mcp","t":"MCP tools not connecting","x":"The MCP server is a Node.js process under %APPDATA%\\multiterminal\\mcp\\ . Its tools are thin wrappers that call the REST API on localhost:5050 , so MCP problems are usually really API-or-path problems. Work through these in order: Is the app running? The MCP tools need MultiTerminal open so the API on 5050 is listening. Start the app first. Is the API up? curl http://localhost:5050/health . If that fails, fix the port first — the MCP layer can't work without it. Does the MCP folder exist? Confirm %APPDATA%\\multiterminal\\mcp\\index.js is present. MultiTerminal provisions this on startup; if it's missing, restart the app to let it re-provision. Is Node.js available? The MCP server runs under Node; node --version should succeed on your PATH. Restart the client. After fixing the above, restart your Claude Code session so it re-handshakes with the MCP server."},{"id":"db","t":"Database location & backup","x":"MultiTerminal stores its data in SQLite under %APPDATA%\\multiterminal\\ : multiterminal.db — tasks, checklists, sessions, knowledge, profiles, projects, and the code graph (all in one file). messages.db — the inter-terminal message queue. To back up: close MultiTerminal completely, then copy the .db files somewhere safe. Closing first matters — SQLite uses write-ahead logging (WAL), so copying while the app is running can capture a half-written state. # PowerShell — back up both databases with the app closed $src = \"$env:APPDATA\\multiterminal\" $dst = \"$env:USERPROFILE\\Desktop\\mt-backup\" New-Item -ItemType Directory -Force $dst | Out-Null Copy-Item \"$src\\multiterminal.db\" $dst Copy-Item \"$src\\messages.db\" $dst To restore: close the app and copy the saved .db files back over the ones in %APPDATA%\\multiterminal\\ ."},{"id":"layout","t":"Resetting the docking layout","x":"MultiTerminal's panels are arranged with a docking layout manager, and the layout is persisted between runs. If panels end up off-screen, collapsed to zero size, or otherwise wedged: Use the toolbar toggle buttons to hide and re-show the affected panel — panels are hidden on close (not destroyed), so toggling re-docks them. If the whole layout is corrupt, exit the app and remove the persisted layout file in %APPDATA%\\multiterminal\\ (the docking-layout file), then relaunch to rebuild the default arrangement. Your tasks and chat history live in the databases, so they are unaffected."},{"id":"terminal","t":"Frozen terminal / respawn","x":"Each terminal hosts a real shell process (ConPTY). If one stops responding — no echo, no output, a hung command: Click into the terminal and press Ctrl + C to interrupt a stuck foreground command. If it's truly frozen, close that terminal tab and open a new one — this respawns a fresh shell process. Other terminals and panels are unaffected. A frozen agent terminal (a spawned teammate) can likewise be closed and re-spawned; its task state persists in the database, so a new session can pick the task back up from its continuation notes."},{"id":"webview2","t":"WebView2 runtime","x":"Most of MultiTerminal's panels (Tasks, Chat, Activity, Office, and others) render in embedded WebView2 controls, which require the Microsoft Edge WebView2 Runtime . Symptoms of a missing/broken runtime: panels are blank or white, or the app errors on startup referencing WebView2. Fix: install the Evergreen WebView2 Runtime from Microsoft (it ships with current Windows 11 but can be absent or outdated on older images), then relaunch. WebView2's own user-data cache lives under your local app data; a corrupt cache is rare but clears by reinstalling the runtime."},{"id":"phone","t":"Phone / Multi-Connect won't connect","x":"Multi-Connect publishes MultiTerminal to your phone over your private Tailscale network (see Multi-Connect ). Most connection failures fall into one of three buckets: Phone can't reach https://<host>.ts.net at all. Confirm both the PC and the phone are signed in to the same tailnet and that Tailscale is up on each. Then confirm MagicDNS is enabled (Tailscale admin console → DNS) — without it there is no .ts.net hostname for the phone to open. Verify tailscale serve is running on the PC and the hostname matches what the settings tab's Detect button reports. Login returns 503 . The phone gateway fails closed : login is disabled until both the phone username and password are changed away from their default changeme placeholders. Set them in the Multi-Connect settings tab, then retry. This is deliberate — it stops the app from ever sitting open on your tailnet with default credentials. Connected, but push notifications don't arrive. Web Push needs a VAPID keypair configured (the settings tab / setup skill manage the keys; you normally only set the VAPID subject)."},{"id":"code-graph","t":"Code-graph search returns 503 \"CodeGraph not available\"","x":"The code-graph endpoints ( /api/code-graph/search , /callers , /callees , /impact , /inheritance ) and the matching MCP tools return 503 {\"error\":\"CodeGraph not available\"} when the project hasn't been indexed yet. The CodeGraphWatcher background service normally indexes every registered C# project automatically — it sweeps and refreshes stale graphs shortly after app startup, and re-indexes on edit — so a 503 usually means one of: The startup sweep hasn't finished. Right after launch there's a brief window before the watcher's first index completes. Wait a few seconds and retry; GET /api/code-graph/stats shows the last-indexed time. The directory isn't a watched project. The watcher only indexes registered projects that have a top-level .csproj . A loose directory (or a src/ -style layout with no root .csproj ) is never auto-indexed. Auto-indexing is disabled. MULTITERMINAL_CODEGRAPH_WATCH is set to 0 / false / off . Fix: for a registered project, just wait for the startup sweep (or check it's eligible / not disabled). To index any directory immediately — including one that isn't a registered project — run the index_code_graph MCP tool or POST /api/code-graph/index with the project directory. You generally don't need to re-index after edits anymore; the watcher handles that."},{"id":"logs","t":"Where to see logs","x":"Debug panel. The in-app Debug panel is the first place to look — it streams live diagnostic output (including remote-mode changes, worktree strands, and service warnings). Toggle it from the toolbar. Startup errors. If the app fails early (before panels load), check %APPDATA%\\multiterminal\\startup-error.log . API health. curl http://localhost:5050/health and curl http://localhost:5050/api/tools confirm the API is up and list every available endpoint."}]},{"u":"webmcp-demo.html","t":"WebMCP Interactive Demo","s":[{"id":"","t":"WebMCP Interactive Demo","x":"W3C Web Model Context Protocol — Structured AI-to-Page Tool Invocation navigator.modelContext polyfill active Polyfill: checking... Tools: 0 Invocations: 0 &#x1F527; Registered Tools 0 Tools will appear here when registered... &#x1F4CB; Invocation Log 0 Agent tool invocations will appear here..."}]},{"u":"worktrees.html","t":"Git Worktrees","s":[{"id":"","t":"Git Worktrees","x":"Per-task git worktree isolation gives every active task its own checkout on its own branch, so parallel agents never trample each other's working tree. Claiming a task materializes a worktree; finishing it auto-commits, merges back to trunk, and prunes the directory."},{"id":"","t":"Typical flow","x":"Set MULTITERMINAL_WORKTREE_MODE=on (a startup env var — see below) and launch MultiTerminal. Claim / activate a task → you get an isolated checkout on branch task/<id> under .claude/worktrees/ . Do the work there — your edits never touch the main checkout or any other task's tree. Mark the task done → MultiTerminal auto-commits, merges the branch back to trunk, and prunes the worktree directory."},{"id":"","t":"On This Page","x":"Why worktrees Turning it on (WORKTREE_MODE) Auto-create on claim Branch & path naming Teardown on done (commit → merge → prune) Where your shell ends up HUD git panel rebind Querying the active worktree Failure handling"},{"id":"why","t":"Why worktrees","x":"A git worktree is a second working directory backed by the same repository — a separate checkout on a separate branch that shares the one .git store. MultiTerminal uses one worktree per active task so that: Two agents working two tasks in the same repo never see each other's uncommitted edits. Each task's commits land on a dedicated task/<id> branch, keeping trunk clean until the task is done. A helper joining a task gets its own branch and worktree, so helper work integrates deliberately rather than racing the assignee's tree. Worktrees live inside the project at .claude/worktrees/ (gitignored). Keeping them under the main checkout matters for Claude Code's permission scope, harness cwd pinning, and the EnterWorktree enter-existing form (see below)."},{"id":"gate","t":"Turning it on (WORKTREE_MODE)","x":"Worktree isolation is opt-in , gated by an environment variable. With it unset, MultiTerminal behaves exactly as before — everyone works directly in the main checkout. # Enable per-task worktree isolation MULTITERMINAL_WORKTREE_MODE=on MULTITERMINAL_WORKTREE_MODE is a process environment variable read once at startup ( WorktreeConfig resolves it on first access and caches the result). Set it before launching MultiTerminal — e.g. as a Windows user/system environment variable, or in the shell that starts the app — and restart the app for a change to take effect. Only the literal value on (case-insensitive) enables it; unset, blank, 1 , true , and yes all leave it off. When the gate is on, the worktree lifecycle hooks fire automatically at task-activate and task-done time. When it is off, no worktrees are created and the teardown steps are skipped."},{"id":"create","t":"Auto-create on claim","x":"Setting a task active (claiming it, or activating an already-claimed task) materializes a worktree for the acting agent. The operation is idempotent: if that agent already has an active worktree on disk for the task, the existing one is returned unchanged — no second checkout, no git work. The assignee gets the canonical worktree on branch task/<id> , forked from trunk. Each helper gets their own worktree on task/<id>--<slug> , forked from the canonical branch's tip (the canonical branch is created first if it does not yet exist). Fresh worktrees contain only tracked files. A few build-required artifacts in this repo are vendored and gitignored (notably tools/rg.exe ), so MultiTerminal seeds the known vendored directories from the main checkout into each new worktree — otherwise a post-build copy step would fail."},{"id":"","t":"Trunk safety","x":"The canonical branch is always rooted explicitly at trunk, never at \"whatever HEAD points to.\" If the main checkout is on a detached HEAD or sitting on another task/ branch, worktree creation fails loudly rather than silently forking the new branch from the wrong commit."},{"id":"naming","t":"Branch & path naming","x":"The first 8 characters of the task id ( <idShort> ) drive both the directory name and the branch name. Role Branch Worktree path Forked from Assignee (canonical) task/<idShort> .claude/worktrees/<idShort>/ trunk Helper task/<idShort>--<slug> .claude/worktrees/<idShort>--<slug>/ canonical branch tip Records are persisted in the task_worktrees table, keyed by the composite (task_id, agent_name) . A record is active while the directory exists on disk and pruned after removal; pruned rows are retained for audit/history."},{"id":"","t":"Two agents on one task","x":"Say task c0ce8037 is assigned to Alice and Bob joins as a helper with slug tests : Alice (assignee) works in .claude/worktrees/c0ce8037/ on branch task/c0ce8037 — the canonical branch, forked from trunk. Bob (helper) works in .claude/worktrees/c0ce8037--tests/ on branch task/c0ce8037--tests — forked from the canonical branch tip. Each has its own checkout, so neither sees the other's uncommitted edits. On done, Bob's branch is merged into Alice's canonical branch first, then the canonical branch lands on trunk."},{"id":"done","t":"Teardown on done (commit → merge → prune)","x":"Moving a task to done runs a multi-phase teardown so nothing the agents wrote is lost and trunk ends up carrying every agent's work: Auto-commit — each worktree's changes are committed on its own branch. MultiTerminal stages the exact file list from git status --porcelain (never a blanket git add -A ), honors pre-commit hooks (never --no-verify ), and writes a single commit with the task title, the implementation summary, and a Co-Authored-By trailer for the agent. A clean worktree is a no-op. Integrate helper branches — each task/<id>--<slug> branch is merged into the canonical task/<id> branch (inside the still-checked-out canonical worktree). A conflict aborts the merge cleanly and halts teardown so nothing is dropped. Prune — every worktree directory for the task is removed and its record marked pruned . Prune must run before the trunk merge: git refuses to merge a branch while it is checked out anywhere. Merge to trunk — the canonical task/<id> branch is merged into the main checkout's trunk with git merge --no-edit (fast-forward or merge commit), then the branch is deleted."},{"id":"","t":"Merge guards (fail closed)","x":"The trunk merge refuses rather than guessing when it cannot be sure it is landing in the right place: The expected trunk is resolved from the project's configured git_default_branch , then the remote's origin/HEAD , then the sole non-task local branch only if it bears a conventional name ( main , master , develop , trunk ). If none resolve, the merge refuses. If the main checkout's branch is not the expected trunk, the merge refuses with a \"check out trunk and re-mark done\" message. If the main checkout has uncommitted tracked changes (beyond MT's own .claude/project.json bookkeeping), the merge refuses — genuine user work is never auto-committed. A merge conflict triggers git merge --abort ; the main checkout stays clean and the task branch is left alive for manual resolution."},{"id":"cwd","t":"Where your shell ends up","x":"On Claude Code 2.1.157 and later, MultiTerminal uses the EnterWorktree / ExitWorktree harness operations to move a session's working directory into and out of a task worktree cleanly (rather than a raw cd , which the cwd-pinned harness does not honor). The session-start auto-cd flow enters the active task's worktree so a resumed shell lands in the right checkout. This is also why worktrees must live under .claude/worktrees/ : the EnterWorktree(path=...) enter-existing form requires the target be a worktree under that directory for cwd-pinned-at-launch agents (MT terminals)."},{"id":"hud","t":"HUD git panel rebind","x":"The HUD git panel always shows the repository state of the active task's worktree, and rebinds itself when the active task changes. Three events drive this: TaskActiveChanged — fires after the active task swaps. The HUD git renderer resolves the new task's worktree path agent-aware (a helper rebinds to its own task/<id>--<slug> worktree, not the assignee's canonical one). WorktreePruning — fires synchronously just before the directory is removed at task-done. Subscribers drop live git handles, and a control message tells any agent whose cwd is inside the worktree to cd out before the rmdir. WorktreeReady — fires after both prune and the post-prune trunk merge complete. The HUD git renderer releases its cached service for the pruned path and rebinds to the post-merge repo root. The contract between the last two: pruning says \"drop your handles, the directory is about to disappear\"; ready says \"the post-merge state is durable, refresh your view.\""},{"id":"query","t":"Querying the active worktree","x":"A long-running shell can switch tasks, so the launch-time worktree path goes stale. Agents query the live path instead via the get_active_worktree MCP tool, which is backed by: GET http://localhost:5050/api/worktrees/active/{agentName} The endpoint always returns HTTP 200. A null worktreePath means \"no active worktree\" (no active task, worktree mode off, or project unregistered) and is used as the no-op signal in the auto-cd protocol. A representative response: { \"agentName\": \"Alice\", \"taskId\": \"c0ce8037\", \"taskTitle\": \"Add dark mode\", \"worktreePath\": \"H:\\\\DevLaptop\\\\...\\\\.claude\\\\worktrees\\\\c0ce8037\", \"repoRoot\": \"H:\\\\DevLaptop\\\\...\\\\MultiTerminal\", \"branchName\": \"task/c0ce8037\" } This is a read-or-create endpoint: if the agent's active task is eligible but its worktree was never materialized, the call backfills it (idempotent, bounded to that agent's one legitimate worktree)."},{"id":"failure","t":"Failure handling","x":"Partial prune (Windows): when an agent's terminal has its cwd inside a worktree, git worktree remove wipes contents and unregisters the worktree but cannot rmdir the directory (the OS holds an open handle). MultiTerminal detects this by re-querying git worktree list ; if the path is gone from git's view it treats the removal as a success and leaves only an empty shell, which the janitor sweeps later. A strand signal is surfaced to the activity feed so it is observable in real time. Stranded directories: GET /api/worktrees/stranded reports de-registered-but-on-disk worktree shells. Its payload carries an explicit status ( ok / partial / unavailable ) so a caller can never mistake \"couldn't tell\" for \"none.\" Dirty main checkout / conflicts: see the merge guards above — these refuse and leave state recoverable rather than forcing a merge."}]}];
